globalThis.__BQ = {"avogadroKutu":{"ilkokul":{"kolay":[{"q":"Bir mol içindeki tanecik sayısını gösteren çok büyük sayıya ne ad verilir?","steps":[{"t":"Mol içeriği","a":"çok tanecik","d":"Bir mol madde, çok ama çok sayıda tanecik içerir."},{"t":"Sayının adı","a":"Avogadro sayısı","d":"Bu büyük sayıya <b>Avogadro sayısı</b> denir."}],"ans":"Bir moldeki tanecik sayısına <b>Avogadro sayısı</b> denir."},{"q":"Avogadro sayısı yaklaşık olarak kaçtır?","steps":[{"t":"Değer","a":"6,02·10²³","d":"Avogadro sayısı 6,02·10²³ tanedir."},{"t":"Büyüklük","a":"çok büyük","d":"Bu, arkasında 23 sıfır olan, hayal edemeyeceğimiz kadar büyük bir sayıdır."}],"ans":"Avogadro sayısı <b>6,02·10²³</b> (çok büyük bir sayı) kadardır."},{"q":"1 mol bilye ile dünyayı kaplasaydık, bu çok az bilye mi yoksa inanılmaz çok bilye mi olurdu?","steps":[{"t":"1 mol","a":"6,02·10²³ tane","d":"1 mol, 6,02·10²³ tane demektir."},{"t":"Karşılaştırma","a":"inanılmaz çok","d":"Bu sayı o kadar büyüktür ki bu kadar bilye tüm dünyayı kalın bir tabaka gibi kaplardı."}],"ans":"Bu <b>inanılmaz çok</b> bilye olurdu; çünkü 1 mol akıl almaz büyüklükte bir sayıdır."},{"q":"İki farklı maddenin birer molü aynı sayıda mı tanecik içerir?","steps":[{"t":"1 mol kuralı","a":"hep aynı sayı","d":"1 mol madde her zaman aynı sayıda, yani 6,02·10²³ tanecik içerir."},{"t":"Sonuç","a":"evet aynı","d":"Madde ne olursa olsun, birer mollerinde aynı sayıda tanecik bulunur."}],"ans":"Evet, iki farklı maddenin birer molü de <b>aynı sayıda</b> (6,02·10²³) tanecik içerir."},{"q":"Avogadro sayısı kadar pirinç tanesi az mı çoktur?","steps":[{"t":"Sayı","a":"6,02·10²³","d":"Avogadro sayısı 6,02·10²³ tanedir."},{"t":"Yorum","a":"sayılamaz çoklukta","d":"Bu kadar pirinç tanesini ömrümüz boyunca saysak bile bitiremezdik."}],"ans":"Avogadro sayısı kadar pirinç <b>sayılamayacak kadar çok</b> olurdu."}],"zor":[{"q":"2 mol şeker tanesi kaç tane tanecik içerir?","steps":[{"t":"1 mol","a":"6,02·10²³","d":"1 mol, 6,02·10²³ tane demektir."},{"t":"2 mol","a":"2 × 6,02·10²³","d":"2 mol için sayıyı 2 ile çarparız: 1,204·10²⁴ tane."}],"ans":"2 mol şeker <b>1,204·10²⁴</b> tane içerir."},{"q":"Avogadro sayısının ne kadar büyük olduğunu anlatmak için nasıl bir benzetme yapılabilir?","steps":[{"t":"Benzetme arayışı","a":"somut örnek","d":"Çok büyük sayıları anlamak için günlük örneklere benzetiriz."},{"t":"Örnek","a":"kum taneleri","d":"Avogadro sayısı kadar kum tanesi, tüm sahilleri ve çölleri kat kat doldurabilecek kadar çoktur."}],"ans":"Avogadro sayısı o kadar büyüktür ki, bu kadar kum tanesi <b>dünyadaki tüm çölleri ve sahilleri</b> doldurabilirdi."},{"q":"Elimizde 6,02·10²³ tane atom varsa, kaç mol atomumuz vardır?","steps":[{"t":"Tanım","a":"1 mol = 6,02·10²³","d":"1 mol, tam olarak 6,02·10²³ taneye eşittir."},{"t":"Sonuç","a":"1 mol","d":"Elimizdeki tanecik sayısı tam Avogadro sayısı kadar olduğundan, 1 molümüz vardır."}],"ans":"6,02·10²³ tane atom, tam olarak <b>1 mol</b> atom demektir."},{"q":"Yarım mol (0,5 mol) bir madde kaç tanecik içerir?","steps":[{"t":"1 mol","a":"6,02·10²³","d":"1 mol, 6,02·10²³ tane içerir."},{"t":"Yarısı","a":"6,02·10²³ ÷ 2","d":"0,5 mol için bu sayının yarısını alırız: 3,01·10²³ tane."}],"ans":"0,5 mol madde <b>3,01·10²³</b> tanecik içerir."},{"q":"Neden 1 düzine yerine 1 mol çok daha büyük bir sayıyı temsil eder?","steps":[{"t":"Düzine","a":"12 tane","d":"Düzine yalnızca 12 taneyi ifade eder, küçük bir birimdir."},{"t":"Mol","a":"6,02·10²³ tane","d":"Mol ise 6,02·10²³ taneyi ifade eder; bu, atomlar gibi çok küçük ve çok sayıda şeyler için seçilmiştir."}],"ans":"Düzine sadece 12, mol ise <b>6,02·10²³</b> tane içerir; çünkü mol atomları saymak için seçilmiş çok büyük bir birimdir."}]},"ortaokul":{"kolay":[{"q":"Avogadro sayısının değeri ve anlamı nedir?","steps":[{"t":"Değer","a":"6,02·10²³","d":"Avogadro sayısı 6,02·10²³ tane/mol değerindedir."},{"t":"Anlam","a":"1 moldeki tanecik","d":"Bu sayı, 1 mol maddedeki tanecik (atom, molekül, iyon) sayısını gösterir."}],"ans":"Avogadro sayısı <b>6,02·10²³</b>'tür ve 1 moldeki tanecik sayısını ifade eder."},{"q":"Tanecik sayısından (N) mol sayısını (n) bulmak için hangi bağıntı kullanılır?","steps":[{"t":"Bağıntı","a":"n = N / N_A","d":"Mol sayısı, tanecik sayısının Avogadro sayısına bölünmesiyle bulunur."},{"t":"Avogadro","a":"6,02·10²³","d":"Burada N_A = 6,02·10²³ tane/mol değerindedir."}],"ans":"Mol sayısı <b>n = N / N_A</b> bağıntısıyla bulunur (N_A = 6,02·10²³)."},{"q":"1,204·10²⁴ tane su molekülü kaç moldür?","steps":[{"t":"Bağıntı","a":"n = N / N_A","d":"Mol sayısı için tanecik sayısını Avogadro sayısına böleriz."},{"t":"İşlem","a":"1,204·10²⁴ ÷ 6,02·10²³","d":"Bölme sonucu 2 çıkar."}],"ans":"1,204·10²⁴ tane su molekülü <b>2 mol</b> eder."},{"q":"3 mol demir atomu kaç tane demir atomu içerir?","steps":[{"t":"Bağıntı","a":"N = n × N_A","d":"Tanecik sayısı, mol sayısı ile Avogadro sayısının çarpımıdır."},{"t":"İşlem","a":"3 × 6,02·10²³","d":"3 × 6,02·10²³ = 1,806·10²⁴ tane."}],"ans":"3 mol demir, <b>1,806·10²⁴</b> tane demir atomu içerir."},{"q":"Avogadro sayısının büyüklüğünü kavramak için nasıl bir somut benzetme yapılır?","steps":[{"t":"Büyüklük","a":"6,02·10²³","d":"Avogadro sayısı 23 sıfır içeren devasa bir sayıdır."},{"t":"Benzetme","a":"su damlaları","d":"Bir mol su damlasını okyanuslara döksek, tüm dünya okyanuslarını kat kat aşardı."}],"ans":"Avogadro sayısı o kadar büyüktür ki 1 mol su damlası <b>dünyanın tüm okyanuslarından</b> bile fazladır."}],"zor":[{"q":"9,03·10²³ tane atom kaç moldür?","steps":[{"t":"Bağıntı","a":"n = N / N_A","d":"Mol = tanecik sayısı / Avogadro sayısı."},{"t":"İşlem","a":"9,03·10²³ ÷ 6,02·10²³","d":"Bölme sonucu 1,5 çıkar."}],"ans":"9,03·10²³ tane atom <b>1,5 mol</b> eder."},{"q":"0,25 mol oksijen molekülü (O₂) kaç tane O₂ molekülü içerir?","steps":[{"t":"Bağıntı","a":"N = n × N_A","d":"Tanecik sayısı = mol × Avogadro sayısı."},{"t":"İşlem","a":"0,25 × 6,02·10²³","d":"0,25 × 6,02·10²³ = 1,505·10²³ tane."}],"ans":"0,25 mol O₂, <b>1,505·10²³</b> tane O₂ molekülü içerir."},{"q":"2 mol su molekülü (H₂O) kaç tane hidrojen atomu içerir?","steps":[{"t":"Molekül sayısı","a":"2 × 6,02·10²³","d":"2 mol su, 2 × 6,02·10²³ = 1,204·10²⁴ tane su molekülü demektir."},{"t":"H atomu sayısı","a":"× 2","d":"Her su molekülünde 2 hidrojen atomu vardır, bu yüzden 1,204·10²⁴ × 2 = 2,408·10²⁴ tane H atomu bulunur."}],"ans":"2 mol su, <b>2,408·10²⁴</b> tane hidrojen atomu içerir."},{"q":"Bir öğrenci '1 mol elektron, 1 mol gezegenden azdır' diyor; bu doğru mudur?","steps":[{"t":"1 mol elektron","a":"6,02·10²³ tane","d":"1 mol elektron, 6,02·10²³ tane elektron demektir."},{"t":"Karşılaştırma","a":"gezegenden çok fazla","d":"Evrendeki gezegen sayısı bunun yanında çok küçük kalır; dolayısıyla ifade yanlıştır."}],"ans":"İfade <b>yanlıştır</b>; 1 mol elektron (6,02·10²³), evrendeki gezegen sayısından çok daha fazladır."},{"q":"3,01·10²³ tane karbon atomunun mol sayısı kaçtır ve bu hangi bağıntıyla bulunur?","steps":[{"t":"Bağıntı","a":"n = N / N_A","d":"Mol sayısını bulmak için tanecik sayısını Avogadro sayısına böleriz."},{"t":"İşlem","a":"3,01·10²³ ÷ 6,02·10²³","d":"Bölme sonucu 0,5 çıkar."}],"ans":"3,01·10²³ tane karbon atomu <b>0,5 mol</b> eder (n = N / N_A bağıntısıyla)."}]},"lise":{"kolay":[{"q":"Avogadro sayısının (N_A) tam değeri nedir ve hangi büyüklüğü tanımlar?","steps":[{"t":"Değer","a":"6,02·10²³ tane/mol","d":"Avogadro sayısı yaklaşık 6,02·10²³ tane/mol olarak alınır."},{"t":"Tanım","a":"1 moldeki tanecik","d":"Bir moldeki temel tanecik (atom, molekül, iyon, elektron) sayısını verir; mol ile tanecik sayısı arasındaki dönüşüm sabitidir."}],"ans":"N_A = <b>6,02·10²³ tane/mol</b>'dür ve 1 moldeki tanecik sayısını tanımlar."},{"q":"Tanecik sayısı (N) ile mol sayısı (n) arasındaki dönüşüm bağıntıları nelerdir?","steps":[{"t":"Mole çevirme","a":"n = N / N_A","d":"Tanecik sayısını mole çevirmek için Avogadro sayısına böleriz."},{"t":"Taneciğe çevirme","a":"N = n × N_A","d":"Mol sayısını tanecik sayısına çevirmek için Avogadro sayısıyla çarparız."}],"ans":"Dönüşüm bağıntıları <b>n = N / N_A</b> ve <b>N = n × N_A</b>'dır (N_A = 6,02·10²³)."},{"q":"1,806·10²⁴ tane azot molekülü (N₂) kaç moldür?","steps":[{"t":"Bağıntı","a":"n = N / N_A","d":"Mol sayısını bulmak için tanecik sayısını Avogadro sayısına böleriz."},{"t":"İşlem","a":"1,806·10²⁴ ÷ 6,02·10²³","d":"Bölme sonucu 3 çıkar."}],"ans":"1,806·10²⁴ tane N₂ molekülü <b>3 mol</b> eder."},{"q":"Avogadro sayısının büyüklüğünü kavramak için 'mol mertebesi' nasıl somutlaştırılır?","steps":[{"t":"Mertebe","a":"10²³","d":"6,02·10²³ sayısı, sıradan günlük sayıların çok ötesinde, 23 basamaklı bir büyüklüktür."},{"t":"Benzetme","a":"saniye-evren yaşı","d":"Evrenin yaşı saniye cinsinden yaklaşık 10¹⁷'dir; Avogadro sayısı bundan bile milyonlarca kat büyüktür."}],"ans":"Avogadro sayısı (6,02·10²³), evrenin saniye cinsinden yaşından (~10¹⁷) bile <b>milyonlarca kat</b> büyük, devasa bir sayıdır."},{"q":"Eşit mol sayısındaki iki farklı madde örneği için hangi nicelik kesinlikle eşittir?","steps":[{"t":"Eşit mol","a":"n aynı","d":"İki örneğin mol sayıları eşitse, n değerleri aynıdır."},{"t":"Tanecik sayısı","a":"N = n·N_A eşit","d":"N = n × N_A olduğundan ve N_A sabit olduğundan, tanecik sayıları da eşit olur."}],"ans":"Eşit mol sayısındaki iki örneğin <b>tanecik sayıları</b> birbirine kesinlikle eşittir (kütleleri ise farklı olabilir)."}],"zor":[{"q":"0,2 mol CO₂ molekülünde toplam kaç tane atom (C ve O birlikte) bulunur?","steps":[{"t":"Molekül sayısı","a":"0,2 × 6,02·10²³","d":"0,2 mol CO₂, 0,2 × 6,02·10²³ = 1,204·10²³ tane CO₂ molekülü demektir."},{"t":"Atom sayısı","a":"× 3 atom","d":"Her CO₂ molekülünde 1 C + 2 O = 3 atom vardır; 1,204·10²³ × 3 = 3,612·10²³ tane atom bulunur."}],"ans":"0,2 mol CO₂'de toplam <b>3,612·10²³</b> tane atom bulunur."},{"q":"1 mol H₂O'daki toplam tanecik (atom) sayısı, 1 mol O₂'deki atom sayısından farklı mıdır?","steps":[{"t":"1 mol H₂O","a":"3 atom × N_A","d":"Her su molekülünde 3 atom (2H + 1O) vardır; 1 mol için 3 × 6,02·10²³ = 1,806·10²⁴ atom."},{"t":"1 mol O₂","a":"2 atom × N_A","d":"Her O₂ molekülünde 2 atom vardır; 1 mol için 2 × 6,02·10²³ = 1,204·10²⁴ atom."}],"ans":"Evet farklıdır; 1 mol H₂O <b>1,806·10²⁴</b> atom, 1 mol O₂ ise 1,204·10²⁴ atom içerir."},{"q":"Bir gaz örneğinde 4,816·10²⁴ tane molekül varsa bu kaç moldür ve sonuç hangi bağıntıyla doğrulanır?","steps":[{"t":"Bağıntı","a":"n = N / N_A","d":"Mol sayısı, tanecik sayısının Avogadro sayısına bölümüdür."},{"t":"İşlem","a":"4,816·10²⁴ ÷ 6,02·10²³","d":"Bölme sonucu 8 çıkar; ters yönde 8 × 6,02·10²³ = 4,816·10²⁴ olduğundan sonuç doğrulanır."}],"ans":"4,816·10²⁴ tane molekül <b>8 mol</b> eder (n = N / N_A ile bulunur, çarparak doğrulanır)."},{"q":"Avogadro sayısının bu kadar büyük seçilmesinin gram-tanecik ilişkisindeki kimyasal nedeni nedir?","steps":[{"t":"Atom kütlesi ölçeği","a":"çok küçük","d":"Tek bir atomun kütlesi gram cinsinden 10⁻²³ ile 10⁻²² gibi son derece küçük değerlerdir."},{"t":"Mol mantığı","a":"gram düzeyine taşıma","d":"Avogadro sayısı kadar atom bir araya gelince kütle gram mertebesine çıkar; böylece tartılabilir ('1 mol C = 12 g')."}],"ans":"Avogadro sayısı, tek atomun çok küçük kütlesini tartılabilir <b>gram düzeyine</b> taşıyacak büyüklükte seçilmiştir; bu yüzden çok büyüktür."},{"q":"İki kaptan birinde 0,5 mol He gazı, diğerinde 0,5 mol Ne gazı varsa tanecik sayıları kıyaslandığında ne söylenir?","steps":[{"t":"Mol eşitliği","a":"0,5 mol = 0,5 mol","d":"Her iki kapta da mol sayıları eşittir (0,5 mol)."},{"t":"Tanecik sayısı","a":"N = 0,5 × N_A","d":"N = n × N_A olduğundan ikisi de 0,5 × 6,02·10²³ = 3,01·10²³ tane atom içerir; element farkı tanecik sayısını değiştirmez."}],"ans":"Tanecik sayıları <b>eşittir</b> (her ikisi de 3,01·10²³ tane); çünkü eşit moldeki örnekler aynı sayıda tanecik içerir."}]}},"avogadroKutuLise":{"ilkokul":{"kolay":[{"q":"Atomlar çok küçük olduğu için tek tek sayılamaz. Bu yüzden onları gruplayan büyük sayıya ne denir?","steps":[{"t":"Çok küçük","a":"sayılamaz","d":"Atom ve moleküller gözle görülemeyecek kadar küçüktür."},{"t":"Büyük sayma","a":"Avogadro sayısı","d":"Bu kadar çok taneciği saymak için Avogadro sayısı kullanılır."}],"ans":"Çok sayıda taneciği saymak için Avogadro sayısı kullanılır."},{"q":"Avogadro sayısı yaklaşık olarak kaçtır?","fig":"<svg viewBox='0 0 320 150'><text x='160' y='50' font-size='12' text-anchor='middle' fill='#1a2b45'>1 mol</text><text x='160' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>=</text><text x='160' y='115' font-size='15' text-anchor='middle' fill='#e0552b'>6,02·10²³ tane</text></svg>","steps":[{"t":"Değer","a":"6,02·10²³","d":"Avogadro sayısı 6,02·10²³ tanedir; çok büyük bir sayıdır."},{"t":"Anlamı","a":"1 moldeki tanecik","d":"Bu sayı, 1 moldeki tanecik sayısını verir."}],"ans":"Avogadro sayısı yaklaşık 6,02·10²³ tanedir."},{"q":"Bir düzine 12, bir mol ise 6,02·10²³ tanecik demektir. Hangisi daha büyük bir miktardır?","steps":[{"t":"Sayıları karşılaştır","a":"6,02·10²³ ≫ 12","d":"Avogadro sayısı 12'den çok çok büyüktür."},{"t":"Sonuç","a":"mol","d":"Bu yüzden 1 mol, 1 düzineden kıyaslanamayacak kadar büyüktür."}],"ans":"1 mol (6,02·10²³ tanecik), 1 düzineden (12) çok daha büyük bir miktardır."},{"q":"1 mol bilye 6,02·10²³ bilye demektir. 2 mol bilye 1 molden daha mı çoktur?","steps":[{"t":"Karşılaştır","a":"2 mol > 1 mol","d":"2 mol, 1 molün iki katı kadar tanecik içerir."},{"t":"Sonuç","a":"daha çok","d":"Bu yüzden 2 mol bilye 1 mol bilyeden daha çoktur."}],"ans":"Evet; 2 mol bilye, 1 mol bilyenin iki katı kadar tanecik içerir."},{"q":"Su damlası gözle görülür ama içinde çok sayıda su molekülü vardır. Bu doğru mu?","steps":[{"t":"Damla görünür","a":"gözle","d":"Bir su damlasını gözümüzle görebiliriz."},{"t":"İçindeki tanecik","a":"çok sayıda","d":"Ama bu damlanın içinde gözle görülemeyen milyarlarca su molekülü bulunur."}],"ans":"Evet; küçük bir su damlasında bile çok büyük sayıda su molekülü vardır."}],"zor":[{"q":"1 mol madde 6,02·10²³ tanecik içeriyorsa, 2 mol madde kaç tanecik içerir?","steps":[{"t":"Bir mol","a":"6,02·10²³","d":"1 mol 6,02·10²³ tanecik içerir."},{"t":"İki ile çarp","a":"2 × 6,02·10²³","d":"2 mol için ikiyle çarparız: 2 × 6,02·10²³ = 12,04·10²³ = 1,204·10²⁴."}],"ans":"2 mol madde 1,204·10²⁴ tanecik içerir."},{"q":"1 mol 6,02·10²³ tanecik ise, yarım (0,5) mol kaç tanecik içerir?","steps":[{"t":"Bir mol","a":"6,02·10²³","d":"1 mol 6,02·10²³ tanecik içerir."},{"t":"Yarısını al","a":"6,02·10²³ ÷ 2","d":"Yarım mol için ikiye böleriz: 3,01·10²³ tanecik."}],"ans":"0,5 mol madde 3,01·10²³ tanecik içerir."},{"q":"Bir kapta 1,204·10²⁴ tane atom var. Bu kaç mol eder? (1 mol = 6,02·10²³)","steps":[{"t":"Avogadro sayısı","a":"6,02·10²³","d":"1 mol 6,02·10²³ tanedir."},{"t":"Böl","a":"1,204·10²⁴ ÷ 6,02·10²³","d":"Tanecik sayısını Avogadro sayısına böleriz: 1,204·10²⁴ ÷ 6,02·10²³ = 2 mol."}],"ans":"1,204·10²⁴ tane atom 2 mol eder."},{"q":"3 mol helyum gazında kaç tane helyum atomu vardır? (1 mol = 6,02·10²³)","steps":[{"t":"Bir mol","a":"6,02·10²³","d":"1 mol helyumda 6,02·10²³ atom vardır."},{"t":"Üç ile çarp","a":"3 × 6,02·10²³","d":"3 mol için üçle çarparız: 3 × 6,02·10²³ = 1,806·10²⁴ atom."}],"ans":"3 mol helyumda 1,806·10²⁴ tane atom vardır."},{"q":"3,01·10²³ tane şeker molekülü kaç mol eder? (1 mol = 6,02·10²³)","steps":[{"t":"Avogadro sayısı","a":"6,02·10²³","d":"1 mol 6,02·10²³ tanedir."},{"t":"Böl","a":"3,01·10²³ ÷ 6,02·10²³","d":"Tanecik sayısını Avogadro sayısına böleriz: sonuç 0,5 mol."}],"ans":"3,01·10²³ tane şeker molekülü 0,5 mol eder."}]},"ortaokul":{"kolay":[{"q":"Mol ile tanecik sayısı arasındaki bağıntı nedir?","steps":[{"t":"Tanecik sayısı","a":"N = n · N_A","d":"Tanecik sayısı, mol sayısının Avogadro sayısı ile çarpımıdır."},{"t":"Tersi","a":"n = N / N_A","d":"Mol sayısı ise tanecik sayısının Avogadro sayısına bölümüdür."}],"ans":"N = n · N_A ve n = N / N_A; N_A = 6,02·10²³ tane/mol."},{"q":"2 mol demir (Fe) atomunda kaç tane atom vardır?","steps":[{"t":"Bağıntı","a":"N = n · N_A","d":"Tanecik sayısı = mol × Avogadro sayısı."},{"t":"Hesapla","a":"2 × 6,02·10²³","d":"N = 2 × 6,02·10²³ = 1,204·10²⁴ atom."}],"ans":"2 mol demirde 1,204·10²⁴ tane atom vardır."},{"q":"9,03·10²³ tane su molekülü kaç moldür? (N_A = 6,02·10²³)","steps":[{"t":"Bağıntı","a":"n = N / N_A","d":"Mol = tanecik sayısı ÷ Avogadro sayısı."},{"t":"Hesapla","a":"9,03·10²³ ÷ 6,02·10²³","d":"n = 9,03·10²³ ÷ 6,02·10²³ = 1,5 mol."}],"ans":"9,03·10²³ tane su molekülü 1,5 moldür."},{"q":"1 mol su (H₂O) molekülünde toplam kaç atom bulunur? (N_A = 6,02·10²³)","fig":"<svg viewBox='0 0 320 150'><circle cx='160' cy='70' r='20' fill='#e0552b' stroke='#1a2b45'/><circle cx='120' cy='100' r='13' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='200' cy='100' r='13' fill='#cfd8e8' stroke='#1a2b45'/><line x1='145' y1='82' x2='128' y2='92' stroke='#1a2b45'/><line x1='175' y1='82' x2='192' y2='92' stroke='#1a2b45'/><text x='160' y='75' font-size='10' text-anchor='middle' fill='#fff'>O</text><text x='120' y='104' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><text x='200' y='104' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text></svg>","steps":[{"t":"Molekülde atom","a":"3 atom","d":"Bir su molekülünde 2 H + 1 O = 3 atom vardır."},{"t":"Mol başına","a":"3 × N_A","d":"1 mol suda 3 × 6,02·10²³ = 1,806·10²⁴ atom bulunur."}],"ans":"1 mol suda toplam 1,806·10²⁴ tane atom bulunur."},{"q":"0,5 mol oksijen gazında (O₂) kaç tane oksijen molekülü vardır?","steps":[{"t":"Bağıntı","a":"N = n · N_A","d":"Molekül sayısı = mol × Avogadro sayısı."},{"t":"Hesapla","a":"0,5 × 6,02·10²³","d":"N = 0,5 × 6,02·10²³ = 3,01·10²³ molekül."}],"ans":"0,5 mol O₂ gazında 3,01·10²³ tane oksijen molekülü vardır."}],"zor":[{"q":"0,5 mol oksijen gazında (O₂) kaç tane oksijen atomu vardır?","steps":[{"t":"Molekül sayısı","a":"3,01·10²³","d":"0,5 mol O₂ = 0,5 × 6,02·10²³ = 3,01·10²³ molekül."},{"t":"Atoma çevir","a":"× 2","d":"Her O₂ molekülünde 2 atom olduğundan: 3,01·10²³ × 2 = 6,02·10²³ atom."}],"ans":"0,5 mol O₂ gazında 6,02·10²³ tane oksijen atomu vardır."},{"q":"36 gram su (H₂O, 18 g/mol) kaç tane su molekülü içerir? (N_A = 6,02·10²³)","steps":[{"t":"Mol bul","a":"n = m / M","d":"n = 36 ÷ 18 = 2 mol."},{"t":"Molekül sayısı","a":"N = n · N_A","d":"N = 2 × 6,02·10²³ = 1,204·10²⁴ molekül."}],"ans":"36 gram su 1,204·10²⁴ tane su molekülü içerir."},{"q":"NK'da 44,8 litre gaz kaç tane molekül içerir? (1 mol = 22,4 L, N_A = 6,02·10²³)","steps":[{"t":"Mol bul","a":"n = V / 22,4","d":"n = 44,8 ÷ 22,4 = 2 mol."},{"t":"Molekül sayısı","a":"N = n · N_A","d":"N = 2 × 6,02·10²³ = 1,204·10²⁴ molekül."}],"ans":"NK'da 44,8 litre gaz 1,204·10²⁴ tane molekül içerir."},{"q":"0,25 mol karbondioksitte (CO₂) toplam kaç tane atom vardır? (N_A = 6,02·10²³)","steps":[{"t":"Molekül sayısı","a":"1,505·10²³","d":"0,25 mol CO₂ = 0,25 × 6,02·10²³ = 1,505·10²³ molekül."},{"t":"Atoma çevir","a":"× 3","d":"Her CO₂'de 3 atom (1 C + 2 O) vardır: 1,505·10²³ × 3 = 4,515·10²³ atom."}],"ans":"0,25 mol CO₂'de toplam 4,515·10²³ tane atom vardır."},{"q":"Bir kapta 1,806·10²⁴ tane atom bulunan demir (Fe, 56 g/mol) örneğinin kütlesi kaç gramdır?","steps":[{"t":"Mol bul","a":"n = N / N_A","d":"n = 1,806·10²⁴ ÷ 6,02·10²³ = 3 mol."},{"t":"Kütle bul","a":"m = n · M","d":"m = 3 × 56 = 168 g."}],"ans":"1,806·10²⁴ tane demir atomu içeren örneğin kütlesi 168 gramdır."}]},"lise":{"kolay":[{"q":"Tanecik, mol, kütle ve hacim arasındaki dönüşümlerde ortak köprü hangi büyüklüktür?","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='65' width='90' height='30' rx='6' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='85' font-size='12' text-anchor='middle' fill='#fff'>MOL</text><text x='40' y='35' font-size='10' text-anchor='middle' fill='#1a2b45'>tanecik</text><text x='280' y='35' font-size='10' text-anchor='middle' fill='#1a2b45'>kütle</text><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>hacim (gaz)</text><line x1='60' y1='45' x2='120' y2='68' stroke='#1a2b45'/><line x1='260' y1='45' x2='200' y2='68' stroke='#1a2b45'/><line x1='160' y1='95' x2='160' y2='135' stroke='#1a2b45'/><text x='75' y='62' font-size='8' fill='#1a2b45'>÷N_A</text><text x='215' y='62' font-size='8' fill='#1a2b45'>÷M</text><text x='165' y='120' font-size='8' fill='#1a2b45'>÷22,4</text></svg>","steps":[{"t":"Ortak büyüklük","a":"mol","d":"Tanecik sayısı, kütle ve gaz hacmi doğrudan birbirine değil, mol üzerinden bağlanır."},{"t":"Bağıntılar","a":"n = N/N_A = m/M = V/22,4","d":"Mol; tanecik (N_A), kütle (M) ve NK hacmi (22,4 L) ile köprü kurar."}],"ans":"Tüm dönüşümlerin ortak köprüsü mol'dür: n = N/N_A = m/M = V/22,4."},{"q":"NK'da 2 mol gazın hacmi ve içerdiği molekül sayısı nedir? (N_A=6,02·10²³)","steps":[{"t":"Hacim","a":"V = n·22,4","d":"V = 2 × 22,4 = 44,8 L."},{"t":"Molekül sayısı","a":"N = n·N_A","d":"N = 2 × 6,02·10²³ = 1,204·10²⁴ molekül."}],"ans":"NK'da 2 mol gaz 44,8 litredir ve 1,204·10²⁴ tane molekül içerir."},{"q":"3,01·10²³ tane CO₂ molekülünün kütlesi kaç gramdır? (CO₂=44 g/mol, N_A=6,02·10²³)","steps":[{"t":"Mol bul","a":"n = N / N_A","d":"n = 3,01·10²³ ÷ 6,02·10²³ = 0,5 mol."},{"t":"Kütle bul","a":"m = n · M","d":"m = 0,5 × 44 = 22 g."}],"ans":"3,01·10²³ tane CO₂ molekülünün kütlesi 22 gramdır."},{"q":"1 mol glikozda (C₆H₁₂O₆) toplam kaç tane atom vardır? (N_A=6,02·10²³)","steps":[{"t":"Molekülde atom","a":"24 atom","d":"C₆H₁₂O₆'da 6 + 12 + 6 = 24 atom vardır."},{"t":"Mol başına","a":"24 · N_A","d":"1 mol glikozda 24 × 6,02·10²³ = 1,4448·10²⁵ atom bulunur."}],"ans":"1 mol glikozda toplam yaklaşık 1,4448·10²⁵ tane atom vardır."},{"q":"Bir su damlasında yaklaşık 0,05 g su (H₂O, 18 g/mol) varsa, kaç tane su molekülü içerir? (N_A=6,02·10²³)","steps":[{"t":"Mol bul","a":"n = m / M","d":"n = 0,05 ÷ 18 ≈ 0,00278 mol."},{"t":"Molekül sayısı","a":"N = n · N_A","d":"N ≈ 0,00278 × 6,02·10²³ ≈ 1,67·10²¹ molekül."}],"ans":"Yaklaşık 0,05 gramlık bir su damlasında yaklaşık 1,67·10²¹ tane su molekülü bulunur."}],"zor":[{"q":"NK'da 11,2 litre CO₂ gazında toplam kaç tane atom vardır? (1 mol=22,4 L, N_A=6,02·10²³)","fig":"<svg viewBox='0 0 320 160'><text x='160' y='28' font-size='10' text-anchor='middle' fill='#1a2b45'>11,2 L CO₂ (NK)</text><text x='160' y='58' font-size='10' text-anchor='middle' fill='#1a2b45'>n = 11,2 ÷ 22,4 = 0,5 mol</text><text x='160' y='88' font-size='10' text-anchor='middle' fill='#1a2b45'>molekül = 0,5 × 6,02·10²³ = 3,01·10²³</text><text x='160' y='118' font-size='10' text-anchor='middle' fill='#1a2b45'>atom = 3,01·10²³ × 3</text><text x='160' y='146' font-size='12' text-anchor='middle' fill='#e0552b'>= 9,03·10²³ atom</text></svg>","steps":[{"t":"Mol bul","a":"n = V / 22,4","d":"n = 11,2 ÷ 22,4 = 0,5 mol."},{"t":"Molekül sayısı","a":"3,01·10²³","d":"N = 0,5 × 6,02·10²³ = 3,01·10²³ molekül."},{"t":"Atoma çevir","a":"× 3","d":"Her CO₂'de 3 atom vardır: 3,01·10²³ × 3 = 9,03·10²³ atom."}],"ans":"NK'da 11,2 litre CO₂'de toplam 9,03·10²³ tane atom vardır."},{"q":"3,612·10²⁴ tane su molekülü içeren örneğin kütlesi ve NK hacmi (buhar) nedir? (H₂O=18 g/mol, N_A=6,02·10²³)","steps":[{"t":"Mol bul","a":"n = N / N_A","d":"n = 3,612·10²⁴ ÷ 6,02·10²³ = 6 mol."},{"t":"Kütle bul","a":"m = n · M","d":"m = 6 × 18 = 108 g."},{"t":"Hacim bul","a":"V = n · 22,4","d":"Buhar (gaz) için NK'da V = 6 × 22,4 = 134,4 L."}],"ans":"Örnek 6 mol olup kütlesi 108 g, NK'da buhar hacmi 134,4 litredir."},{"q":"2 mol karbondioksitte (CO₂) kaç tane oksijen atomu bulunur? (N_A=6,02·10²³)","steps":[{"t":"Molekül sayısı","a":"N = n · N_A","d":"N = 2 × 6,02·10²³ = 1,204·10²⁴ molekül."},{"t":"O atomu sayısı","a":"× 2","d":"Her CO₂'de 2 oksijen vardır: 1,204·10²⁴ × 2 = 2,408·10²⁴ oksijen atomu."}],"ans":"2 mol CO₂'de 2,408·10²⁴ tane oksijen atomu bulunur."},{"q":"9 gram su (H₂O, 18 g/mol) örneğinde kaç tane hidrojen atomu vardır? (N_A=6,02·10²³)","steps":[{"t":"Mol bul","a":"n = m / M","d":"n = 9 ÷ 18 = 0,5 mol su."},{"t":"Molekül sayısı","a":"3,01·10²³","d":"N = 0,5 × 6,02·10²³ = 3,01·10²³ su molekülü."},{"t":"H atomu sayısı","a":"× 2","d":"Her suda 2 hidrojen vardır: 3,01·10²³ × 2 = 6,02·10²³ hidrojen atomu."}],"ans":"9 gram suda 6,02·10²³ tane hidrojen atomu vardır."},{"q":"Eşit kütlede (örneğin 16'şar gram) O₂ (32 g/mol) ve CH₄ (16 g/mol) örneklerinden hangisi daha çok molekül içerir? (N_A=6,02·10²³)","steps":[{"t":"O₂ molü","a":"0,5 mol","d":"16 ÷ 32 = 0,5 mol O₂ → 0,5 × 6,02·10²³ = 3,01·10²³ molekül."},{"t":"CH₄ molü","a":"1 mol","d":"16 ÷ 16 = 1 mol CH₄ → 1 × 6,02·10²³ = 6,02·10²³ molekül."},{"t":"Karşılaştır","a":"CH₄ daha çok","d":"Molar kütlesi küçük olan CH₄ daha çok mol, dolayısıyla daha çok molekül içerir."}],"ans":"Eşit kütlede molar kütlesi küçük olan CH₄ daha çok molekül içerir (6,02·10²³'e karşı 3,01·10²³)."}]}},"avogadroSayisi":{"ilkokul":{"kolay":[{"q":"Bir düzine kalem 12 kalem demektir. Peki bir kelimeyle çok büyük bir sayıyı belirtmek neden kolaylık sağlar?","steps":[{"t":"Düzine örneği","a":"12 demek","d":"Düzine deyince 12 tane anlarız; tek tek saymaya gerek kalmaz."},{"t":"Kimyada da öyle","a":"mol kullanılır","d":"Kimyada çok küçük tanecikleri saymak için mol adı verilen bir sayı paketi kullanılır."}],"ans":"Bir kelime (düzine gibi) büyük sayıyı kısaca anlatır; kimyada da çok sayıda taneciği saymak için mol kullanılır."},{"q":"Çok çok küçük tanecikleri (atom gibi) saymak için kimyacılar hangi büyük sayıyı kullanır?","steps":[{"t":"Sayının adı","a":"Avogadro sayısı","d":"Tanecikleri saymak için Avogadro sayısı denilen çok büyük bir sayı kullanılır."},{"t":"Ne kadar büyük","a":"6,02·10²³","d":"Bu sayı 6,02·10²³ tanedir; yani 602 den sonra 21 sıfır kadar büyük bir sayıdır."}],"ans":"Kimyacılar çok küçük tanecikleri saymak için Avogadro sayısını (6,02·10²³) kullanır."},{"q":"1 mol madde içinde kaç tane tanecik vardır?","fig":"<svg viewBox='0 0 300 100'><text x='10' y='40' font-size='15' fill='#1a2b45'>1 mol = ?</text><text x='10' y='75' font-size='15' fill='#e0552b'>6,02·10²³ tane</text></svg>","steps":[{"t":"Mol nedir","a":"bir paket sayı","d":"Mol, belli sayıda taneciği ifade eden bir pakettir."},{"t":"Kaç tane","a":"6,02·10²³","d":"Bir mol içinde her zaman 6,02·10²³ tane tanecik bulunur."}],"ans":"1 mol madde içinde 6,02·10²³ tane tanecik vardır."},{"q":"2 mol madde içinde toplam kaç tane tanecik bulunur?","steps":[{"t":"1 mol kaç tane","a":"6,02·10²³","d":"Bir mol 6,02·10²³ tanecik demektir."},{"t":"2 katına çıkar","a":"2 mol = 2 katı","d":"İki mol, bir molün iki katı olduğundan tanecik sayısı da iki katı, yani 12,04·10²³ olur."}],"ans":"2 mol madde içinde 2 × 6,02·10²³ = 12,04·10²³ tanecik bulunur."},{"q":"Yarım (0,5) mol madde içinde kaç tane tanecik vardır?","steps":[{"t":"1 mol kaç tane","a":"6,02·10²³","d":"Bir mol 6,02·10²³ tanecik içerir."},{"t":"Yarısını al","a":"yarısı","d":"Yarım mol, bir molün yarısı kadar tanecik içerir: 6,02·10²³ ün yarısı = 3,01·10²³."}],"ans":"0,5 mol madde içinde 3,01·10²³ tane tanecik vardır."}],"zor":[{"q":"3 mol atom içinde toplam kaç tane atom bulunur?","steps":[{"t":"1 mol kaç atom","a":"6,02·10²³","d":"Bir mol atom, 6,02·10²³ tane atom demektir."},{"t":"3 katına çıkar","a":"3 × 6,02·10²³","d":"3 mol için tanecik sayısı 3 × 6,02·10²³ = 18,06·10²³ atom olur."}],"ans":"3 mol atom içinde 3 × 6,02·10²³ = 18,06·10²³ tane atom bulunur."},{"q":"Elinizde 12,04·10²³ tane tanecik varsa bu kaç mol eder?","steps":[{"t":"1 mol kaç tane","a":"6,02·10²³","d":"Bir mol 6,02·10²³ tanecik içerir."},{"t":"Böl","a":"12,04 ÷ 6,02 = 2","d":"12,04·10²³ ü 6,02·10²³ e bölersek 2 çıkar; yani 2 mol eder."}],"ans":"12,04·10²³ tane tanecik 2 mol eder."},{"q":"1 tane su molekülünde (H₂O) toplam kaç tane atom vardır?","fig":"<svg viewBox='0 0 300 120'><circle cx='150' cy='55' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='150' y='60' font-size='12' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='80' r='11' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='84' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='190' cy='80' r='11' fill='#cfd8e8' stroke='#1a2b45'/><text x='190' y='84' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><text x='150' y='112' font-size='12' text-anchor='middle' fill='#1a2b45'>2 H + 1 O = 3 atom</text></svg>","steps":[{"t":"Atomları say","a":"2 H + 1 O","d":"Su molekülü 2 hidrojen ve 1 oksijen atomundan oluşur."},{"t":"Topla","a":"2 + 1 = 3","d":"Toplam atom sayısı 2 + 1 = 3 tür."}],"ans":"Bir su molekülünde (H₂O) toplam 3 tane atom vardır."},{"q":"1 mol su (H₂O) molekülünde kaç mol atom bulunur?","steps":[{"t":"1 molekülde atom","a":"3 atom","d":"Bir su molekülünde 2 hidrojen ve 1 oksijen olmak üzere 3 atom vardır."},{"t":"Mole çevir","a":"3 mol atom","d":"1 mol molekülde her molekül 3 atom içerdiğinden toplam 3 mol atom bulunur."}],"ans":"1 mol su molekülünde 3 mol atom bulunur (2 mol H + 1 mol O)."},{"q":"Bir mol şeker ile bir mol tuz karşılaştırılırsa hangisinde daha çok tanecik vardır?","steps":[{"t":"Mol ne sayar","a":"tanecik sayısı","d":"Mol, maddenin türünden bağımsız olarak hep aynı tanecik sayısını ifade eder."},{"t":"Karşılaştır","a":"eşit","d":"Her iki maddede de 1 mol = 6,02·10²³ tanecik olduğundan tanecik sayıları eşittir."}],"ans":"Bir mol şeker ile bir mol tuzda tanecik sayıları eşittir; her ikisinde de 6,02·10²³ tanecik vardır."}]},"ortaokul":{"kolay":[{"q":"Avogadro sayısı nedir ve neyi ifade eder?","steps":[{"t":"Değeri","a":"6,02·10²³","d":"Avogadro sayısı N_A = 6,02·10²³ tane/mol değerindedir."},{"t":"Anlamı","a":"1 moldeki tanecik","d":"Bir mol maddedeki tanecik (atom, molekül veya iyon) sayısını gösterir."}],"ans":"Avogadro sayısı N_A = 6,02·10²³ tane/mol olup 1 moldeki tanecik sayısını ifade eder."},{"q":"Mol sayısı ile tanecik sayısı arasındaki bağıntı nedir?","fig":"<svg viewBox='0 0 320 90'><text x='10' y='40' font-size='14' fill='#1a2b45'>tanecik = mol × N_A</text><text x='10' y='72' font-size='13' fill='#e0552b'>N_A = 6,02·10²³</text></svg>","steps":[{"t":"Formül","a":"N = n × N_A","d":"Tanecik sayısı N, mol sayısı n ile Avogadro sayısının çarpımıdır: N = n × N_A."},{"t":"Ters yön","a":"n = N / N_A","d":"Mol sayısı isteniyorsa tanecik sayısı Avogadro sayısına bölünür."}],"ans":"Tanecik sayısı N = mol × N_A; mol sayısı ise n = tanecik / N_A bağıntısıyla bulunur."},{"q":"2 mol demir atomunda kaç tane demir atomu vardır?","steps":[{"t":"Formülü yaz","a":"N = n × N_A","d":"Atom sayısı N = mol × Avogadro sayısı ile bulunur."},{"t":"Yerine koy","a":"2 × 6,02·10²³","d":"N = 2 × 6,02·10²³ = 12,04·10²³ atomdur."}],"ans":"2 mol demir atomunda 2 × 6,02·10²³ = 12,04·10²³ atom vardır."},{"q":"3,01·10²³ tane molekül kaç mol eder?","steps":[{"t":"Formülü yaz","a":"n = N / N_A","d":"Mol sayısı, tanecik sayısının Avogadro sayısına bölünmesiyle bulunur."},{"t":"Yerine koy","a":"3,01 ÷ 6,02 = 0,5","d":"n = 3,01·10²³ / 6,02·10²³ = 0,5 mol eder."}],"ans":"3,01·10²³ tane molekül 0,5 mol eder."},{"q":"1 mol CO₂ molekülünde toplam kaç mol atom vardır?","steps":[{"t":"1 molekülde atom","a":"3 atom","d":"CO₂ molekülü 1 karbon ve 2 oksijen olmak üzere 3 atom içerir."},{"t":"Mole çevir","a":"3 mol atom","d":"1 mol CO₂ molekülünde her molekül 3 atom içerdiğinden toplam 3 mol atom bulunur."}],"ans":"1 mol CO₂ molekülünde 3 mol atom vardır (1 mol C + 2 mol O)."}],"zor":[{"q":"0,25 mol oksijen gazı (O₂) molekülünde kaç tane oksijen atomu vardır?","fig":"<svg viewBox='0 0 300 100'><circle cx='120' cy='50' r='16' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='50' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='140' y='90' font-size='12' text-anchor='middle' fill='#1a2b45'>O₂: 1 molekül = 2 atom</text></svg>","steps":[{"t":"Molekül sayısı","a":"0,25 × N_A","d":"Molekül sayısı = 0,25 × 6,02·10²³ = 1,505·10²³ molekül."},{"t":"Atoma çevir","a":"× 2","d":"Her O₂ molekülünde 2 atom olduğundan atom sayısı 1,505·10²³ × 2 = 3,01·10²³ atomdur."}],"ans":"0,25 mol O₂ içinde 3,01·10²³ tane oksijen atomu vardır."},{"q":"1 mol Na₂SO₄ içinde toplam kaç tane iyon bulunur? (Na⁺ ve SO₄²⁻)","steps":[{"t":"İyonları say","a":"2 Na⁺ + 1 SO₄²⁻","d":"Bir Na₂SO₄ birim formülü, suda 2 tane Na⁺ ve 1 tane SO₄²⁻ olmak üzere 3 iyon verir."},{"t":"Toplam iyon","a":"3 × N_A","d":"1 mol Na₂SO₄ için iyon sayısı 3 × 6,02·10²³ = 18,06·10²³ iyondur."}],"ans":"1 mol Na₂SO₄ içinde 3 × 6,02·10²³ = 18,06·10²³ tane iyon bulunur."},{"q":"6,02·10²² tane atom kaç mol eder?","steps":[{"t":"Formülü yaz","a":"n = N / N_A","d":"Mol sayısı, atom sayısının Avogadro sayısına bölünmesiyle bulunur."},{"t":"Yerine koy","a":"6,02·10²² / 6,02·10²³","d":"n = 6,02·10²² / 6,02·10²³ = 0,1 mol eder (üs farkı bir basamak)."}],"ans":"6,02·10²² tane atom 0,1 mol eder."},{"q":"2 mol NH₃ molekülünde toplam kaç mol atom ve kaç mol hidrojen atomu vardır?","steps":[{"t":"1 molekülde atom","a":"1 N + 3 H = 4","d":"NH₃ molekülü 1 azot ve 3 hidrojen olmak üzere 4 atom içerir."},{"t":"2 mole çıkar","a":"8 mol atom, 6 mol H","d":"2 mol NH₃ için toplam atom = 4 × 2 = 8 mol; hidrojen atomu = 3 × 2 = 6 moldür."}],"ans":"2 mol NH₃ içinde toplam 8 mol atom bulunur; bunun 6 molü hidrojen atomudur."},{"q":"1,204·10²⁴ tane su molekülü kaç mol su eder ve içinde kaç mol hidrojen atomu vardır?","steps":[{"t":"Mole çevir","a":"2 mol su","d":"n = 1,204·10²⁴ / 6,02·10²³ = 2 mol su eder."},{"t":"H atomunu bul","a":"4 mol H","d":"Her H₂O molekülü 2 hidrojen içerdiğinden 2 mol suda 2 × 2 = 4 mol hidrojen atomu bulunur."}],"ans":"1,204·10²⁴ tane su molekülü 2 mol su eder ve içinde 4 mol hidrojen atomu vardır."}]},"lise":{"kolay":[{"q":"Avogadro sayısının değeri, birimi ve mol kavramıyla ilişkisi nedir?","steps":[{"t":"Değer ve birim","a":"6,02·10²³ tane/mol","d":"Avogadro sayısı N_A = 6,02·10²³ tane/mol olup 1 mol maddedeki tanecik sayısını verir."},{"t":"Mol ilişkisi","a":"sayma birimi","d":"Mol, tıpkı düzine gibi bir sayma birimidir; 1 mol her zaman N_A kadar tanecik içerir, madde türünden bağımsızdır."}],"ans":"Avogadro sayısı N_A = 6,02·10²³ tane/mol olup mol denilen sayma biriminin temelidir; 1 mol madde her zaman N_A tanecik içerir."},{"q":"0,2 mol gümüş (Ag) atomunda kaç tane atom bulunur?","steps":[{"t":"Formül","a":"N = n × N_A","d":"Atom sayısı, mol sayısı ile Avogadro sayısının çarpımıdır."},{"t":"Yerine koy","a":"0,2 × 6,02·10²³","d":"N = 0,2 × 6,02·10²³ = 1,204·10²³ atomdur."}],"ans":"0,2 mol gümüş atomunda 1,204·10²³ tane atom bulunur."},{"q":"3,01·10²⁴ tane karbon atomu kaç mol eder?","steps":[{"t":"Formül","a":"n = N / N_A","d":"Mol sayısı, tanecik sayısının Avogadro sayısına bölünmesiyle bulunur."},{"t":"Yerine koy","a":"3,01·10²⁴ / 6,02·10²³ = 5","d":"n = 3,01·10²⁴ / 6,02·10²³ = 5 mol eder (üs farkı dikkate alınır)."}],"ans":"3,01·10²⁴ tane karbon atomu 5 mol eder."},{"q":"1 mol CaCl₂ suda tamamen çözündüğünde kaç mol ve kaç tane iyon oluşur?","fig":"<svg viewBox='0 0 320 90'><text x='10' y='40' font-size='14' fill='#1a2b45'>CaCl₂ → Ca²⁺ + 2Cl⁻</text><text x='10' y='72' font-size='12' fill='#e0552b'>1 birim = 3 iyon</text></svg>","steps":[{"t":"İyonları yaz","a":"1 Ca²⁺ + 2 Cl⁻","d":"CaCl₂, suda 1 mol Ca²⁺ ve 2 mol Cl⁻ olmak üzere toplam 3 mol iyon verir."},{"t":"Taneciğe çevir","a":"3 × N_A","d":"3 mol iyon, 3 × 6,02·10²³ = 18,06·10²³ tane iyona karşılık gelir."}],"ans":"1 mol CaCl₂ çözündüğünde 3 mol (18,06·10²³ tane) iyon oluşur (1 mol Ca²⁺ + 2 mol Cl⁻)."},{"q":"1 mol C₆H₁₂O₆ (glikoz) molekülünde toplam kaç mol atom vardır?","steps":[{"t":"Atomları say","a":"6 + 12 + 6 = 24","d":"Glikoz molekülü 6 karbon, 12 hidrojen ve 6 oksijen olmak üzere 24 atom içerir."},{"t":"Mole çevir","a":"24 mol atom","d":"1 mol glikozda her molekül 24 atom içerdiğinden toplam 24 mol atom bulunur."}],"ans":"1 mol glikozda (C₆H₁₂O₆) toplam 24 mol atom vardır."}],"zor":[{"q":"9,03·10²³ tane SO₃ molekülünde toplam kaç tane oksijen atomu vardır?","fig":"<svg viewBox='0 0 320 110'><circle cx='160' cy='55' r='16' fill='#33415588' stroke='#1a2b45'/><text x='160' y='60' font-size='11' text-anchor='middle' fill='#fff'>S</text><circle cx='110' cy='55' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='210' cy='55' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='95' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='25' font-size='11' text-anchor='middle' fill='#1a2b45'>SO₃: 3 O / molekül</text></svg>","steps":[{"t":"Molekülü mole çevir","a":"1,5 mol","d":"Molekül sayısı / N_A = 9,03·10²³ / 6,02·10²³ = 1,5 mol SO₃."},{"t":"O atomunu hesapla","a":"4,5 mol → atom","d":"Her SO₃ te 3 oksijen var; O = 3 × 1,5 = 4,5 mol = 4,5 × 6,02·10²³ = 27,09·10²³ atomdur."}],"ans":"9,03·10²³ tane SO₃ molekülünde 4,5 mol, yani 27,09·10²³ tane oksijen atomu vardır."},{"q":"0,5 mol Al₂(SO₄)₃ içinde kaç mol Al³⁺, kaç mol SO₄²⁻ ve toplam kaç tane iyon bulunur?","steps":[{"t":"İyonları belirle","a":"2 Al³⁺ + 3 SO₄²⁻","d":"Bir birim Al₂(SO₄)₃, 2 tane Al³⁺ ve 3 tane SO₄²⁻ verir; 1 mol için 2 mol Al³⁺ ve 3 mol SO₄²⁻ olur."},{"t":"0,5 mole indir","a":"1 + 1,5 = 2,5 mol","d":"0,5 mol için Al³⁺ = 2 × 0,5 = 1 mol, SO₄²⁻ = 3 × 0,5 = 1,5 mol; toplam 2,5 mol iyon = 2,5 × 6,02·10²³ = 15,05·10²³ tanedir."}],"ans":"0,5 mol Al₂(SO₄)₃ içinde 1 mol Al³⁺ ve 1,5 mol SO₄²⁻ vardır; toplam 2,5 mol (15,05·10²³ tane) iyon bulunur."},{"q":"Eşit kütlede (örneğin 1,204·10²⁴ tane) H₂ ve O₂ molekülü alındığında her birinde kaç mol atom bulunur ve karşılaştırınız.","steps":[{"t":"Mole çevir","a":"her biri 2 mol","d":"1,204·10²⁴ / 6,02·10²³ = 2 mol; hem H₂ hem O₂ için 2 mol molekül vardır."},{"t":"Atomu hesapla","a":"4 mol atom (her biri)","d":"İki gaz da iki atomlu (H₂, O₂) olduğundan her birinde 2 × 2 = 4 mol atom bulunur; atom sayıları eşittir."}],"ans":"Her iki gazda da 2 mol molekül vardır; ikisi de iki atomlu olduğundan her birinde 4 mol atom bulunur (atom sayıları eşittir)."},{"q":"1 mol KMnO₄ içinde kaç mol oksijen atomu ve kaç tane oksijen atomu vardır?","steps":[{"t":"Formülü incele","a":"4 oksijen","d":"KMnO₄ formülünde 1 K, 1 Mn ve 4 oksijen atomu bulunur."},{"t":"Mole ve taneciğe çevir","a":"4 mol → tane","d":"1 mol KMnO₄ için oksijen = 4 mol = 4 × 6,02·10²³ = 24,08·10²³ tane atomdur."}],"ans":"1 mol KMnO₄ içinde 4 mol, yani 24,08·10²³ tane oksijen atomu vardır."},{"q":"3,612·10²⁴ tane azot atomu (N) kaç mol N₂ molekülüne karşılık gelir?","steps":[{"t":"Atomu mole çevir","a":"6 mol N atomu","d":"n = 3,612·10²⁴ / 6,02·10²³ = 6 mol azot atomu eder."},{"t":"Moleküle çevir","a":"6 ÷ 2 = 3 mol N₂","d":"Her N₂ molekülü 2 azot atomu içerdiğinden 6 mol atom, 6 / 2 = 3 mol N₂ molekülüne karşılık gelir."}],"ans":"3,612·10²⁴ tane azot atomu 6 mol N atomu, yani 3 mol N₂ molekülüne karşılık gelir."}]}},"buyukSayi":{"ilkokul":{"kolay":[{"q":"Bir kavanozdaki binlerce kum tanesini neden tek tek saymak zordur?","steps":[{"t":"Çok fazla","a":"binlerce tane","d":"Kavanozda o kadar çok kum tanesi vardır ki birer birer saymak çok uzun sürer."},{"t":"Karışır","a":"hata olur","d":"Sayarken hangi taneyi saydığımızı şaşırırız ve sayım yanlış çıkar."}],"ans":"Çok fazla sayıda olduğu için kum tanelerini tek tek saymak hem çok uzun sürer hem de karışır."},{"q":"Çok küçük şeyleri tek tek saymak yerine ne yaparız?","steps":[{"t":"Grupla","a":"birlikte say","d":"Küçük nesneleri tek tek değil, gruplar (avuç, kaşık, paket) halinde sayarız."},{"t":"Daha kolay","a":"hızlı sonuç","d":"Gruplar halinde sayınca işimiz hızlanır ve daha az hata yaparız."}],"ans":"Çok küçük şeyleri tek tek değil, gruplar halinde sayarız."},{"q":"Bir torba pirinci tek tek saymak yerine nasıl ölçeriz?","steps":[{"t":"Tek tek olmaz","a":"çok küçük","d":"Pirinç taneleri hem çok küçük hem çok sayıdadır, tek tek sayılmaz."},{"t":"Tartarız","a":"kütle ile","d":"Bu yüzden pirinci sayı yerine terazide tartarak (örneğin 1 kilogram) ölçeriz."}],"ans":"Pirinç gibi çok küçük ve çok sayıdaki şeyleri saymak yerine tartarak ölçeriz."},{"q":"Gözle göremediğimiz kadar küçük tanecikler olduğunu biliyor muyuz?","steps":[{"t":"Çok küçük","a":"görünmez","d":"Her şey atom denen, gözle görülemeyecek kadar küçük taneciklerden oluşur."},{"t":"Çok sayıda","a":"sayılamaz","d":"Küçük bir nesnede bile o kadar çok atom vardır ki tek tek saymak imkânsızdır."}],"ans":"Evet; her şey gözle görülemeyen, çok küçük ve çok sayıda atom adı verilen taneciklerden oluşur."},{"q":"Bir bardak suda çok mu yoksa az mı su taneciği vardır?","fig":"<svg viewBox='0 0 320 150'><path d='M110 30 L210 30 L195 120 L125 120 Z' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='140' cy='60' r='3' fill='#2b6be0'/><circle cx='160' cy='70' r='3' fill='#2b6be0'/><circle cx='180' cy='60' r='3' fill='#2b6be0'/><circle cx='150' cy='90' r='3' fill='#2b6be0'/><circle cx='170' cy='95' r='3' fill='#2b6be0'/><circle cx='160' cy='50' r='3' fill='#2b6be0'/><text x='160' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>sayılamayacak kadar çok</text></svg>","steps":[{"t":"Çok küçük","a":"su taneciği","d":"Su, gözle görülemeyen çok küçük su taneciklerinden (moleküllerinden) oluşur."},{"t":"Çok sayıda","a":"sayılamaz","d":"Bir bardak suda bile o kadar çok tanecik vardır ki sayısı düşünülemeyecek kadar büyüktür."}],"ans":"Bir bardak suda sayılamayacak kadar çok su taneciği vardır."}],"zor":[{"q":"Neden çakıl taşlarını sayabiliriz ama kum tanelerini kolayca sayamayız?","steps":[{"t":"Boyut farkı","a":"kum çok küçük","d":"Çakıl taşları büyük ve az sayıdadır; kum taneleri ise çok küçük ve çok sayıdadır."},{"t":"Sayım zorluğu","a":"kum sayılamaz","d":"Küçüldükçe ve sayı arttıkça tek tek saymak imkânsız hale gelir."}],"ans":"Çakıl büyük ve az olduğu için sayılabilir; kum çok küçük ve çok fazla olduğundan tek tek sayılamaz."},{"q":"Bir öğretmen sınıftaki tebeşir tozu zerrelerini saymak isterse ne sorun yaşar?","steps":[{"t":"Çok küçük","a":"görünmez zerre","d":"Tebeşir tozu zerreleri gözle zor görülecek kadar küçüktür."},{"t":"Çok sayıda","a":"sayılamaz","d":"Az bir tozda bile milyonlarca zerre olduğundan tek tek saymak mümkün değildir."}],"ans":"Tebeşir tozu zerreleri çok küçük ve çok sayıda olduğundan tek tek sayılamaz; saymak imkânsızdır."},{"q":"Çok büyük sayıda nesneyi saymak için neden büyük bir sayma birimi gerekir?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='50' width='60' height='55' rx='5' fill='#9ed9a8' stroke='#1a2b45'/><text x='60' y='82' font-size='10' text-anchor='middle' fill='#1a2b45'>1000</text><rect x='100' y='50' width='60' height='55' rx='5' fill='#9ed9a8' stroke='#1a2b45'/><text x='130' y='82' font-size='10' text-anchor='middle' fill='#1a2b45'>1000</text><rect x='170' y='50' width='60' height='55' rx='5' fill='#9ed9a8' stroke='#1a2b45'/><text x='200' y='82' font-size='10' text-anchor='middle' fill='#1a2b45'>1000</text><rect x='240' y='50' width='60' height='55' rx='5' fill='#9ed9a8' stroke='#1a2b45'/><text x='270' y='82' font-size='10' text-anchor='middle' fill='#1a2b45'>1000</text><text x='160' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>büyük gruplar halinde say</text></svg>","steps":[{"t":"Tek tek uzun","a":"yorucu","d":"Çok büyük sayıda nesneyi birer birer saymak günlerce sürebilir."},{"t":"Büyük birim","a":"toplu sayma","d":"Binlik, milyonluk gibi büyük gruplar halinde sayarsak işi çok hızlandırırız."}],"ans":"Çok sayıda nesneyi tek tek saymak imkânsıza yakın olduğundan, büyük gruplar halinde sayan büyük bir sayma birimi gerekir."},{"q":"Şekerin tatlı olması, içindeki taneciklerin sayısı hakkında bize ne düşündürür?","steps":[{"t":"Küçük tanecik","a":"şeker taneciği","d":"Şeker, gözle görülemeyen çok küçük şeker taneciklerinden oluşur."},{"t":"Çok sayıda","a":"sayısız","d":"Bir kaşık şekerde bile sayılamayacak kadar çok tanecik bulunur."}],"ans":"Bir kaşık şekerde bile sayılamayacak kadar çok küçük tanecik bulunduğunu düşündürür."},{"q":"Bilim insanları sayılamayacak kadar küçük tanecikleri saymak için ne yapmış olabilir?","steps":[{"t":"Tek tek olmaz","a":"imkânsız","d":"Tanecikler çok küçük ve çok sayıda olduğundan tek tek saymak imkânsızdır."},{"t":"Yeni birim","a":"büyük sayma birimi","d":"Bu yüzden bilim insanları çok büyük bir sayma birimi (mol) bulmuş ve tanecikleri bu birimle ifade etmiştir."}],"ans":"Tek tek sayamadıkları için bilim insanları çok büyük bir sayma birimi (mol) tanımlayıp tanecikleri bu birimle saymıştır."}]},"ortaokul":{"kolay":[{"q":"Atom ve moleküller neden tek tek sayılamaz?","steps":[{"t":"Boyut","a":"aşırı küçük","d":"Atom ve moleküller, en güçlü ışık mikroskobuyla bile tek tek görülemeyecek kadar küçüktür."},{"t":"Sayı","a":"aşırı çok","d":"Küçük bir madde parçasında bile o kadar çok tanecik vardır ki birer birer saymak imkânsızdır."}],"ans":"Atom ve moleküller hem görülemeyecek kadar küçük hem de çok sayıda olduğundan tek tek sayılamaz."},{"q":"Çok sayıda küçük taneciği saymanın pratik bir yolu nedir?","steps":[{"t":"Sabit grup","a":"sayma birimi","d":"Belirli sayıda taneciği bir grup sayarsak (düzine gibi ama çok daha büyük) işimiz kolaylaşır."},{"t":"Büyük birim","a":"mol gibi","d":"Kimyada bu amaçla çok büyük bir sayma birimi olan mol kullanılır."}],"ans":"Çok sayıda taneciği, belirli sayıyı bir grup kabul eden büyük bir sayma birimiyle (mol) saymak pratik bir yoldur."},{"q":"Bir çay kaşığı suda yaklaşık kaç tane su molekülü olabilir; az mı çok mu?","steps":[{"t":"Molekül küçük","a":"çok küçük","d":"Su molekülleri gözle görülemeyecek kadar küçüktür."},{"t":"Sayı çok","a":"milyarlarca milyar","d":"Bir çay kaşığı suda bile milyarlarca milyar (akıl almaz sayıda) molekül bulunur."}],"ans":"Bir çay kaşığı suda akıl almayacak kadar çok (milyarlarca milyar) su molekülü vardır."},{"q":"Neden taneciklerin sayısını kütleyle (tartarak) ilişkilendiririz?","steps":[{"t":"Sayamayız","a":"tek tek imkânsız","d":"Tanecikleri tek tek sayamadığımız için doğrudan adetlerini bulamayız."},{"t":"Tartabiliriz","a":"kütle ölçülür","d":"Ama maddenin kütlesini kolayca tartarız; kütle ile tanecik sayısı arasında bir ilişki kurulur."}],"ans":"Tanecikleri tek tek sayamadığımızdan, kolayca ölçebildiğimiz kütleyi kullanarak tanecik sayısını dolaylı yoldan buluruz."},{"q":"Sayma birimi büyüdükçe çok sayıda nesneyi ifade etmek nasıl kolaylaşır?","fig":"<svg viewBox='0 0 320 150'><text x='160' y='35' font-size='11' text-anchor='middle' fill='#1a2b45'>1 tane &lt; düzine (12) &lt; mol (çok büyük)</text><circle cx='60' cy='80' r='6' fill='#2b6be0'/><rect x='120' y='65' width='40' height='30' fill='#9ed9a8' stroke='#1a2b45'/><text x='140' y='85' font-size='9' text-anchor='middle' fill='#1a2b45'>12</text><rect x='210' y='60' width='70' height='40' fill='#e0552b' stroke='#1a2b45'/><text x='245' y='85' font-size='9' text-anchor='middle' fill='#fff'>mol</text></svg>","steps":[{"t":"Büyük birim","a":"daha az sayı","d":"Birim büyüdükçe aynı miktarı daha küçük bir sayı ile ifade ederiz."},{"t":"Örnek","a":"24 = 2 düzine","d":"24 nesneyi '24' yerine '2 düzine' demek gibi; çok büyük tanecik sayıları da 'mol' ile kısaca yazılır."}],"ans":"Sayma birimi büyüdükçe çok sayıda nesneyi daha küçük ve kolay sayılarla ifade edebiliriz; bu yüzden tanecikler için büyük birim (mol) kullanılır."}],"zor":[{"q":"Bir gram demirde milyarlarca milyar atom varsa bunu saymak için neden özel bir birim gerekir?","steps":[{"t":"Sayı devasa","a":"yazması bile zor","d":"Bir gram demirdeki atom sayısı o kadar büyüktür ki sıradan rakamlarla yazmak ve saymak zordur."},{"t":"Büyük birim","a":"mol","d":"Bu dev sayıyı yönetebilmek için 6,02·10²³ taneyi 1 birim (mol) kabul eden bir sayma birimi tanımlanır."}],"ans":"Atom sayısı sıradan sayılarla baş edilemeyecek kadar büyük olduğundan, bu sayıyı düzenli ifade etmek için mol gibi özel ve çok büyük bir birim gerekir."},{"q":"Çok büyük sayıları yazarken bilim insanları neden 10'un kuvvetlerini (üslü sayı) kullanır?","fig":"<svg viewBox='0 0 320 130'><text x='160' y='45' font-size='13' text-anchor='middle' fill='#1a2b45'>602 000 000 000 000 000 000 000</text><text x='160' y='75' font-size='12' text-anchor='middle' fill='#1a2b45'>= 6,02 × 10²³</text><text x='160' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>kısa ve okunaklı</text></svg>","steps":[{"t":"Çok uzun yazım","a":"karışır","d":"Çok büyük sayıları tam yazmak çok sayıda sıfır gerektirir ve okumak/karşılaştırmak zorlaşır."},{"t":"Üslü gösterim","a":"kısa form","d":"10'un kuvvetiyle (örneğin 6,02·10²³) yazarsak sayı kısalır, anlaşılır ve hesaplaması kolaylaşır."}],"ans":"Çok büyük sayılarda sıfırları tek tek yazmak yerine 10'un kuvvetleri (üslü gösterim) kullanılır; böylece sayı kısa, okunaklı ve hesaplanabilir olur."},{"q":"Neden bir maddenin tanecik sayısını doğrudan saymak yerine onu mol cinsinden ifade ederiz?","steps":[{"t":"Sayım imkânsız","a":"çok küçük/çok sayı","d":"Tanecikler tek tek sayılamayacak kadar küçük ve çok olduğundan doğrudan adet bulunamaz."},{"t":"Mol kolaylığı","a":"ortak ölçek","d":"Mol, bu dev sayıyı standart bir ölçeğe indirir; '2 mol atom' demek, devasa bir sayıyı kısaca anlatır."}],"ans":"Tanecikleri doğrudan saymak imkânsız olduğundan, dev tanecik sayısını standart ve kullanışlı bir ölçeğe taşıyan mol birimiyle ifade ederiz."},{"q":"Bir avuç toprakta yaklaşık 10²² tanecik olduğunu düşünün; bu sayı neden tek tek sayılamaz?","steps":[{"t":"Saniyede 1 say","a":"çok yavaş","d":"Saniyede bir tanecik saysak bile bu sayıya ulaşmak evrenin yaşından kat kat uzun sürer."},{"t":"Pratik çözüm","a":"büyük birim","d":"Bu yüzden tek tek saymak yerine taneciği büyük bir birimle (mol) gruplayarak ifade ederiz."}],"ans":"10²² tanecik o kadar çoktur ki saniyede bir sayılsa bile ömür yetmez; bu yüzden tek tek değil, mol gibi büyük bir birimle sayılır."},{"q":"Sayma birimi olarak '12' (düzine) yerine kimyada çok daha büyük bir sayı seçilmesinin nedeni nedir?","steps":[{"t":"Düzine küçük","a":"tanecikte yetersiz","d":"Tanecik sayısı milyarlarca milyar olduğundan, 12'lik düzine bu ölçekte hiçbir kolaylık sağlamaz."},{"t":"Büyük seçim","a":"6,02·10²³","d":"Tanecik sayılarına uygun büyüklükte, 6,02·10²³ değerinde bir birim (mol) seçilir; böylece sayılar makul büyüklüğe iner."}],"ans":"Tanecik sayıları devasa olduğundan 12'lik düzine yetersiz kalır; bu yüzden kimyada çok daha büyük (6,02·10²³) bir sayma birimi olan mol seçilmiştir."}]},"lise":{"kolay":[{"q":"Maddedeki taneciklerin tek tek sayılamamasının iki temel nedeni nedir?","steps":[{"t":"Boyut","a":"atom/molekül çapı çok küçük","d":"Atom ve moleküller nanometre altı boyuttadır; tek tek ayırt edilip sayılamaz."},{"t":"Sayı","a":"makro örnekte devasa","d":"Birkaç gram maddede bile 10²³ mertebesinde tanecik bulunur; bu sayı tek tek sayılamayacak kadar büyüktür."}],"ans":"Tanecikler hem ayırt edilemeyecek kadar küçük hem de makroskobik örnekte 10²³ mertebesinde çok sayıda olduğundan tek tek sayılamaz."},{"q":"Avogadro sayısı kaçtır ve neye karşılık gelir?","steps":[{"t":"Değer","a":"6,02·10²³","d":"Avogadro sayısı N_A = 6,02·10²³ tane/mol değerindedir."},{"t":"Anlamı","a":"1 moldeki tanecik","d":"Bir moldeki tanecik (atom, molekül, iyon) sayısına eşittir; mol bu sayıyı bir birim kabul eder."}],"ans":"Avogadro sayısı 6,02·10²³ tane/mol'dür ve 1 moldeki tanecik sayısına karşılık gelir."},{"q":"Mol birimi, çok büyük tanecik sayılarıyla çalışmayı nasıl kolaylaştırır?","steps":[{"t":"Ölçek indirimi","a":"10²³ → birkaç mol","d":"Devasa tanecik sayısını 6,02·10²³'e bölerek birkaç birimlik (mol) makul sayılara indiririz."},{"t":"Kütle bağı","a":"tartılabilir","d":"Mol, kütle ile (molar kütle) ilişkilendirildiğinden, tartarak dolaylı olarak tanecik sayısı bulunur."}],"ans":"Mol, 10²³ mertebesindeki tanecik sayısını birkaç birimlik makul sayılara indirir ve kütleyle ilişkilendirilebildiğinden tanecikleri tartarak saymayı sağlar."},{"q":"3,01·10²³ tane atom kaç mol atoma karşılık gelir?","steps":[{"t":"Formül","a":"mol = tanecik / N_A","d":"Mol sayısını bulmak için tanecik sayısını Avogadro sayısına böleriz."},{"t":"Hesap","a":"3,01·10²³ / 6,02·10²³ = 0,5","d":"3,01·10²³ atomu 6,02·10²³'e bölersek 0,5 mol buluruz."}],"ans":"3,01·10²³ tane atom 0,5 mol atoma karşılık gelir."},{"q":"2 mol su molekülü kaç tane molekül içerir?","steps":[{"t":"Formül","a":"tanecik = mol × N_A","d":"Tanecik sayısını bulmak için mol sayısını Avogadro sayısıyla çarparız."},{"t":"Hesap","a":"2 × 6,02·10²³ = 1,204·10²⁴","d":"2 mol için 6,02·10²³'ü 2 ile çarparız: 1,204·10²⁴ molekül eder."}],"ans":"2 mol su 1,204·10²⁴ tane su molekülü içerir."}],"zor":[{"q":"Mol kavramının tanımlanması, çok küçük ve çok sayıda taneciği saymadaki temel sorunu nasıl çözer?","steps":[{"t":"Sorun","a":"sayım imkânsız","d":"Tanecikler tek tek sayılamayacak kadar küçük ve 10²³ mertebesinde çok olduğundan doğrudan adet bulunamaz."},{"t":"Çözüm","a":"sayı-kütle köprüsü","d":"Mol, 6,02·10²³ taneyi bir birim kabul ederek tanecik sayısını molar kütleye bağlar; böylece tartılan kütleden tanecik sayısı hesaplanır."}],"ans":"Mol, 6,02·10²³ taneyi bir birim sayarak sayılamayan tanecikleri kütleyle ilişkilendirir; tek tek sayım yerine maddeyi tartarak tanecik sayısını dolaylı ama kesin biçimde bulmamızı sağlar."},{"q":"0,25 mol CO₂ kaç tane molekül ve kaç tane oksijen atomu içerir?","steps":[{"t":"Molekül sayısı","a":"0,25 × 6,02·10²³","d":"Mol sayısını N_A ile çarparız: 0,25 × 6,02·10²³ = 1,505·10²³ molekül."},{"t":"O atomu sayısı","a":"molekül × 2","d":"Her CO₂ molekülünde 2 oksijen atomu olduğundan molekül sayısını 2 ile çarparız."},{"t":"Hesap","a":"1,505·10²³ × 2 = 3,01·10²³","d":"Oksijen atomu sayısı 3,01·10²³ tane bulunur."}],"ans":"0,25 mol CO₂, 1,505·10²³ tane molekül ve 3,01·10²³ tane oksijen atomu içerir."},{"q":"Avogadro sayısının ne kadar büyük olduğunu kavramak için saniyede 1 milyon tanecik sayan biri 1 mol taneciği ne kadar sürede sayardı?","steps":[{"t":"Toplam tanecik","a":"6,02·10²³","d":"1 mol, 6,02·10²³ tanecik içerir."},{"t":"Süre hesabı","a":"6,02·10²³ / 10⁶","d":"Saniyede 10⁶ sayan biri için süre 6,02·10²³ ÷ 10⁶ = 6,02·10¹⁷ saniye eder."},{"t":"Yorum","a":"milyarlarca yıl","d":"6,02·10¹⁷ saniye, yaklaşık 19 milyar yıldan uzundur; yani evrenin yaşından bile fazladır."}],"ans":"Saniyede 1 milyon tanecik saysa bile 1 molü saymak yaklaşık 6,02·10¹⁷ saniye, yani milyarlarca yıl sürerdi; bu, mol'ün ne kadar büyük olduğunu ve tek tek saymanın imkânsızlığını gösterir."},{"q":"Neden tanecik sayısını doğrudan değil de mol ve molar kütle üzerinden hesaplamak laboratuvarda daha kullanışlıdır?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='50' width='70' height='45' rx='5' fill='#9ed9a8' stroke='#1a2b45'/><text x='65' y='77' font-size='10' text-anchor='middle' fill='#1a2b45'>kütle (g)</text><rect x='125' y='50' width='70' height='45' rx='5' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='77' font-size='10' text-anchor='middle' fill='#1a2b45'>mol</text><rect x='220' y='50' width='70' height='45' rx='5' fill='#e0552b' stroke='#1a2b45'/><text x='255' y='77' font-size='10' text-anchor='middle' fill='#fff'>tanecik</text><line x1='100' y1='72' x2='124' y2='72' stroke='#1a2b45' stroke-width='2'/><polygon points='124,72 114,67 114,77' fill='#1a2b45'/><line x1='195' y1='72' x2='219' y2='72' stroke='#1a2b45' stroke-width='2'/><polygon points='219,72 209,67 209,77' fill='#1a2b45'/></svg>","steps":[{"t":"Kütle ölçülebilir","a":"terazi yeterli","d":"Laboratuvarda tanecik sayılamaz ama madde kolayca tartılabilir; kütle doğrudan ölçülen bir niceliktir."},{"t":"Mol köprüsü","a":"kütle → mol → tanecik","d":"Molar kütle ile kütleden mol, mol'den de Avogadro sayısıyla tanecik sayısı hesaplanır; zincir pratik ve kesindir."}],"ans":"Laboratuvarda tanecik tek tek sayılamaz ama kütle kolayca tartılır; mol ve molar kütle, tartılan kütleyi tanecik sayısına bağlayan pratik bir köprü kurduğundan bu yol çok daha kullanışlıdır."},{"q":"Bir su damlasında yaklaşık 1,5·10²¹ molekül bulunuyorsa bu kaç mol suya karşılık gelir?","steps":[{"t":"Formül","a":"mol = tanecik / N_A","d":"Mol sayısı, tanecik sayısının Avogadro sayısına bölünmesiyle bulunur."},{"t":"Hesap","a":"1,5·10²¹ / 6,02·10²³","d":"1,5·10²¹ ÷ 6,02·10²³ ≈ 0,0025 mol; yani yaklaşık 2,5·10⁻³ mol."},{"t":"Yorum","a":"çok küçük mol","d":"Damlada bile 10²¹ molekül bulunması, tek bir damlanın milimol mertebesinde madde içerdiğini gösterir."}],"ans":"Bir su damlasındaki 1,5·10²¹ molekül yaklaşık 2,5·10⁻³ (0,0025) mol suya karşılık gelir; bu, çok küçük bir hacimde bile devasa sayıda tanecik bulunduğunu gösterir."}]}},"denklemDenklestirme":{"ilkokul":{"kolay":[{"q":"Bir kimyasal değişimde maddenin toplam kütlesi değişir mi?","steps":[{"t":"Atomlar yok olmaz","a":"sayı korunur","d":"Tepkimede atomlar sadece yer değiştirir; hiçbiri yok olmaz, yeni atom da oluşmaz."},{"t":"Kütle aynı kalır","a":"korunur","d":"Atom sayısı değişmediği için başlangıç ve sonuç kütlesi birbirine eşit kalır."}],"ans":"Kimyasal değişimde toplam kütle korunur, yani aynı kalır."},{"q":"İki hidrojen tanesi (H₂) ve bir oksijen tanesi (O₂) su (H₂O) oluşturuyor. Sağda ve solda atomların sayısı neden eşit olmalı?","steps":[{"t":"Atomlar kaybolmaz","a":"hepsi geçer","d":"Sol taraftaki her atom sağ tarafta da bulunmalıdır; hiçbiri kaybolmaz."},{"t":"Denge kuralı","a":"eşit sayı","d":"Bu yüzden her atomdan iki tarafta eşit sayıda olacak şekilde sayılar ayarlanır."}],"ans":"Atomlar kaybolmadığı için her atomdan iki tarafta eşit sayıda bulunması gerekir."},{"q":"Bir mum yandığında kütlesi azalır gibi görünür. Aslında kütle nereye gider?","steps":[{"t":"Gaz oluşur","a":"havaya karışır","d":"Mum yanınca su buharı ve karbondioksit gazı oluşur ve bunlar havaya karışıp uçar."},{"t":"Kütle korunur","a":"yok olmaz","d":"Uçan gazların kütlesini de sayarsak toplam kütle yine aynı kalır, yok olmamıştır."}],"ans":"Mumun azalan kütlesi gaz olarak havaya karışır; toplam kütle yine korunur."},{"q":"Kapalı bir kapta tepkime olursa kütle artar mı, azalır mı, aynı mı kalır?","steps":[{"t":"Kapalı kap","a":"hiçbir şey çıkmaz","d":"Kap kapalı olduğu için içeriden dışarıya hiçbir madde çıkamaz, dışarıdan da giremez."},{"t":"Sonuç","a":"aynı kalır","d":"Madde girip çıkmadığı için tepkime sonrası toplam kütle başlangıçtaki kadardır."}],"ans":"Kapalı kapta tepkime sonrası toplam kütle aynı kalır (değişmez)."},{"q":"Denklemi denkleştirmek için atomların sayısını değiştirmek yerine ne yaparız?","fig":"<svg viewBox='0 0 320 120'><text x='30' y='45' font-size='16' fill='#1a2b45'>2 H₂</text><text x='80' y='45' font-size='16' fill='#1a2b45'>+</text><text x='105' y='45' font-size='16' fill='#1a2b45'>O₂</text><text x='150' y='45' font-size='18' fill='#e0552b'>→</text><text x='185' y='45' font-size='16' fill='#1a2b45'>2 H₂O</text><text x='160' y='95' font-size='11' text-anchor='middle' fill='#5b6b85'>öndeki büyük sayı: katsayı</text></svg>","steps":[{"t":"Formül değişmez","a":"H₂O aynı kalır","d":"Maddenin formülünü (örneğin H₂O) değiştiremeyiz, yoksa madde başka madde olur."},{"t":"Katsayı yazılır","a":"önüne sayı","d":"Onun yerine formülün önüne büyük bir sayı (katsayı) yazarak tane sayısını ayarlarız."}],"ans":"Formülü değiştirmeyiz; formülün önüne katsayı (büyük sayı) yazarak sayıları ayarlarız."}],"zor":[{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde sol ve sağda kaç hidrojen atomu vardır?","steps":[{"t":"Soldaki H","a":"4 tane","d":"2 H₂ demek 2·2 = 4 hidrojen atomu demektir."},{"t":"Sağdaki H","a":"4 tane","d":"2 H₂O demek 2·2 = 4 hidrojen atomu demektir; iki taraf da 4'tür, denktir."}],"ans":"Hem solda hem sağda 4 hidrojen atomu vardır; denklem denktir."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde sol ve sağda kaç oksijen atomu vardır?","steps":[{"t":"Soldaki O","a":"2 tane","d":"O₂ bir tane olduğu için 2 oksijen atomu içerir."},{"t":"Sağdaki O","a":"2 tane","d":"2 H₂O içinde 2·1 = 2 oksijen atomu vardır; iki taraf eşit, denktir."}],"ans":"Hem solda hem sağda 2 oksijen atomu vardır; denklem denktir."},{"q":"2 Na + Cl₂ → 2 NaCl tepkimesinde sodyum (Na) atomları iki tarafta eşit midir?","steps":[{"t":"Soldaki Na","a":"2 tane","d":"2 Na ifadesi 2 sodyum atomu demektir."},{"t":"Sağdaki Na","a":"2 tane","d":"2 NaCl içinde 2 sodyum atomu bulunur; iki taraf eşittir."}],"ans":"Solda 2, sağda 2 sodyum atomu vardır; eşittir, denklem denktir."},{"q":"Bir tepkimede solda toplam 10 atom varsa, sağda kaç atom olmalıdır?","fig":"<svg viewBox='0 0 320 110'><rect x='25' y='35' width='90' height='40' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='60' font-size='13' text-anchor='middle' fill='#1a2b45'>sol: 10</text><text x='150' y='60' font-size='18' fill='#e0552b'>→</text><rect x='195' y='35' width='90' height='40' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='240' y='60' font-size='13' text-anchor='middle' fill='#1a2b45'>sağ: 10</text></svg>","steps":[{"t":"Kütle korunumu","a":"atom korunur","d":"Atomlar tepkimede yok olmaz; soldaki tüm atomlar sağda da bulunur."},{"t":"Sonuç","a":"10 atom","d":"Solda 10 atom varsa sağda da tam 10 atom olmalıdır."}],"ans":"Sağda da tam 10 atom olmalıdır; atom sayısı korunur."},{"q":"C + O₂ → CO₂ tepkimesi denk midir? Atomları sayarak gör.","steps":[{"t":"Karbon sayısı","a":"1 = 1","d":"Solda 1 karbon (C), sağda CO₂ içinde 1 karbon vardır; eşit."},{"t":"Oksijen sayısı","a":"2 = 2","d":"Solda O₂ ile 2 oksijen, sağda CO₂ içinde 2 oksijen vardır; eşit, denklem denktir."}],"ans":"Karbon 1=1, oksijen 2=2 olduğu için C + O₂ → CO₂ denktir."}]},"ortaokul":{"kolay":[{"q":"Kütlenin korunumu yasası kimyasal denklem denkleştirmeyle nasıl bağlantılıdır?","steps":[{"t":"Yasa","a":"kütle korunur","d":"Kütlenin korunumu yasasına göre tepkimede atomlar ne yaratılır ne yok edilir."},{"t":"Denklik gereği","a":"atom eşitliği","d":"Bu yüzden denklemde her elementin atom sayısı girenlerde ve ürünlerde eşit olmalıdır; bunu sağlamak denkleştirmektir."}],"ans":"Kütle korunduğu için denklemde her atom türü iki tarafta eşitlenir; denkleştirmenin temeli budur."},{"q":"H₂ + O₂ → H₂O denklemi neden denk değildir, nasıl denkleştirilir?","steps":[{"t":"Oksijeni say","a":"2 ≠ 1","d":"Solda O₂ ile 2 oksijen var, sağda H₂O içinde 1 oksijen var; eşit değil."},{"t":"Katsayı ekle","a":"2 H₂ + O₂ → 2 H₂O","d":"H₂O önüne 2, H₂ önüne 2 yazınca: H 4=4, O 2=2 olur ve denklem denkleşir."}],"ans":"Denk hâli 2 H₂ + O₂ → 2 H₂O'dur; böylece H 4=4 ve O 2=2 olur."},{"q":"Denklem denkleştirirken maddenin alt indisini (örneğin H₂O'daki 2) değiştirebilir miyiz?","steps":[{"t":"Alt indis","a":"değiştirilemez","d":"Alt indis maddenin kimliğini belirler; değiştirirsek H₂O su olmaktan çıkar, başka madde olur."},{"t":"Doğru yol","a":"katsayı kullan","d":"Sayıları ayarlamak için sadece formülün önüne katsayı yazılır, alt indise dokunulmaz."}],"ans":"Hayır; alt indis değiştirilemez, sadece formülün önündeki katsayı ayarlanır."},{"q":"2 Mg + O₂ → 2 MgO denkleminde magnezyum ve oksijeni sayarak denk olup olmadığını göster.","steps":[{"t":"Magnezyum","a":"2 = 2","d":"Solda 2 Mg, sağda 2 MgO içinde 2 magnezyum vardır; eşit."},{"t":"Oksijen","a":"2 = 2","d":"Solda O₂ ile 2 oksijen, sağda 2 MgO içinde 2 oksijen vardır; eşit, denklem denktir."}],"ans":"Mg 2=2 ve O 2=2 olduğundan 2 Mg + O₂ → 2 MgO denktir."},{"q":"N₂ + 3 H₂ → 2 NH₃ tepkimesinde hidrojen atomları iki tarafta eşit midir?","fig":"<svg viewBox='0 0 320 110'><text x='25' y='50' font-size='15' fill='#1a2b45'>N₂ + 3H₂</text><text x='140' y='50' font-size='18' fill='#e0552b'>→</text><text x='180' y='50' font-size='15' fill='#1a2b45'>2NH₃</text><text x='160' y='90' font-size='11' text-anchor='middle' fill='#5b6b85'>H: 6 = 6, N: 2 = 2</text></svg>","steps":[{"t":"Soldaki H","a":"6 tane","d":"3 H₂ demek 3·2 = 6 hidrojen atomu demektir."},{"t":"Sağdaki H","a":"6 tane","d":"2 NH₃ içinde 2·3 = 6 hidrojen atomu vardır; iki taraf eşit."}],"ans":"Solda 6, sağda 6 hidrojen atomu vardır; eşittir, denklem denktir."}],"zor":[{"q":"CH₄ + O₂ → CO₂ + H₂O denklemini denkleştir.","steps":[{"t":"C ve H'yi dengele","a":"H için 2 H₂O","d":"1 karbon iki tarafta da var. CH₄'te 4 H olduğundan sağda 2 H₂O (4 H) gerekir."},{"t":"Oksijeni dengele","a":"2 O₂ ekle","d":"Sağda CO₂'de 2, 2 H₂O'da 2, toplam 4 oksijen var; solda 4 oksijen için 2 O₂ gerekir. Sonuç: CH₄ + 2 O₂ → CO₂ + 2 H₂O."}],"ans":"Denk hâli CH₄ + 2 O₂ → CO₂ + 2 H₂O'dur (C 1=1, H 4=4, O 4=4)."},{"q":"Fe + O₂ → Fe₂O₃ denklemini denkleştir.","fig":"<svg viewBox='0 0 320 110'><text x='15' y='50' font-size='14' fill='#1a2b45'>4Fe + 3O₂</text><text x='135' y='50' font-size='18' fill='#e0552b'>→</text><text x='175' y='50' font-size='14' fill='#1a2b45'>2Fe₂O₃</text><text x='160' y='90' font-size='11' text-anchor='middle' fill='#5b6b85'>Fe: 4=4, O: 6=6</text></svg>","steps":[{"t":"Demir ve oksijeni eşitle","a":"2 Fe₂O₃","d":"Tek molekül oksijeni çift sayı yapmak için sağa 2 Fe₂O₃ yazılır; bu 4 Fe ve 6 O verir."},{"t":"Katsayıları tamamla","a":"4 Fe + 3 O₂","d":"4 demir için solda 4 Fe, 6 oksijen için 3 O₂ gerekir. Sonuç: 4 Fe + 3 O₂ → 2 Fe₂O₃."}],"ans":"Denk hâli 4 Fe + 3 O₂ → 2 Fe₂O₃'tür (Fe 4=4, O 6=6)."},{"q":"Al + HCl → AlCl₃ + H₂ denklemini denkleştir.","steps":[{"t":"Klor ve hidrojeni dengele","a":"6 HCl, 2 AlCl₃","d":"Klor ve hidrojeni çift yapmak için: 2 AlCl₃ (6 Cl) ve solda 6 HCl (6 H, 6 Cl) alınır; H₂'yi 3 yapınca 6 H olur."},{"t":"Alüminyumu tamamla","a":"2 Al","d":"2 AlCl₃ için solda 2 Al gerekir. Sonuç: 2 Al + 6 HCl → 2 AlCl₃ + 3 H₂ (Al 2=2, H 6=6, Cl 6=6)."}],"ans":"Denk hâli 2 Al + 6 HCl → 2 AlCl₃ + 3 H₂'dir (Al 2=2, Cl 6=6, H 6=6)."},{"q":"C₃H₈ + O₂ → CO₂ + H₂O (propan yanması) denklemini denkleştir.","steps":[{"t":"Karbon ve hidrojen","a":"3 CO₂, 4 H₂O","d":"3 karbon için 3 CO₂, 8 hidrojen için 4 H₂O (4·2=8 H) yazılır."},{"t":"Oksijeni dengele","a":"5 O₂","d":"Sağda 3·2 + 4·1 = 10 oksijen vardır; solda 10 oksijen için 5 O₂ gerekir. Sonuç: C₃H₈ + 5 O₂ → 3 CO₂ + 4 H₂O."}],"ans":"Denk hâli C₃H₈ + 5 O₂ → 3 CO₂ + 4 H₂O'dur (C 3=3, H 8=8, O 10=10)."},{"q":"CaCO₃ → CaO + CO₂ denklemi neden katsayı eklemeden denktir?","steps":[{"t":"Atomları say","a":"Ca 1, C 1, O 3","d":"Solda CaCO₃: 1 kalsiyum, 1 karbon, 3 oksijen vardır."},{"t":"Sağı say","a":"Ca 1, C 1, O 3","d":"Sağda CaO (1 Ca, 1 O) + CO₂ (1 C, 2 O) toplam 1 Ca, 1 C, 3 O verir; tüm atomlar eşittir."}],"ans":"Ca 1=1, C 1=1, O 3=3 olduğundan CaCO₃ → CaO + CO₂ baştan denktir."}]},"lise":{"kolay":[{"q":"Kimyasal bir denklemi denkleştirmenin dayandığı temel ilke nedir?","steps":[{"t":"İlke","a":"kütlenin korunumu","d":"Lavoisier'in kütlenin korunumu yasasına göre kapalı sistemde atomlar yaratılamaz ve yok edilemez."},{"t":"Uygulama","a":"atom dengesi","d":"Bu nedenle her elementin atom sayısı girenler ve ürünlerde eşitlenir; yükler de korunur."}],"ans":"Denkleştirme, kütlenin korunumu yasasına dayanır; her elementin atom sayısı iki tarafta eşitlenir."},{"q":"Denkleştirmede neden formüllerin alt indisleri değil, yalnızca katsayılar değiştirilir?","steps":[{"t":"Alt indisin anlamı","a":"madde kimliği","d":"Alt indis bileşiğin sabit bileşimini gösterir; değiştirmek bileşiği başka bir maddeye dönüştürür."},{"t":"Katsayının rolü","a":"mol/molekül sayısı","d":"Katsayı yalnızca o maddenin molekül (mol) sayısını gösterir; bunu değiştirmek madde kimliğini bozmaz."}],"ans":"Alt indis madde kimliğini belirlediğinden sabit kalır; yalnızca molekül sayısını veren katsayılar ayarlanır."},{"q":"N₂ + H₂ ⇌ NH₃ (amonyak sentezi) denklemini denkleştir ve denge okunu açıkla.","steps":[{"t":"Katsayıları belirle","a":"N₂ + 3 H₂ ⇌ 2 NH₃","d":"2 N için 2 NH₃, 6 H için 3 H₂ gerekir; N 2=2, H 6=6 olur ve denklem denkleşir."},{"t":"Denge oku","a":"⇌","d":"Çift yönlü ok (⇌), tepkimenin tersinir olduğunu, ileri ve geri yönde aynı anda yürüyebildiğini gösterir."}],"ans":"Denk hâli N₂ + 3 H₂ ⇌ 2 NH₃'tür; ⇌ tepkimenin tersinir (denge) olduğunu belirtir."},{"q":"Yarım (kesirli) katsayı kullanılarak ½ O₂ yazılan bir denklem nasıl tam sayılı hâle getirilir?","steps":[{"t":"Kesir sorunu","a":"½ O₂","d":"Örneğin H₂ + ½ O₂ → H₂O denktir ama termokimya dışında kesirli katsayı tercih edilmez."},{"t":"Tümünü çarp","a":"×2","d":"Tüm denklemi 2 ile çarpınca 2 H₂ + O₂ → 2 H₂O elde edilir; katsayılar en küçük tam sayı hâline gelir."}],"ans":"Denklemin tüm terimlerini ortak paydayla (örneğin 2 ile) çarparak kesirli katsayılar tam sayıya çevrilir."},{"q":"Bir denklemin denk olup olmadığı nasıl kontrol edilir?","steps":[{"t":"Atom sayımı","a":"her element ayrı","d":"Her element için girenlerdeki ve ürünlerdeki atom sayısı (katsayı × alt indis) ayrı ayrı toplanır."},{"t":"Eşitlik testi","a":"iki taraf eşit","d":"Her element için iki tarafın toplamı eşitse ve yük korunuyorsa denklem denktir."}],"ans":"Her element için katsayı × alt indis toplamı iki tarafta eşitse (ve yük korunuyorsa) denklem denktir."}],"zor":[{"q":"C₂H₆ + O₂ → CO₂ + H₂O (etan yanması) denklemini denkleştir.","steps":[{"t":"C ve H'yi dengele","a":"2 CO₂, 3 H₂O","d":"2 karbon için 2 CO₂; 6 hidrojen için 3 H₂O (3·2=6 H) yazılır."},{"t":"Oksijeni dengele","a":"kesirden tam sayıya","d":"Sağda 2·2 + 3·1 = 7 oksijen var; solda 7/2 O₂ gerekir. Tüm denklemi 2 ile çarpınca: 2 C₂H₆ + 7 O₂ → 4 CO₂ + 6 H₂O olur (C 4=4, H 12=12, O 14=14)."}],"ans":"Denk hâli 2 C₂H₆ + 7 O₂ → 4 CO₂ + 6 H₂O'dur (C 4=4, H 12=12, O 14=14)."},{"q":"İyon-elektron yöntemine gerek kalmadan, KClO₃ → KCl + O₂ ayrışma denklemini denkleştir.","steps":[{"t":"Oksijeni dengele","a":"ortak kat","d":"Solda KClO₃'te 3 oksijen (tek), sağda O₂'de 2 oksijen (çift) var; ortak kat 6'dır."},{"t":"Katsayıları belirle","a":"2 KClO₃ → 2 KCl + 3 O₂","d":"6 oksijen için solda 2 KClO₃, sağda 3 O₂ gerekir; bu da 2 K ve 2 Cl verir. K 2=2, Cl 2=2, O 6=6 olur."}],"ans":"Denk hâli 2 KClO₃ → 2 KCl + 3 O₂'dir (K 2=2, Cl 2=2, O 6=6)."},{"q":"Fe₂O₃ + CO → Fe + CO₂ (demir indirgenmesi) denklemini denkleştir.","steps":[{"t":"Demiri dengele","a":"2 Fe","d":"Solda Fe₂O₃'te 2 demir var; sağa 2 Fe yazılır."},{"t":"Karbon ve oksijeni dengele","a":"3 CO, 3 CO₂","d":"Oksijen sayısını eşitlemek için 3 CO ve 3 CO₂ alınır: solda 3+3=6 O, sağda 3·2=6 O; C 3=3 olur. Sonuç: Fe₂O₃ + 3 CO → 2 Fe + 3 CO₂."}],"ans":"Denk hâli Fe₂O₃ + 3 CO → 2 Fe + 3 CO₂'dir (Fe 2=2, C 3=3, O 6=6)."},{"q":"C₄H₁₀ + O₂ → CO₂ + H₂O (bütan yanması) denklemini denkleştir.","fig":"<svg viewBox='0 0 320 110'><text x='8' y='50' font-size='13' fill='#1a2b45'>2C₄H₁₀ + 13O₂</text><text x='150' y='50' font-size='17' fill='#e0552b'>→</text><text x='185' y='50' font-size='13' fill='#1a2b45'>8CO₂ + 10H₂O</text><text x='160' y='92' font-size='10' text-anchor='middle' fill='#5b6b85'>C:8=8, H:20=20, O:26=26</text></svg>","steps":[{"t":"C ve H'yi dengele","a":"4 CO₂, 5 H₂O","d":"Bir C₄H₁₀ için 4 CO₂ (4 C) ve 5 H₂O (10 H) yazılır."},{"t":"Oksijen ve tam sayı","a":"×2","d":"Sağda 4·2 + 5·1 = 13 oksijen var; solda 13/2 O₂ gerekir. Tümünü 2 ile çarpınca: 2 C₄H₁₀ + 13 O₂ → 8 CO₂ + 10 H₂O (C 8=8, H 20=20, O 26=26)."}],"ans":"Denk hâli 2 C₄H₁₀ + 13 O₂ → 8 CO₂ + 10 H₂O'dur (C 8=8, H 20=20, O 26=26)."},{"q":"Al + H₂SO₄ → Al₂(SO₄)₃ + H₂ denklemini denkleştir.","steps":[{"t":"Sülfat grubunu dengele","a":"3 SO₄","d":"Sağda Al₂(SO₄)₃ üç sülfat grubu içerir; solda 3 H₂SO₄ gerekir, böylece sülfat 3=3 olur."},{"t":"Al ve H'yi tamamla","a":"2 Al, 3 H₂","d":"2 alüminyum için 2 Al; 3 H₂SO₄'teki 6 hidrojen için 3 H₂ gerekir. Sonuç: 2 Al + 3 H₂SO₄ → Al₂(SO₄)₃ + 3 H₂ (Al 2=2, S 3=3, O 12=12, H 6=6)."}],"ans":"Denk hâli 2 Al + 3 H₂SO₄ → Al₂(SO₄)₃ + 3 H₂'dir (Al 2=2, S 3=3, H 6=6, O 12=12)."}]}},"duzine":{"ilkokul":{"kolay":[{"q":"Bir düzine kaç tane demektir?","steps":[{"t":"Düzine sözcüğü","a":"sayma birimi","d":"Düzine, belli sayıda nesneyi bir grup gibi saymak için kullanılan bir birimdir."},{"t":"Sayı","a":"12 tane","d":"Bir düzine her zaman 12 tane demektir."}],"ans":"Bir düzine 12 tane demektir."},{"q":"Yarım düzine yumurta kaç tane eder?","steps":[{"t":"Bir düzine","a":"12 tane","d":"Bir düzine 12 tanedir."},{"t":"Yarısı","a":"12 ÷ 2 = 6","d":"Yarım düzine, 12'nin yarısı yani 6 tanedir."}],"ans":"Yarım düzine 6 tane yumurta eder."},{"q":"İki düzine kalem kaç tane kalem eder?","steps":[{"t":"Bir düzine","a":"12 tane","d":"Bir düzine 12 tanedir."},{"t":"İki düzine","a":"12 × 2 = 24","d":"İki düzine için 12'yi 2 ile çarparız: 24 tane olur."}],"ans":"İki düzine kalem 24 tane eder."},{"q":"Düzineyi neden tek tek saymak yerine kullanırız?","steps":[{"t":"Tek tek saymak","a":"yavaş","d":"Çok sayıda nesneyi birer birer saymak uzun sürer ve karışır."},{"t":"Grupla saymak","a":"hızlı","d":"12'lik gruplar (düzine) halinde sayarsak daha hızlı ve kolay sayarız."}],"ans":"Düzineyi, nesneleri 12'şer gruplayıp daha hızlı saymak için kullanırız."},{"q":"Markette 3 düzine muz alan biri kaç muz almış olur?","fig":"<svg viewBox='0 0 320 150'><rect x='20' y='40' width='80' height='70' rx='6' fill='#9ed9a8' stroke='#1a2b45'/><text x='60' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>12</text><rect x='120' y='40' width='80' height='70' rx='6' fill='#9ed9a8' stroke='#1a2b45'/><text x='160' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>12</text><rect x='220' y='40' width='80' height='70' rx='6' fill='#9ed9a8' stroke='#1a2b45'/><text x='260' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>12</text><text x='160' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>3 düzine = 3 × 12</text></svg>","steps":[{"t":"Bir düzine","a":"12 tane","d":"Her düzine 12 muz demektir."},{"t":"Üç düzine","a":"12 × 3 = 36","d":"Üç düzine için 12'yi 3 ile çarparız: 36 muz eder."}],"ans":"3 düzine muz 36 muz eder."}],"zor":[{"q":"4 düzine bardağın 6 tanesi kırılırsa kaç bardak kalır?","steps":[{"t":"4 düzine","a":"12 × 4 = 48","d":"Önce 4 düzineyi bulalım: 12 × 4 = 48 bardak."},{"t":"Kırılanı çıkar","a":"48 − 6 = 42","d":"6 bardak kırılınca 48'den 6 çıkarırız: 42 bardak kalır."}],"ans":"Geriye 42 bardak kalır."},{"q":"Bir kutuda 12 yumurta var. 5 kutu yumurta toplam kaç düzine eder?","steps":[{"t":"Her kutu","a":"1 düzine","d":"Bir kutuda 12 yumurta olduğu için her kutu 1 düzinedir."},{"t":"Beş kutu","a":"5 düzine","d":"5 kutu, 5 düzine yani 5 × 12 = 60 yumurta eder."}],"ans":"5 kutu yumurta 5 düzine (60 yumurta) eder."},{"q":"30 kalem kaç düzine ve kaç tane kalem eder?","steps":[{"t":"Düzineye böl","a":"30 ÷ 12 = 2 kalan 6","d":"30'u 12'ye bölersek 2 tam düzine olur, geriye 6 kalem kalır."},{"t":"Sonuç","a":"2 düzine + 6","d":"Yani 30 kalem, 2 düzine ile 6 fazladan kalemdir."}],"ans":"30 kalem 2 düzine ve fazladan 6 kalem eder."},{"q":"Bir düzine ile bir deste arasındaki fark nedir?","fig":"<svg viewBox='0 0 320 150'><rect x='30' y='40' width='110' height='70' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='85' y='72' font-size='13' text-anchor='middle' fill='#1a2b45'>düzine</text><text x='85' y='95' font-size='12' text-anchor='middle' fill='#1a2b45'>12 tane</text><rect x='180' y='40' width='110' height='70' rx='6' fill='#9ed9a8' stroke='#1a2b45'/><text x='235' y='72' font-size='13' text-anchor='middle' fill='#1a2b45'>deste</text><text x='235' y='95' font-size='12' text-anchor='middle' fill='#1a2b45'>10 tane</text></svg>","steps":[{"t":"Düzine","a":"12 tane","d":"Düzine 12'lik bir gruptur."},{"t":"Deste","a":"10 tane","d":"Deste ise 10'luk bir gruptur; ikisi de sayma birimidir ama sayıları farklıdır."}],"ans":"Bir düzine 12 tane, bir deste ise 10 tanedir; aralarındaki fark 2 tanedir."},{"q":"Anne yarım düzine elma, baba bir düzine elma alırsa toplam kaç elma olur?","steps":[{"t":"Yarım düzine","a":"6 elma","d":"Yarım düzine 12'nin yarısı, yani 6 elmadır."},{"t":"Toplam","a":"6 + 12 = 18","d":"Babanın 1 düzinesi (12) ile anneninkini (6) toplarsak 18 elma olur."}],"ans":"Toplam 18 elma olur."}]},"ortaokul":{"kolay":[{"q":"Düzine, deste ve çift gibi birimlerin ortak amacı nedir?","steps":[{"t":"Hepsi sayma birimi","a":"grup","d":"Çift (2), deste (10) ve düzine (12); hepsi nesneleri belirli sayıda gruplayan sayma birimleridir."},{"t":"Neden gerekli","a":"kolay sayma","d":"Çok sayıda nesneyi tek tek değil, hazır gruplar halinde saymayı sağlar; sayma hızlanır ve hata azalır."}],"ans":"Çift, deste ve düzinenin ortak amacı çok sayıda nesneyi belirli gruplar halinde hızlı ve düzenli saymaktır."},{"q":"Çift, deste ve düzine sırasıyla kaçar taneyi ifade eder?","fig":"<svg viewBox='0 0 320 150'><rect x='15' y='45' width='85' height='60' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='57' y='72' font-size='12' text-anchor='middle' fill='#1a2b45'>çift</text><text x='57' y='92' font-size='12' text-anchor='middle' fill='#1a2b45'>2</text><rect x='118' y='45' width='85' height='60' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='72' font-size='12' text-anchor='middle' fill='#1a2b45'>deste</text><text x='160' y='92' font-size='12' text-anchor='middle' fill='#1a2b45'>10</text><rect x='221' y='45' width='85' height='60' rx='6' fill='#9ed9a8' stroke='#1a2b45'/><text x='263' y='72' font-size='12' text-anchor='middle' fill='#1a2b45'>düzine</text><text x='263' y='92' font-size='12' text-anchor='middle' fill='#1a2b45'>12</text></svg>","steps":[{"t":"Çift ve deste","a":"2 ve 10","d":"Çift 2 taneyi, deste 10 taneyi ifade eder."},{"t":"Düzine","a":"12","d":"Düzine ise 12 taneyi ifade eder."}],"ans":"Çift 2, deste 10, düzine ise 12 taneyi ifade eder."},{"q":"Bir grosun 12 düzine olduğu bilindiğine göre 1 gros kaç tanedir?","steps":[{"t":"Bir düzine","a":"12 tane","d":"Bir düzine 12 tanedir."},{"t":"12 düzine","a":"12 × 12 = 144","d":"Gros 12 düzine olduğundan 12 × 12 = 144 tane eder."}],"ans":"1 gros 144 tanedir (12 düzine)."},{"q":"Bir nesneyi 'düzine' ile saymak ne zaman bir kolaylık sağlar?","steps":[{"t":"Çok sayı","a":"toplu üretim/satış","d":"Kalem, yumurta, çatal gibi çok sayıda ve aynı nesneler toplu üretilip satılır."},{"t":"Grup avantajı","a":"hesap kolaylığı","d":"12'şer gruplayınca toplamı çarpma ile hızlı buluruz; ayrı ayrı saymaya gerek kalmaz."}],"ans":"Çok sayıdaki aynı nesneleri (yumurta, kalem gibi) toplu olarak sayıp hesaplamada düzine büyük kolaylık sağlar."},{"q":"144 kalem kaç düzine eder?","steps":[{"t":"Bir düzine","a":"12 tane","d":"Her düzine 12 kalemdir."},{"t":"Bölme","a":"144 ÷ 12 = 12","d":"Toplam kalemi 12'ye bölersek düzine sayısını buluruz: 144 ÷ 12 = 12 düzine."}],"ans":"144 kalem 12 düzine eder."}],"zor":[{"q":"Bir düzine 12, bir deste 10 ise 5 düzine ile 5 deste arasındaki tane farkı kaçtır?","steps":[{"t":"5 düzine","a":"5 × 12 = 60","d":"5 düzine 60 tanedir."},{"t":"5 deste ve fark","a":"5 × 10 = 50, fark 10","d":"5 deste 50 tanedir; aralarındaki fark 60 − 50 = 10 tanedir."}],"ans":"5 düzine ile 5 deste arasındaki fark 10 tanedir."},{"q":"Bir tüccar 8 düzine 5 tane bardak almıştır. Toplam kaç bardak almıştır?","steps":[{"t":"8 düzine","a":"8 × 12 = 96","d":"8 düzine 96 bardak eder."},{"t":"Fazla 5 tane","a":"96 + 5 = 101","d":"Bunun üzerine 5 bardak daha eklenir: 101 bardak olur."}],"ans":"Tüccar toplam 101 bardak almıştır."},{"q":"100 yumurtayı düzineli kutulara koyarsak kaç dolu kutu olur ve kaç yumurta artar?","steps":[{"t":"Düzineye böl","a":"100 ÷ 12 = 8 kalan 4","d":"100'ü 12'ye bölersek 8 tam düzine olur, geriye 4 yumurta kalır."},{"t":"Yorum","a":"8 dolu kutu, 4 artar","d":"Yani 8 kutu dolar, 4 yumurta tek başına kalır."}],"ans":"8 dolu düzine kutu olur ve 4 yumurta artar."},{"q":"Neden 12 sayısı (düzine) gruplamak için pratik bir sayıdır?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='30' width='240' height='40' fill='none' stroke='#1a2b45'/><line x1='80' y1='30' x2='80' y2='70' stroke='#1a2b45'/><line x1='120' y1='30' x2='120' y2='70' stroke='#1a2b45'/><line x1='160' y1='30' x2='160' y2='70' stroke='#1a2b45'/><line x1='200' y1='30' x2='200' y2='70' stroke='#1a2b45'/><line x1='240' y1='30' x2='240' y2='70' stroke='#1a2b45'/><text x='160' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>12 = 2·6 = 3·4 = 12·1</text><text x='160' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>1,2,3,4,6,12 ile tam bölünür</text></svg>","steps":[{"t":"Bölenleri çok","a":"1,2,3,4,6,12","d":"12 sayısı 1, 2, 3, 4, 6 ve 12'ye tam bölünür; bu yüzden eşit parçalara ayırmak kolaydır."},{"t":"Pratik kullanım","a":"yarısı, üçte biri tam","d":"Yarısı (6), üçte biri (4), dörtte biri (3) tam sayı olduğundan paylaştırmada 10'a göre daha kullanışlıdır."}],"ans":"12'nin pek çok tam böleni (1, 2, 3, 4, 6, 12) olduğu için yarıya, üçe, dörde kolayca bölünür; bu yüzden düzine gruplamak için pratiktir."},{"q":"3 düzine 4 tane çatal alan biri, bunların yarısını kullanırsa kaç çatal kullanmış olur?","steps":[{"t":"Toplam çatal","a":"3 × 12 + 4 = 40","d":"3 düzine 36 çataldır, üstüne 4 eklenince toplam 40 çatal olur."},{"t":"Yarısı","a":"40 ÷ 2 = 20","d":"40 çatalın yarısı 20 çataldır."}],"ans":"20 çatal kullanmış olur."}]},"lise":{"kolay":[{"q":"Düzine gibi sabit sayıda nesneyi temsil eden birimler kimyada hangi büyük sayma birimine zemin hazırlar?","steps":[{"t":"Sabit sayı birimi","a":"düzine = 12","d":"Düzine, her zaman tam 12 taneyi gösteren sabit bir sayma birimidir; sayıyı kütleden bağımsız tutar."},{"t":"Kimyaya geçiş","a":"mol","d":"Aynı mantıkla kimyada çok küçük tanecikleri saymak için 'mol' adlı dev bir sayma birimi tanımlanır."}],"ans":"Düzine gibi sabit sayma birimleri, kimyada tanecikleri saymak için kullanılan 'mol' kavramına zemin hazırlar."},{"q":"Düzine ile mol arasındaki temel benzerlik nedir?","steps":[{"t":"İkisi de sabit sayı","a":"belirli adet","d":"Düzine her zaman 12 taneyi, mol ise her zaman 6,02·10²³ taneyi temsil eder."},{"t":"Sayma amacı","a":"grupla say","d":"Her ikisi de çok sayıda nesneyi tek bir birimle ifade ederek saymayı kolaylaştırır."}],"ans":"Hem düzine hem mol, sabit bir tane sayısını (12 ve 6,02·10²³) temsil eden sayma birimleridir."},{"q":"Bir düzine kalem ile bir düzine yumurta aynı sayıda nesne içerir mi?","steps":[{"t":"Sayı aynı","a":"12 ve 12","d":"Düzine yalnızca sayıyı belirler; kalem de yumurta da 12 tanedir."},{"t":"Kütle farklı","a":"farklı ağırlık","d":"Sayıları eşit olsa da kalem ile yumurtanın kütleleri farklıdır; birim sayıyı sabitler, kütleyi değil."}],"ans":"Evet, ikisi de 12 tanedir; düzine sadece sayıyı belirler, nesnelerin kütlesini değil."},{"q":"2,5 düzine kalem kaç tane kalem eder?","steps":[{"t":"Bir düzine","a":"12 tane","d":"Her düzine 12 kalemdir."},{"t":"Çarpma","a":"12 × 2,5 = 30","d":"2,5 düzine için 12 ile 2,5'i çarparız: 30 kalem eder."}],"ans":"2,5 düzine kalem 30 kalem eder."},{"q":"Neden çok küçük tanecikleri saymak için düzineden çok daha büyük bir birime ihtiyaç duyarız?","steps":[{"t":"Tanecik çok küçük","a":"atom/molekül","d":"Atom ve moleküller gözle görülemeyecek kadar küçük olduğundan bir gramda bile akıl almaz sayıda bulunur."},{"t":"12 yetersiz","a":"çok büyük birim gerek","d":"12'lik düzine bu sayıların yanında çok küçük kalır; bu yüzden 6,02·10²³ büyüklüğünde 'mol' birimi kullanılır."}],"ans":"Tanecikler çok küçük ve çok sayıda olduğundan, 12'lik düzine yetersiz kalır; mol gibi çok büyük bir sayma birimine ihtiyaç duyarız."}],"zor":[{"q":"Düzine kavramı, kimyadaki mol kavramının mantığını anlamada nasıl bir köprü kurar?","steps":[{"t":"Soyutlama","a":"sabit sayı = birim","d":"Düzine, 'belirli sayıda nesneyi tek isimle anma' fikrini somutlaştırır; 12 demek yerine 'düzine' deriz."},{"t":"Ölçeklendirme","a":"12 → 6,02·10²³","d":"Aynı mantık kimyada ölçeklenir: tanecik sayısı dev olduğundan birim 12 yerine 6,02·10²³ seçilir ve bu birime mol denir."}],"ans":"Düzine, 'sabit bir sayıyı tek birimle ifade etme' fikrini öğretir; mol de aynı fikrin çok büyük tanecik sayılarına uyarlanmış halidir, bu yüzden düzine mol'ü anlamada köprü kurar."},{"q":"Bir öğrenci 3,5 düzine bilye almıştır. Bunların çeyreğini kardeşine verirse kendinde kaç bilye kalır?","steps":[{"t":"Toplam bilye","a":"12 × 3,5 = 42","d":"3,5 düzine için 12 ile 3,5'i çarparız: 42 bilye eder."},{"t":"Çeyreğini ver","a":"42 ÷ 4 = 10,5","d":"42'nin çeyreği 10,5 olur; ancak bilye tam sayı olmalıdır, dolayısıyla bu dağıtım tam bölünmez."},{"t":"Yorum","a":"tam bölünmez","d":"42 sayısı 4'e tam bölünmediğinden bilyeler eşit çeyreklere ayrılamaz; bu, sayma biriminin tam katı önemini gösterir."}],"ans":"42 bilyenin çeyreği 10,5 çıkar; bilye bölünemediği için bu sayı 4 eşit parçaya tam ayrılamaz, yani dağıtım gerçekte yapılamaz."},{"q":"Düzine ile sayarken neden nesnelerin kütlesini bilmek zorunda değiliz, mol'de ise molar kütle neden gerekir?","steps":[{"t":"Düzine: doğrudan say","a":"gözle sayılır","d":"Düzinedeki nesneler büyük ve sayılabilir olduğundan kütleye gerek kalmadan doğrudan 12'şer sayarız."},{"t":"Mol: dolaylı say","a":"kütle üzerinden","d":"Tanecikler tek tek sayılamayacak kadar küçük olduğundan, mol'ü ölçmek için kütleden (molar kütle) yararlanırız."}],"ans":"Düzinedeki nesneler doğrudan gözle sayılabildiği için kütle gerekmez; mol'deki tanecikler sayılamayacak kadar küçük olduğundan, sayıyı belirlemek için molar kütle üzerinden ölçüm yapmak gerekir."},{"q":"Bir fabrika günde 18 gros vida üretiyor. Bir gros 12 düzine olduğuna göre günlük üretim kaç vidadır?","fig":"<svg viewBox='0 0 320 140'><text x='160' y='35' font-size='12' text-anchor='middle' fill='#1a2b45'>1 gros = 12 düzine = 144 tane</text><rect x='40' y='55' width='240' height='40' fill='none' stroke='#1a2b45'/><text x='160' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>18 gros × 144</text><text x='160' y='120' font-size='12' text-anchor='middle' fill='#1a2b45'>= 2592 vida</text></svg>","steps":[{"t":"Bir gros","a":"12 × 12 = 144","d":"Bir gros 12 düzine, yani 144 tanedir."},{"t":"18 gros","a":"18 × 144 = 2592","d":"Günlük 18 gros için 18 ile 144'ü çarparız: 2592 vida eder."}],"ans":"Fabrika günde 2592 vida üretir."},{"q":"Bir tüccarda 5 gros, 7 düzine ve 9 tane fazladan kalem vardır. Toplam kaç kalemi olduğunu adım adım bulunuz.","steps":[{"t":"Gros kısmı","a":"5 × 144 = 720","d":"5 gros, her biri 144 olmak üzere 720 kalem eder."},{"t":"Düzine kısmı","a":"7 × 12 = 84","d":"7 düzine 84 kalem eder."},{"t":"Topla","a":"720 + 84 + 9 = 813","d":"Gros, düzine ve fazla taneleri toplarız: 720 + 84 + 9 = 813 kalem."}],"ans":"Tüccarın toplam 813 kalemi vardır."}]}},"esitFarkli":{"ilkokul":{"kolay":[{"q":"10 tane misket ile 10 tane balon aynı ağırlıkta mıdır?","steps":[{"t":"Sayı aynı","a":"ikisi de 10","d":"Misketler de balonlar da 10 tanedir; sayıları eşittir."},{"t":"Ağırlık farklı","a":"misket ağır","d":"Ama misket balondan çok daha ağırdır; aynı sayıda olsalar da ağırlıkları farklıdır."}],"ans":"Hayır; sayıları eşit olsa da misketler balonlardan daha ağırdır."},{"q":"Aynı sayıda elma ve kiraz hangisi daha ağır gelir?","steps":[{"t":"Tek tane","a":"elma ağır","d":"Bir elma, bir kirazdan çok daha ağırdır."},{"t":"Aynı sayı","a":"elmalar ağır","d":"Aynı sayıda alsak bile elmalar toplamda daha ağır gelir."}],"ans":"Aynı sayıda olsalar da elmalar kirazlardan daha ağır gelir."},{"q":"12 tane saçma tanesi ile 12 tane patlamış mısır eşit ağırlıkta mıdır?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='100' r='25' fill='#5b6b85' stroke='#1a2b45'/><text x='90' y='105' font-size='10' text-anchor='middle' fill='#fff'>ağır</text><circle cx='230' cy='100' r='25' fill='#f0e2b6' stroke='#1a2b45'/><text x='230' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>hafif</text><text x='90' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>12 saçma</text><text x='230' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>12 mısır</text></svg>","steps":[{"t":"Sayı aynı","a":"ikisi de 12","d":"Saçma da mısır da 12 tanedir; sayıları eşittir."},{"t":"Ağırlık farklı","a":"saçma ağır","d":"Saçma tanesi mısırdan çok daha ağır olduğundan toplam ağırlık eşit değildir."}],"ans":"Hayır; sayıları eşit olsa da 12 saçma, 12 mısırdan çok daha ağırdır."},{"q":"Neden aynı sayıda iki farklı nesne farklı ağırlıkta olabilir?","steps":[{"t":"Tek nesne ağırlığı","a":"farklı","d":"Her nesnenin tek başına ağırlığı farklıdır."},{"t":"Toplam","a":"ağır olan baskın","d":"Sayı aynı olsa bile tek tane ağırlığı büyük olanın toplamı daha ağır olur."}],"ans":"Çünkü her nesnenin tek başına ağırlığı farklıdır; sayı aynı olsa da ağır olanın toplamı daha ağır gelir."},{"q":"Terazinin bir kefesine 5 ceviz, diğerine 5 fındık koyarsak ne olur?","steps":[{"t":"Sayı eşit","a":"5 ve 5","d":"İki kefede de 5'er tane vardır; sayılar eşittir."},{"t":"Ceviz ağır","a":"o kefe iner","d":"Ceviz fındıktan ağır olduğundan cevizli kefe aşağı iner."}],"ans":"Sayıları eşit olsa da ceviz daha ağır olduğundan cevizli kefe aşağı iner."}],"zor":[{"q":"12 tane oyun hamuru topu ile 12 tane demir bilye karşılaştırılırsa hangisi ağır olur, neden?","steps":[{"t":"Sayı eşit","a":"ikisi de 12","d":"Hamur topları da demir bilyeler de 12 tanedir."},{"t":"Madde farkı","a":"demir ağır","d":"Demir, oyun hamurundan daha ağır bir maddedir; bu yüzden 12 demir bilye toplamda daha ağır gelir."}],"ans":"12 demir bilye daha ağırdır; çünkü demir, oyun hamurundan daha ağır bir maddedir."},{"q":"Aynı sayıda farklı nesnenin ağırlığını eşitlemek için ne yapmak gerekir?","steps":[{"t":"Eşit değil","a":"sayı yetmiyor","d":"Sayıyı eşit tutmak ağırlığı eşitlemez, çünkü tek tane ağırlıkları farklıdır."},{"t":"Sayı ayarı","a":"hafif olandan çok","d":"Ağırlıkları eşitlemek için hafif olan nesneden daha çok almak gerekir."}],"ans":"Ağırlığı eşitlemek için hafif olan nesneden daha fazla sayıda almak gerekir; sadece sayıyı eşitlemek yetmez."},{"q":"Bir poşet pamuk ile aynı sayıda demir vidayı taşımak neden farklıdır?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='80' r='30' fill='#eef2f8' stroke='#1a2b45'/><text x='90' y='85' font-size='10' text-anchor='middle' fill='#1a2b45'>pamuk</text><rect x='200' y='60' width='50' height='40' fill='#5b6b85' stroke='#1a2b45'/><text x='225' y='85' font-size='10' text-anchor='middle' fill='#fff'>vida</text><text x='90' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>hafif</text><text x='225' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>ağır</text></svg>","steps":[{"t":"Sayı aynı","a":"eşit adet","d":"Pamuk parçaları ve vidalar aynı sayıda olabilir."},{"t":"Ağırlık çok farklı","a":"vida ağır","d":"Demir vidalar pamuktan çok daha ağır olduğundan, taşımak çok daha güçtür."}],"ans":"Aynı sayıda olsalar da demir vidalar pamuktan çok daha ağır olduğundan taşımak çok daha zordur."},{"q":"Annene yardım ederken 10 tane patates mi yoksa 10 tane limon mu taşımak daha kolaydır?","steps":[{"t":"Sayı eşit","a":"10 ve 10","d":"İkisi de 10 tanedir; sayıları aynıdır."},{"t":"Limon hafif","a":"daha kolay","d":"Limon patatesten daha hafif olduğundan 10 limon taşımak daha kolaydır."}],"ans":"10 limon taşımak daha kolaydır; çünkü limon patatesten daha hafiftir, sayıları eşit olsa bile."},{"q":"Bir kutuya sığan ceviz sayısı ile fındık sayısı neden farklı olabilir?","steps":[{"t":"Boyut farkı","a":"fındık küçük","d":"Fındık cevizden daha küçüktür, bu yüzden aynı kutuya daha çok fındık sığar."},{"t":"Sayı-kütle","a":"farklı dolar","d":"Aynı kutu daha çok fındık alsa bile, her birinin ağırlığı farklı olduğundan toplam ağırlıkları da farklıdır."}],"ans":"Fındık daha küçük olduğundan kutuya daha çok sığar; nesnelerin boyut ve ağırlığı farklı olduğundan sayıları ve toplam ağırlıkları farklı olur."}]},"ortaokul":{"kolay":[{"q":"Aynı sayıda hidrojen atomu ile oksijen atomu eşit kütlede midir?","steps":[{"t":"Sayı aynı","a":"eşit adet","d":"Örneğin 100 hidrojen ve 100 oksijen atomu sayıca eşittir."},{"t":"Kütle farklı","a":"oksijen ağır","d":"Bir oksijen atomu bir hidrojen atomundan çok daha ağırdır; bu yüzden kütleleri eşit olmaz."}],"ans":"Hayır; aynı sayıda olsalar da oksijen atomları hidrojen atomlarından daha ağır olduğu için kütleleri farklıdır."},{"q":"Atomların kütlesinin farklı olmasının nedeni nedir?","steps":[{"t":"Tanecik içeriği","a":"proton-nötron","d":"Atomun kütlesi büyük ölçüde içindeki proton ve nötron sayısına bağlıdır."},{"t":"Element farkı","a":"farklı atom = farklı kütle","d":"Farklı elementlerin atomlarında farklı sayıda proton ve nötron bulunur, bu yüzden kütleleri farklıdır."}],"ans":"Atomların kütlesi içindeki proton ve nötron sayısına bağlıdır; farklı elementlerde bu sayılar farklı olduğundan atom kütleleri de farklıdır."},{"q":"12 karbon atomu ile 12 oksijen atomundan hangisinin toplam kütlesi daha büyüktür?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='80' r='28' fill='#33415588' stroke='#1a2b45'/><text x='90' y='85' font-size='12' text-anchor='middle' fill='#fff'>C</text><circle cx='230' cy='80' r='32' fill='#e0552b' stroke='#1a2b45'/><text x='230' y='85' font-size='12' text-anchor='middle' fill='#fff'>O</text><text x='90' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>12 (kütle 12)</text><text x='230' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>16 (kütle 16)</text></svg>","steps":[{"t":"Atom kütleleri","a":"C=12, O=16","d":"Bir karbon atomunun kütlesi 12, bir oksijen atomunun kütlesi 16 birimdir."},{"t":"Sayı eşit, kütle farklı","a":"oksijen ağır","d":"Sayıları eşit (12'şer) olsa da her oksijen daha ağır olduğundan toplam kütlesi daha büyüktür."}],"ans":"12 oksijen atomunun toplam kütlesi daha büyüktür; çünkü oksijen atomu karbon atomundan daha ağırdır."},{"q":"Aynı kütlede karbon ve oksijen alırsak atom sayıları eşit olur mu?","steps":[{"t":"Hafif olandan çok","a":"karbon fazla","d":"Karbon atomu daha hafif olduğundan, aynı kütleyi oluşturmak için daha çok karbon atomu gerekir."},{"t":"Sonuç","a":"sayılar farklı","d":"Bu yüzden eşit kütledeki karbonda, oksijene göre daha fazla atom bulunur; sayılar eşit olmaz."}],"ans":"Hayır; karbon daha hafif olduğundan aynı kütlede karbonda oksijenden daha çok atom bulunur, atom sayıları eşit olmaz."},{"q":"Eşit sayıda farklı atomun kütlesinin farklı olması bize molar kütle hakkında ne sezdirir?","steps":[{"t":"Atom başına kütle","a":"elemente özgü","d":"Her elementin atomunun kendine özgü bir kütlesi vardır."},{"t":"Mol kütlesi","a":"farklı g/mol","d":"Aynı sayıda (1 mol) atom alsak bile her elementin kütlesi farklı çıkar; buna molar kütle denir."}],"ans":"Eşit sayıda farklı atomun farklı kütlede olması, her elementin 1 molünün farklı kütleye (molar kütleye) sahip olduğunu sezdirir."}],"zor":[{"q":"1 mol hidrojen atomu ile 1 mol oksijen atomu aynı sayıda tanecik içerdiği halde neden farklı kütlededir?","steps":[{"t":"Sayı eşit","a":"6,02·10²³ tane","d":"Her ikisi de 1 mol olduğundan aynı sayıda (6,02·10²³) atom içerir."},{"t":"Atom kütlesi farklı","a":"H=1, O=16 g/mol","d":"Bir oksijen atomu bir hidrojen atomundan 16 kat ağır olduğundan, 1 mol oksijen 16 g, 1 mol hidrojen 1 g gelir."}],"ans":"İkisi de eşit sayıda (6,02·10²³) atom içerir ama oksijen atomu hidrojenden ağır olduğundan, 1 mol oksijen 16 g, 1 mol hidrojen 1 g'dır; sayı eşit, kütle farklıdır."},{"q":"Aynı kütlede (örneğin 12 g) karbon ve magnezyum alındığında hangisinde daha çok atom bulunur?","steps":[{"t":"Atom kütleleri","a":"C=12, Mg=24","d":"Karbonun atom kütlesi 12, magnezyumunki 24 g/mol'dür; magnezyum atomu daha ağırdır."},{"t":"Mol karşılaştır","a":"12 g C = 1 mol, 12 g Mg = 0,5 mol","d":"12 g karbon 1 mol (6,02·10²³ atom), 12 g magnezyum yalnızca 0,5 mol (3,01·10²³ atom) eder."}],"ans":"Aynı 12 g kütlede karbonda daha çok atom bulunur; çünkü karbon atomu daha hafif olduğundan aynı kütle daha fazla (iki kat) atom içerir."},{"q":"Bir tepkimede 'aynı sayıda atom' ile 'aynı kütlede madde' kavramlarını karıştırmak neden hataya yol açar?","fig":"<svg viewBox='0 0 320 150'><circle cx='70' cy='70' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='75' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='110' cy='70' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='75' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='70' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='75' font-size='10' text-anchor='middle' fill='#fff'>O</text><circle cx='265' cy='70' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='265' y='75' font-size='10' text-anchor='middle' fill='#fff'>O</text><text x='90' y='120' font-size='9' text-anchor='middle' fill='#1a2b45'>2 H (kütle 2)</text><text x='242' y='120' font-size='9' text-anchor='middle' fill='#1a2b45'>2 O (kütle 32)</text></svg>","steps":[{"t":"Sayı ≠ kütle","a":"farklı kavram","d":"Atom sayısı tanecik adedini, kütle ise toplam ağırlığı belirtir; bu ikisi farklı atomlarda eşit olmaz."},{"t":"Stokiyometri etkisi","a":"mol oranı önemli","d":"Tepkimeler atom/mol sayısı oranıyla yürür; kütleyi sayı sanmak mol oranını ve hesabı yanlış yapar."}],"ans":"Atom sayısı (adet) ile kütle (ağırlık) farklı kavramlardır; farklı atomlarda eşit sayı eşit kütle demek değildir. Tepkimeler mol/atom oranıyla yürüdüğünden, kütleyi sayı gibi kullanmak stokiyometri hesabını yanlış yapar."},{"q":"6,02·10²³ tane demir atomu 56 g, aynı sayıda kükürt atomu 32 g geliyorsa bu fark neden kaynaklanır?","steps":[{"t":"Sayı eşit","a":"1'er mol","d":"Her ikisi de 6,02·10²³ tane, yani 1'er mol atom içerir."},{"t":"Atom kütlesi","a":"Fe=56, S=32","d":"Demir atomu 56, kükürt atomu 32 birim kütleye sahiptir; demir atomu daha ağırdır."},{"t":"Sonuç","a":"56 g > 32 g","d":"Aynı sayıda atom olsa da demir atomu ağır olduğundan toplam kütlesi (56 g) kükürtten (32 g) büyüktür."}],"ans":"İkisi de 1 mol (6,02·10²³ atom) olmasına rağmen demir atomu kükürt atomundan ağır olduğundan, demirin molar kütlesi 56 g, kükürdünki 32 g'dır; fark atom kütlelerinden kaynaklanır."},{"q":"Molar kütle kavramı, 'eşit sayıda farklı atom farklı kütlededir' gerçeğiyle nasıl ilişkilidir?","steps":[{"t":"Gözlem","a":"sayı eşit, kütle farklı","d":"Eşit sayıda farklı atomun farklı kütlede olması, her atomun kendine özgü bir kütlesi olmasından kaynaklanır."},{"t":"Molar kütle tanımı","a":"1 molün kütlesi","d":"Molar kütle, 1 mol (6,02·10²³ tane) atomun gram cinsinden kütlesidir; her element için farklıdır ve atom kütlesine eşit sayıdadır."}],"ans":"Eşit sayıda farklı atomun farklı kütlede olması, her elementin atomunun farklı kütlesi olmasından gelir; molar kütle de bu gerçeği niceler: her elementin 1 molünün (eşit sayıda atomun) kütlesi farklıdır ve atom kütlesine eşit sayıyı g cinsinden verir."}]},"lise":{"kolay":[{"q":"Eşit sayıda farklı atomun farklı kütlede olmasının temel nedeni nedir?","steps":[{"t":"Atom kütlesi","a":"proton + nötron","d":"Bir atomun kütlesi çekirdeğindeki proton ve nötron sayısına bağlıdır; elektronun katkısı ihmal edilir."},{"t":"Elemente özgü","a":"farklı çekirdek","d":"Farklı elementlerin çekirdeklerinde farklı sayıda nükleon bulunur, bu yüzden atom kütleleri ve eşit sayıdaki kütleleri farklıdır."}],"ans":"Atom kütlesi çekirdekteki proton ve nötron sayısına bağlıdır; farklı elementlerde bu sayı farklı olduğundan, eşit sayıda atom alınsa bile kütleleri farklı olur."},{"q":"Molar kütle nedir ve neden her element için farklıdır?","steps":[{"t":"Tanım","a":"1 molün g kütlesi","d":"Molar kütle, 1 mol (6,02·10²³ tane) taneciğin gram cinsinden kütlesidir; birimi g/mol'dür."},{"t":"Element farkı","a":"atom kütlesine bağlı","d":"Atom kütleleri elementten elemente değiştiğinden, eşit sayıdaki (1 mol) atomun kütlesi de farklıdır."}],"ans":"Molar kütle, 1 moldeki taneciklerin gram cinsinden kütlesidir (g/mol); atom kütleleri elemente özgü olduğundan her element için farklı bir değer alır."},{"q":"1 mol H atomu 1 g, 1 mol C atomu 12 g geliyorsa atom sayıları arasında nasıl bir ilişki vardır?","steps":[{"t":"Sayı eşit","a":"6,02·10²³","d":"Her ikisi de 1 mol olduğundan eşit sayıda (6,02·10²³) atom içerir."},{"t":"Kütle oranı","a":"12 kat","d":"Karbon atomu hidrojenden 12 kat ağır olduğundan, eşit sayıda olmalarına rağmen karbonun kütlesi 12 katıdır."}],"ans":"Atom sayıları eşittir (her biri 6,02·10²³); kütle farkı yalnızca karbon atomunun hidrojenden 12 kat ağır olmasından kaynaklanır."},{"q":"4 g hidrojen (H, 1 g/mol) ile 4 g helyum (He, 4 g/mol) örneklerinden hangisi daha çok atom içerir?","steps":[{"t":"Mol hesabı","a":"mol = kütle / molar kütle","d":"4 g H = 4 / 1 = 4 mol; 4 g He = 4 / 4 = 1 mol."},{"t":"Atom sayısı","a":"H daha çok","d":"4 mol hidrojen, 1 mol helyumdan dört kat fazla atom içerir."}],"ans":"4 g hidrojen daha çok atom içerir; çünkü hidrojen atomu daha hafif olduğundan aynı kütle (4 g) dört kat fazla (4 mol) atom barındırır."},{"q":"Neden iki maddenin kütlesi eşit olduğu halde mol sayıları (tanecik sayıları) farklı olabilir?","steps":[{"t":"Molar kütle farkı","a":"g/mol farklı","d":"Her maddenin molar kütlesi farklı olduğundan, aynı kütle farklı sayıda mole karşılık gelir."},{"t":"Mol = kütle / molar kütle","a":"ters orantı","d":"Eşit kütlede molar kütlesi küçük olan madde daha çok mol (daha çok tanecik) içerir."}],"ans":"Maddelerin molar kütleleri farklı olduğundan, eşit kütle farklı mol sayısına karşılık gelir; molar kütlesi küçük olan madde aynı kütlede daha çok tanecik içerir."}],"zor":[{"q":"Eşit sayıda farklı atomun farklı kütlede olması gerçeği, mol ve molar kütle kavramlarının doğmasını nasıl gerektirmiştir?","steps":[{"t":"Sorun","a":"sayı-kütle ayrımı","d":"Tanecikler sayılamadığından kütleyle çalışılır; ama eşit sayıda farklı atom farklı kütlede olduğu için kütle tek başına tanecik sayısını vermez."},{"t":"Çözüm","a":"mol + molar kütle","d":"Mol, sabit tanecik sayısını (6,02·10²³) tanımlar; molar kütle ise her elementin 1 molünün kütlesini verir, böylece kütleden tanecik sayısına geçilir."}],"ans":"Eşit sayıda farklı atom farklı kütlede olduğundan kütle, tanecik sayısını doğrudan vermez; bu sorunu çözmek için sabit tanecik sayısını tanımlayan mol ve her elementin 1 molünün kütlesini veren molar kütle kavramları geliştirilmiştir."},{"q":"32 g oksijen gazı (O₂, 32 g/mol) ile 32 g metan (CH₄, 16 g/mol) örneklerinin molekül sayılarını karşılaştırınız.","steps":[{"t":"Mol O₂","a":"32 / 32 = 1 mol","d":"O₂'nin molar kütlesi 32 g/mol olduğundan 32 g, 1 mol O₂ eder."},{"t":"Mol CH₄","a":"32 / 16 = 2 mol","d":"CH₄'ün molar kütlesi 16 g/mol olduğundan 32 g, 2 mol CH₄ eder."},{"t":"Molekül sayısı","a":"CH₄ iki kat","d":"2 mol CH₄, 1 mol O₂'nin iki katı kadar molekül (2 × 6,02·10²³) içerir."}],"ans":"Eşit kütlede (32 g) olmalarına rağmen metan iki kat fazla molekül içerir; çünkü CH₄'ün molar kütlesi (16 g/mol) oksijenin (32 g/mol) yarısıdır, dolayısıyla aynı kütle iki kat mol verir."},{"q":"1 mol Mg (24 g/mol) atomu ile 1 mol O (16 g/mol) atomunun kütlelerini ve atom sayılarını karşılaştırınız.","steps":[{"t":"Atom sayısı","a":"eşit: 6,02·10²³","d":"Her ikisi de 1 mol olduğundan eşit sayıda (6,02·10²³) atom içerir."},{"t":"Kütle","a":"Mg 24 g, O 16 g","d":"Magnezyum atomu daha ağır olduğundan 1 mol Mg 24 g, 1 mol O 16 g gelir."},{"t":"Yorum","a":"sayı eşit, kütle farklı","d":"Bu, 'eşit sayı eşit kütle demek değildir' ilkesinin somut örneğidir: aynı tanecik sayısı, farklı toplam kütle verir."}],"ans":"İkisi de 6,02·10²³ atom (eşit sayıda) içerir, ancak magnezyum atomu ağır olduğundan 1 mol Mg 24 g, 1 mol O 16 g gelir; eşit sayı eşit kütle anlamına gelmez."},{"q":"Eşit hacimde (NK) iki farklı gaz aynı sayıda molekül içerdiği halde neden farklı kütlede olabilir?","fig":"<svg viewBox='0 0 320 155'><rect x='35' y='35' width='90' height='90' rx='6' fill='none' stroke='#1a2b45'/><circle cx='60' cy='65' r='6' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='95' cy='80' r='6' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='70' cy='100' r='6' fill='#cfd8e8' stroke='#1a2b45'/><text x='80' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>H₂ (hafif)</text><rect x='195' y='35' width='90' height='90' rx='6' fill='none' stroke='#1a2b45'/><circle cx='220' cy='65' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='255' cy='80' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='230' cy='100' r='9' fill='#e0552b' stroke='#1a2b45'/><text x='240' y='145' font-size='10' text-anchor='middle' fill='#1a2b45'>O₂ (ağır)</text></svg>","steps":[{"t":"Avogadro ilkesi","a":"eşit hacim = eşit molekül","d":"NK'de eşit hacimdeki gazlar eşit sayıda molekül içerir (Avogadro hipotezi)."},{"t":"Molar kütle farkı","a":"O₂ ağır","d":"Molekül sayısı eşit olsa da O₂ (32 g/mol) molekülü H₂ (2 g/mol) molekülünden ağır olduğundan, eşit hacim O₂ daha kütlelidir."}],"ans":"NK'de eşit hacimdeki gazlar eşit sayıda molekül içerir; ancak molekül kütleleri (molar kütleleri) farklı olduğundan, eşit sayıda molekül farklı toplam kütle verir, örneğin O₂ örneği H₂'den ağır olur."},{"q":"Bir öğrenci 'eşit sayıda atom her zaman eşit kütle demektir' diyor. Bu yargıyı bir hesapla çürütünüz.","steps":[{"t":"Örnek seç","a":"1 mol Na, 1 mol Ca","d":"1 mol sodyum ve 1 mol kalsiyum alalım; her ikisi de 6,02·10²³ atom (eşit sayıda) içerir."},{"t":"Kütleleri bul","a":"Na 23 g, Ca 40 g","d":"Molar kütleler Na = 23 g/mol, Ca = 40 g/mol olduğundan kütleleri 23 g ve 40 g çıkar."},{"t":"Sonuç","a":"23 g ≠ 40 g","d":"Eşit sayıda atom olmasına rağmen kütleler farklıdır; yargı yanlıştır."}],"ans":"Yargı yanlıştır: 1 mol Na ve 1 mol Ca eşit sayıda (6,02·10²³) atom içerir ama kütleleri sırasıyla 23 g ve 40 g'dır; eşit sayıda atom eşit kütle anlamına gelmez, kütle atomun molar kütlesine bağlıdır."}]}},"kutleHesabi":{"ilkokul":{"kolay":[{"q":"Bir tarif 1 bardak un ile 1 bardak süt ister. 3 bardak un kullanırsak kaç bardak süt gerekir?","fig":"<svg viewBox='0 0 320 120'><rect x='40' y='45' width='30' height='40' fill='#cfd8e8' stroke='#1a2b45'/><rect x='80' y='45' width='30' height='40' fill='#cfd8e8' stroke='#1a2b45'/><rect x='120' y='45' width='30' height='40' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>3 un</text><text x='180' y='70' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><rect x='220' y='45' width='28' height='40' fill='#2b6be0'/><rect x='255' y='45' width='28' height='40' fill='#2b6be0'/><rect x='290' y='45' width='28' height='40' fill='#2b6be0'/><text x='270' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>3 süt</text></svg>","steps":[{"t":"Oranı bul","a":"1 un = 1 süt","d":"Tarif her 1 bardak una karşılık 1 bardak süt ister; oran birebirdir."},{"t":"Çoğalt","a":"3 bardak","d":"Un 3 bardak olunca süt de 3 bardak olur; oran aynı kalır."}],"ans":"Oran birebir olduğu için 3 bardak una 3 bardak süt gerekir."},{"q":"Bir oyuncak araba yapmak için 4 tekerlek gerekiyor. 5 araba için kaç tekerlek lazım?","steps":[{"t":"Bir araba","a":"4 tekerlek","d":"Her arabaya 4 tekerlek takılır."},{"t":"Beş araba","a":"20 tekerlek","d":"5 araba × 4 tekerlek = 20 tekerlek gerekir."}],"ans":"Her arabaya 4 tekerlek gerektiğinden 5 araba için 5 × 4 = 20 tekerlek lazımdır."},{"q":"2 limondan 1 bardak limonata çıkıyor. 8 limonla kaç bardak limonata yapılır?","fig":"<svg viewBox='0 0 320 110'><circle cx='60' cy='50' r='12' fill='#e0c23a'/><circle cx='95' cy='50' r='12' fill='#e0c23a'/><text x='78' y='90' font-size='10' text-anchor='middle' fill='#1a2b45'>2 limon</text><text x='150' y='55' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><rect x='200' y='35' width='26' height='34' fill='#2b6be0'/><text x='213' y='90' font-size='10' text-anchor='middle' fill='#1a2b45'>1 bardak</text></svg>","steps":[{"t":"Grupla","a":"2'şer limon","d":"Her bardak için 2 limon gerekir; limonları 2'şerli gruplarız."},{"t":"Say","a":"4 bardak","d":"8 limon ÷ 2 = 4 grup, yani 4 bardak limonata çıkar."}],"ans":"Her bardak 2 limon istediğinden 8 ÷ 2 = 4 bardak limonata yapılır."},{"q":"Bir kek için 2 yumurta gerekiyor. 6 yumurtayla aynı tarifle kaç kek yapılır?","steps":[{"t":"Bir kek","a":"2 yumurta","d":"Tarif her kek için 2 yumurta ister."},{"t":"Böl","a":"3 kek","d":"6 yumurta ÷ 2 = 3, yani 3 kek yapılabilir."}],"ans":"Her kek 2 yumurta istediğinden 6 ÷ 2 = 3 kek yapılır."},{"q":"Madde miktarı tartılırken neden 'kütle' deriz ve birimi nedir?","steps":[{"t":"Kütle nedir","a":"madde miktarı","d":"Kütle, bir cisimde ne kadar madde olduğunu gösterir."},{"t":"Birimi","a":"gram, kilogram","d":"Günlük hayatta kütleyi gram (g) ve kilogram (kg) ile ölçeriz."}],"ans":"Kütle bir maddenin miktarıdır; gram ve kilogram gibi birimlerle ölçülür."}],"zor":[{"q":"Bir tarifte 100 g un, 50 g şeker karışıyor. Aynı oranı koruyarak 300 g un kullanırsak kaç g şeker gerekir?","fig":"<svg viewBox='0 0 320 120'><rect x='50' y='40' width='40' height='50' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>300 g un</text><text x='150' y='70' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><rect x='210' y='55' width='40' height='35' fill='#e0c23a'/><text x='230' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>? g şeker</text></svg>","steps":[{"t":"Oranı bul","a":"un 2 kat şeker","d":"100 g una 50 g şeker düşer; un, şekerin 2 katıdır."},{"t":"Hesapla","a":"150 g","d":"Un 300 g olunca şeker de 3 katına çıkar: 50 × 3 = 150 g şeker gerekir."}],"ans":"Oran korunduğundan 300 g una 150 g şeker gerekir (un, şekerin 2 katı)."},{"q":"3 elmadan 1 bardak elma suyu çıkıyor. 12 elmadan kaç bardak su çıkar ve kaç elma 'fazladan' kalmaz?","steps":[{"t":"Grupla","a":"3'er elma","d":"Her bardak için 3 elma gerekir; elmaları 3'erli gruplarız."},{"t":"Say","a":"4 bardak","d":"12 elma ÷ 3 = 4 grup, yani tam 4 bardak su çıkar, hiç elma artmaz."}],"ans":"Her bardak 3 elma istediğinden 12 ÷ 3 = 4 bardak çıkar; hiç elma artmaz."},{"q":"Bir kola tabağında 2 ölçek kakao, 6 ölçek süt var. Süt 18 ölçek olursa kaç ölçek kakao gerekir?","steps":[{"t":"Oranı bul","a":"süt kakaonun 3 katı","d":"6 ölçek süte 2 ölçek kakao düşer; süt, kakaonun 3 katıdır."},{"t":"Hesapla","a":"6 ölçek","d":"Süt 18 ölçek olunca kakao 18 ÷ 3 = 6 ölçek olur."}],"ans":"Süt kakaonun 3 katı olduğundan 18 ölçek süte 18 ÷ 3 = 6 ölçek kakao gerekir."},{"q":"Su, hidrojen ve oksijenin birleşmesiyle oluşur. 2 g hidrojen 16 g oksijenle birleşirse kaç g su oluşur?","fig":"<svg viewBox='0 0 320 110'><text x='160' y='28' font-size='11' text-anchor='middle' fill='#1a2b45'>2 g + 16 g → su</text><circle cx='70' cy='65' r='10' fill='#cfd8e8' stroke='#1a2b45'/><text x='105' y='70' font-size='14' text-anchor='middle' fill='#1a2b45'>+</text><circle cx='140' cy='65' r='12' fill='#e0552b'/><text x='185' y='70' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><text x='250' y='70' font-size='12' text-anchor='middle' fill='#1a2b45'>18 g su</text></svg>","steps":[{"t":"Topla","a":"2 + 16 gram","d":"Birleşen maddelerin kütleleri toplanır: 2 g hidrojen + 16 g oksijen = 18 g."},{"t":"Sonuç","a":"18 g su","d":"Madde kaybolmadığı için oluşan suyun kütlesi 18 gram olur."}],"ans":"Birleşen kütleler toplandığında 2 + 16 = 18 g su oluşur."},{"q":"Bir manav 4 kg elmayı 5 poşete eşit paylaştırıyor. Aynı oranla 12 kg elma kaç poşet yapar?","steps":[{"t":"Bir oranı bul","a":"4 kg = 5 poşet","d":"4 kg elma 5 poşet ediyorsa, elma 3 katına çıkınca poşet de 3 katına çıkar."},{"t":"Hesapla","a":"15 poşet","d":"12 kg, 4 kg'ın 3 katıdır; 5 × 3 = 15 poşet olur."}],"ans":"Elma 3 katına çıktığından (12 ÷ 4 = 3) poşet de 3 katına çıkar: 5 × 3 = 15 poşet."}]},"ortaokul":{"kolay":[{"q":"Kütleden mol bulmak için hangi işlem yapılır ve mol nedir?","steps":[{"t":"Mol nedir","a":"madde miktarı birimi","d":"Mol, çok sayıda tanecik (atom/molekül) içeren madde miktarı birimidir."},{"t":"İşlem","a":"kütle ÷ molkütlesi","d":"Mol = kütle (g) ÷ molkütlesi (g/mol) bağıntısıyla bulunur."}],"ans":"Mol bir madde miktarı birimidir; mol = kütle ÷ molkütlesi işlemiyle bulunur."},{"q":"32 g oksijen gazı (O₂) kaç moldür? (O=16)","fig":"<svg viewBox='0 0 320 110'><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>mol = kütle ÷ molkütlesi</text><circle cx='130' cy='65' r='14' fill='#e0552b'/><circle cx='165' cy='65' r='14' fill='#e0552b'/><text x='147' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>O₂ = 32 g/mol</text></svg>","steps":[{"t":"Molkütlesi","a":"32 g/mol","d":"O₂ molekülünün molkütlesi 2 × 16 = 32 g/mol'dür."},{"t":"Mol bul","a":"1 mol","d":"Mol = 32 ÷ 32 = 1, yani 32 g oksijen 1 moldür."}],"ans":"O₂ molkütlesi 32 g/mol; 32 ÷ 32 = 1 mol oksijen gazıdır."},{"q":"Stokiyometrik kütle hesabında izlenen genel yol (basamaklar) nedir?","steps":[{"t":"Önce mole çevir","a":"kütle → mol","d":"Verilen kütleyi molkütlesine bölerek mol sayısına çeviririz."},{"t":"Sonra oran ve kütle","a":"mol → mol → kütle","d":"Denklemdeki mol oranıyla aranan maddenin molünü buluruz, sonra molü molkütlesiyle çarparak kütlesini hesaplarız."}],"ans":"Önce kütle mole çevrilir, denklemin mol oranıyla aranan madde molü bulunur, sonra mol kütleye çevrilir."},{"q":"C + O₂ → CO₂ tepkimesinde 1 mol karbon yanarsa kaç mol CO₂ oluşur?","steps":[{"t":"Mol oranı","a":"1 C : 1 CO₂","d":"Denkleme göre 1 mol karbon 1 mol CO₂ verir; oran birebirdir."},{"t":"Sonuç","a":"1 mol CO₂","d":"1 mol karbondan 1 mol CO₂ oluşur."}],"ans":"Mol oranı 1 : 1 olduğundan 1 mol karbon yandığında 1 mol CO₂ oluşur."},{"q":"44 g karbondioksitin (CO₂) mol sayısı kaçtır? (C=12, O=16)","steps":[{"t":"Molkütlesi","a":"44 g/mol","d":"CO₂ molkütlesi 12 + 2 × 16 = 12 + 32 = 44 g/mol'dür."},{"t":"Mol bul","a":"1 mol","d":"Mol = 44 ÷ 44 = 1, yani 44 g CO₂ tam 1 moldür."}],"ans":"CO₂ molkütlesi 44 g/mol; 44 ÷ 44 = 1 mol karbondioksittir."}],"zor":[{"q":"C + O₂ → CO₂ tepkimesinde 24 g karbon tam yanarsa kaç gram CO₂ oluşur? (C=12, O=16)","fig":"<svg viewBox='0 0 320 110'><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>C + O₂ → CO₂</text><rect x='40' y='50' width='50' height='30' fill='#33415588' stroke='#1a2b45'/><text x='65' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>24 g C</text><text x='110' y='70' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><rect x='160' y='50' width='80' height='30' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>? g CO₂</text></svg>","steps":[{"t":"Kütle → mol","a":"2 mol C","d":"Karbonun molkütlesi 12 g/mol; 24 ÷ 12 = 2 mol karbon vardır."},{"t":"Mol oranı","a":"2 mol CO₂","d":"Mol oranı 1 C : 1 CO₂ olduğundan 2 mol karbondan 2 mol CO₂ oluşur."},{"t":"Mol → kütle","a":"88 g","d":"CO₂ molkütlesi 44 g/mol; 2 × 44 = 88 g CO₂ oluşur."}],"ans":"24 g C = 2 mol; 1 : 1 oranla 2 mol CO₂ oluşur ve kütlesi 2 × 44 = 88 gramdır."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde 4 g hidrojen (H₂) tam yanarsa kaç gram su oluşur? (H=1, O=16)","steps":[{"t":"Kütle → mol","a":"2 mol H₂","d":"H₂ molkütlesi 2 g/mol; 4 ÷ 2 = 2 mol hidrojen vardır."},{"t":"Mol oranı","a":"2 mol su","d":"Mol oranı 2 H₂ : 2 H₂O = 1 : 1 olduğundan 2 mol H₂'den 2 mol su oluşur."},{"t":"Mol → kütle","a":"36 g","d":"H₂O molkütlesi 18 g/mol; 2 × 18 = 36 g su oluşur."}],"ans":"4 g H₂ = 2 mol; 2 mol su oluşur ve kütlesi 2 × 18 = 36 gramdır."},{"q":"CaCO₃ → CaO + CO₂ tepkimesinde 100 g CaCO₃ ısıtılırsa kaç gram CaO oluşur? (Ca=40, C=12, O=16)","fig":"<svg viewBox='0 0 320 110'><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>CaCO₃ → CaO + CO₂</text><rect x='40' y='48' width='70' height='32' fill='#cfd8e8' stroke='#1a2b45'/><text x='75' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>100 g</text><text x='128' y='70' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><rect x='160' y='48' width='55' height='32' fill='#cfd8e8' stroke='#1a2b45'/><text x='187' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>? g CaO</text></svg>","steps":[{"t":"Kütle → mol","a":"1 mol CaCO₃","d":"CaCO₃ molkütlesi 40 + 12 + 3 × 16 = 100 g/mol; 100 ÷ 100 = 1 mol vardır."},{"t":"Mol oranı","a":"1 mol CaO","d":"Mol oranı 1 CaCO₃ : 1 CaO olduğundan 1 mol CaO oluşur."},{"t":"Mol → kütle","a":"56 g","d":"CaO molkütlesi 40 + 16 = 56 g/mol; 1 × 56 = 56 g CaO oluşur."}],"ans":"100 g CaCO₃ = 1 mol; 1 mol CaO oluşur ve kütlesi 1 × 56 = 56 gramdır."},{"q":"2Na + Cl₂ → 2NaCl tepkimesinde 46 g sodyum tam tepkirse kaç gram NaCl oluşur? (Na=23, Cl=35,5)","steps":[{"t":"Kütle → mol","a":"2 mol Na","d":"Sodyumun molkütlesi 23 g/mol; 46 ÷ 23 = 2 mol sodyum vardır."},{"t":"Mol oranı","a":"2 mol NaCl","d":"Mol oranı 2 Na : 2 NaCl = 1 : 1 olduğundan 2 mol NaCl oluşur."},{"t":"Mol → kütle","a":"117 g","d":"NaCl molkütlesi 23 + 35,5 = 58,5 g/mol; 2 × 58,5 = 117 g NaCl oluşur."}],"ans":"46 g Na = 2 mol; 2 mol NaCl oluşur ve kütlesi 2 × 58,5 = 117 gramdır."},{"q":"CH₄ + 2O₂ → CO₂ + 2H₂O tepkimesinde 8 g metan (CH₄) tam yanarsa kaç gram CO₂ oluşur? (C=12, H=1, O=16)","steps":[{"t":"Kütle → mol","a":"0,5 mol CH₄","d":"CH₄ molkütlesi 12 + 4 = 16 g/mol; 8 ÷ 16 = 0,5 mol metan vardır."},{"t":"Mol oranı","a":"0,5 mol CO₂","d":"Mol oranı 1 CH₄ : 1 CO₂ olduğundan 0,5 mol CO₂ oluşur."},{"t":"Mol → kütle","a":"22 g","d":"CO₂ molkütlesi 44 g/mol; 0,5 × 44 = 22 g CO₂ oluşur."}],"ans":"8 g CH₄ = 0,5 mol; 0,5 mol CO₂ oluşur ve kütlesi 0,5 × 44 = 22 gramdır."}]},"lise":{"kolay":[{"q":"Stokiyometrik kütle hesabının dört temel basamağını (kütle→mol→mol oranı→kütle) açıklayınız.","steps":[{"t":"Kütleyi mole çevir","a":"mol = kütle/MA","d":"Verilen maddenin kütlesi molkütlesine bölünerek mol sayısı bulunur."},{"t":"Oranla aranan molü bul","a":"denklem katsayıları","d":"Denk tepkimenin katsayı (mol) oranı kullanılarak aranan maddenin mol sayısı hesaplanır."},{"t":"Molü kütleye çevir","a":"kütle = mol×MA","d":"Aranan maddenin mol sayısı kendi molkütlesiyle çarpılarak kütlesi bulunur."}],"ans":"Önce verilen kütle mole çevrilir, denklemin mol oranıyla aranan madde molü bulunur, son olarak bu mol kendi molkütlesiyle çarpılarak kütleye dönüştürülür."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde 8 g hidrojen (H₂) tam yanarsa kaç gram su oluşur? (H=1, O=16)","fig":"<svg viewBox='0 0 320 110'><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>2H₂ + O₂ → 2H₂O</text><rect x='40' y='50' width='55' height='30' fill='#cfd8e8' stroke='#1a2b45'/><text x='67' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>8 g H₂</text><text x='115' y='70' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><rect x='165' y='50' width='80' height='30' fill='#2b6be0'/><text x='205' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>? g su</text></svg>","steps":[{"t":"Kütle → mol","a":"4 mol H₂","d":"H₂ molkütlesi 2 g/mol; 8 ÷ 2 = 4 mol hidrojen bulunur."},{"t":"Mol oranı","a":"4 mol su","d":"Mol oranı 2 H₂ : 2 H₂O = 1 : 1 olduğundan 4 mol H₂'den 4 mol su oluşur."},{"t":"Mol → kütle","a":"72 g","d":"H₂O molkütlesi 18 g/mol; 4 × 18 = 72 g su oluşur."}],"ans":"8 g H₂ = 4 mol; 1 : 1 oranla 4 mol su oluşur ve kütlesi 4 × 18 = 72 gramdır."},{"q":"Bir maddenin molkütlesi nasıl hesaplanır ve neden stokiyometrik kütle hesabının temelidir?","steps":[{"t":"Molkütlesi","a":"atom kütleleri toplamı","d":"Molkütlesi, formüldeki tüm atomların atom kütlelerinin (katsayılarıyla) toplamıdır; örneğin H₂O için 2 × 1 + 16 = 18 g/mol."},{"t":"Önemi","a":"kütle-mol köprüsü","d":"Stokiyometri mol oranıyla yürür; molkütlesi, tartılabilen kütle ile hesapta kullanılan mol arasındaki dönüşümü sağladığı için zorunlu köprüdür."}],"ans":"Molkütlesi formüldeki atom kütlelerinin toplamıdır; kütle ile mol arasındaki dönüşümü sağladığından stokiyometrik hesabın temelini oluşturur."},{"q":"N₂ + 3H₂ ⇌ 2NH₃ tepkimesinde 28 g azot (N₂) tam tepkirse en çok kaç gram NH₃ oluşur? (N=14, H=1)","steps":[{"t":"Kütle → mol","a":"1 mol N₂","d":"N₂ molkütlesi 28 g/mol; 28 ÷ 28 = 1 mol azot bulunur."},{"t":"Mol oranı","a":"2 mol NH₃","d":"Mol oranı 1 N₂ : 2 NH₃ olduğundan 1 mol azottan 2 mol amonyak oluşur."},{"t":"Mol → kütle","a":"34 g","d":"NH₃ molkütlesi 14 + 3 = 17 g/mol; 2 × 17 = 34 g NH₃ oluşur."}],"ans":"28 g N₂ = 1 mol; 1 : 2 oranla 2 mol NH₃ oluşur ve kütlesi 2 × 17 = 34 gramdır."},{"q":"CaCO₃ → CaO + CO₂ tepkimesinde 50 g CaCO₃ bozunursa kaç gram CO₂ açığa çıkar? (Ca=40, C=12, O=16)","steps":[{"t":"Kütle → mol","a":"0,5 mol CaCO₃","d":"CaCO₃ molkütlesi 40 + 12 + 48 = 100 g/mol; 50 ÷ 100 = 0,5 mol bulunur."},{"t":"Mol oranı","a":"0,5 mol CO₂","d":"Mol oranı 1 CaCO₃ : 1 CO₂ olduğundan 0,5 mol CO₂ açığa çıkar."},{"t":"Mol → kütle","a":"22 g","d":"CO₂ molkütlesi 44 g/mol; 0,5 × 44 = 22 g CO₂ açığa çıkar."}],"ans":"50 g CaCO₃ = 0,5 mol; 0,5 mol CO₂ açığa çıkar ve kütlesi 0,5 × 44 = 22 gramdır."}],"zor":[{"q":"CH₄ + 2O₂ → CO₂ + 2H₂O tepkimesinde 32 g metan (CH₄) tam yanarsa oluşan suyun kütlesini bulunuz. (C=12, H=1, O=16)","fig":"<svg viewBox='0 0 320 110'><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>CH₄ + 2O₂ → CO₂ + 2H₂O</text><rect x='40' y='50' width='55' height='30' fill='#33415588' stroke='#1a2b45'/><text x='67' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>32 g CH₄</text><text x='118' y='70' font-size='14' text-anchor='middle' fill='#1a2b45'>→</text><rect x='170' y='50' width='80' height='30' fill='#2b6be0'/><text x='210' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>? g su</text></svg>","steps":[{"t":"Kütle → mol","a":"2 mol CH₄","d":"CH₄ molkütlesi 16 g/mol; 32 ÷ 16 = 2 mol metan bulunur."},{"t":"Mol oranı","a":"4 mol su","d":"Mol oranı 1 CH₄ : 2 H₂O olduğundan 2 mol metanden 2 × 2 = 4 mol su oluşur."},{"t":"Mol → kütle","a":"72 g","d":"H₂O molkütlesi 18 g/mol; 4 × 18 = 72 g su oluşur."}],"ans":"32 g CH₄ = 2 mol; 1 : 2 oranla 4 mol su oluşur ve kütlesi 4 × 18 = 72 gramdır."},{"q":"2Na + Cl₂ → 2NaCl tepkimesinde 117 g NaCl elde etmek için kaç gram sodyum gerekir? (Na=23, Cl=35,5)","steps":[{"t":"Kütle → mol","a":"2 mol NaCl","d":"NaCl molkütlesi 23 + 35,5 = 58,5 g/mol; 117 ÷ 58,5 = 2 mol NaCl bulunur."},{"t":"Mol oranı","a":"2 mol Na","d":"Mol oranı 2 Na : 2 NaCl = 1 : 1 olduğundan 2 mol NaCl için 2 mol sodyum gerekir."},{"t":"Mol → kütle","a":"46 g","d":"Sodyumun molkütlesi 23 g/mol; 2 × 23 = 46 g sodyum gerekir."}],"ans":"117 g NaCl = 2 mol; 1 : 1 oranla 2 mol sodyum, yani 2 × 23 = 46 g sodyum gerekir."},{"q":"C + O₂ → CO₂ tepkimesinde tam yanma sonucu 132 g CO₂ elde edildiğine göre kaç gram karbon yakılmıştır? (C=12, O=16)","steps":[{"t":"Kütle → mol","a":"3 mol CO₂","d":"CO₂ molkütlesi 44 g/mol; 132 ÷ 44 = 3 mol CO₂ bulunur."},{"t":"Mol oranı","a":"3 mol C","d":"Mol oranı 1 C : 1 CO₂ olduğundan 3 mol CO₂ için 3 mol karbon gerekir."},{"t":"Mol → kütle","a":"36 g","d":"Karbonun molkütlesi 12 g/mol; 3 × 12 = 36 g karbon yakılmıştır."}],"ans":"132 g CO₂ = 3 mol; 1 : 1 oranla 3 mol karbon, yani 3 × 12 = 36 g karbon yakılmıştır."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde 36 g su oluşturmak için kaç gram oksijen (O₂) gerekir? (H=1, O=16)","steps":[{"t":"Kütle → mol","a":"2 mol su","d":"H₂O molkütlesi 18 g/mol; 36 ÷ 18 = 2 mol su bulunur."},{"t":"Mol oranı","a":"1 mol O₂","d":"Mol oranı 2 H₂O : 1 O₂ olduğundan 2 mol su için 1 mol oksijen gerekir."},{"t":"Mol → kütle","a":"32 g","d":"O₂ molkütlesi 32 g/mol; 1 × 32 = 32 g oksijen gerekir."}],"ans":"36 g su = 2 mol; 2 : 1 oranla 1 mol O₂, yani 1 × 32 = 32 g oksijen gerekir."},{"q":"CaCO₃ → CaO + CO₂ tepkimesinde 11,2 g CaO elde etmek için kaç gram CaCO₃ ısıtılmalıdır? (Ca=40, C=12, O=16)","steps":[{"t":"Kütle → mol","a":"0,2 mol CaO","d":"CaO molkütlesi 40 + 16 = 56 g/mol; 11,2 ÷ 56 = 0,2 mol CaO bulunur."},{"t":"Mol oranı","a":"0,2 mol CaCO₃","d":"Mol oranı 1 CaCO₃ : 1 CaO olduğundan 0,2 mol CaO için 0,2 mol CaCO₃ gerekir."},{"t":"Mol → kütle","a":"20 g","d":"CaCO₃ molkütlesi 100 g/mol; 0,2 × 100 = 20 g CaCO₃ ısıtılmalıdır."}],"ans":"11,2 g CaO = 0,2 mol; 1 : 1 oranla 0,2 mol CaCO₃, yani 0,2 × 100 = 20 g CaCO₃ ısıtılmalıdır."}]}},"kutleTartisi":{"ilkokul":{"kolay":[{"q":"Bir maddenin 1 molünün gram cinsinden kütlesine ne ad verilir?","steps":[{"t":"1 mol","a":"belli miktar madde","d":"1 mol, belli sayıda tanecik içeren madde miktarıdır."},{"t":"Kütlesi","a":"molar kütle","d":"Bu 1 molün gram olarak kütlesine <b>molar kütle</b> denir."}],"ans":"1 molün gram cinsinden kütlesine <b>molar kütle</b> denir (birimi g/mol)."},{"q":"Bir maddeyi terazide neyle ölçeriz: tane sayısı mı, kütle mi?","steps":[{"t":"Terazi","a":"kütle ölçer","d":"Terazi bize maddenin kütlesini, yani gram olarak ağırlığını söyler."},{"t":"Sonuç","a":"kütle","d":"Atomları tek tek sayamadığımız için maddeyi gram olarak tartarız."}],"ans":"Maddeyi terazide <b>kütle</b> (gram) olarak ölçeriz, tane tane saymayız."},{"q":"1 mol su (H₂O) kaç gram gelir?","steps":[{"t":"Bilgi","a":"verilen değer","d":"1 mol suyun kütlesi bize 18 gram olarak verilir."},{"t":"Sonuç","a":"18 gram","d":"Yani 1 mol su tartıldığında terazi 18 gram gösterir."}],"ans":"1 mol su <b>18 gram</b> gelir."},{"q":"İki farklı maddenin 1 molü aynı gram mı gelir?","steps":[{"t":"Tanecik sayısı","a":"aynı","d":"Birer mollerinde aynı sayıda tanecik vardır."},{"t":"Kütle","a":"farklı olabilir","d":"Ama tanecikler farklı ağırlıkta olduğundan kütleleri farklı olur."}],"ans":"Hayır; aynı sayıda tanecik içerseler de 1 molleri genelde <b>farklı gram</b> gelir."},{"q":"Tuz (NaCl) ile su (H₂O) gibi maddelerin molar kütleleri farklı mıdır?","steps":[{"t":"Farklı maddeler","a":"farklı tanecik","d":"Tuz ve su farklı atomlardan oluşur."},{"t":"Kütle","a":"farklı g/mol","d":"Bu yüzden 1 mollerinin kütleleri (molar kütleleri) birbirinden farklıdır."}],"ans":"Evet; farklı maddeler oldukları için molar kütleleri (1 mollerinin gramı) <b>farklıdır</b>."}],"zor":[{"q":"1 mol su 18 gram ise 2 mol su kaç gram gelir?","steps":[{"t":"1 mol","a":"18 gram","d":"1 mol suyun kütlesi 18 gramdır."},{"t":"2 mol","a":"2 × 18","d":"2 mol için 2 × 18 = 36 gram buluruz."}],"ans":"2 mol su <b>36 gram</b> gelir."},{"q":"1 mol karbondioksit (CO₂) 44 gram ise yarım mol kaç gram gelir?","steps":[{"t":"1 mol","a":"44 gram","d":"1 mol CO₂ 44 gramdır."},{"t":"Yarısı","a":"44 ÷ 2","d":"0,5 mol için kütlenin yarısını alırız: 44 ÷ 2 = 22 gram."}],"ans":"0,5 mol CO₂ <b>22 gram</b> gelir."},{"q":"Neden atomları tek tek saymak yerine maddeyi tartarız?","steps":[{"t":"Saymak imkânsız","a":"çok küçük","d":"Atomlar gözle görülemeyecek kadar küçük ve çok sayıda olduğu için tek tek sayılamaz."},{"t":"Tartmak kolay","a":"terazi","d":"Onun yerine maddeyi terazide tartarız; kütlesinden mol sayısını bulabiliriz."}],"ans":"Atomlar sayılamayacak kadar küçük olduğu için onları saymak yerine maddeyi <b>tartarız</b>."},{"q":"36 gram su kaç mol eder (1 mol su = 18 gram)?","steps":[{"t":"1 mol","a":"18 gram","d":"1 mol su 18 gramdır."},{"t":"Bölme","a":"36 ÷ 18","d":"36 gramı 18'e böleriz ve 2 buluruz."}],"ans":"36 gram su <b>2 mol</b> eder."},{"q":"1 mol su 18 g, 1 mol CO₂ 44 g ise hangisinin 1 molü daha ağırdır?","steps":[{"t":"Su","a":"18 gram","d":"1 mol suyun kütlesi 18 gramdır."},{"t":"Karşılaştırma","a":"CO₂ ağır","d":"1 mol CO₂ 44 gramdır; 44 > 18 olduğundan CO₂'nin 1 molü daha ağırdır."}],"ans":"1 mol <b>CO₂ (44 g)</b>, 1 mol sudan (18 g) daha ağırdır."}]},"ortaokul":{"kolay":[{"q":"Molar kütle nedir ve birimi nedir?","steps":[{"t":"Tanım","a":"1 molün kütlesi","d":"Molar kütle, bir maddenin 1 molünün gram cinsinden kütlesidir."},{"t":"Birim","a":"g/mol","d":"Birimi gram bölü mol (g/mol) şeklinde yazılır."}],"ans":"Molar kütle, 1 molün gram cinsinden kütlesidir; birimi <b>g/mol</b>'dür."},{"q":"Suyun (H₂O) molar kütlesi formülden nasıl bulunur (H=1, O=16)?","steps":[{"t":"Atomlar","a":"2 H + 1 O","d":"H₂O'da 2 hidrojen ve 1 oksijen atomu vardır."},{"t":"Toplam","a":"2·1 + 16","d":"Atom kütlelerini toplarız: 2×1 + 16 = 18 g/mol."}],"ans":"Suyun molar kütlesi <b>18 g/mol</b>'dür (2×1 + 16)."},{"q":"Mol sayısı (n) kütleden (m) nasıl hesaplanır?","steps":[{"t":"Bağıntı","a":"n = m / M","d":"Mol sayısı, kütlenin molar kütleye bölünmesiyle bulunur."},{"t":"Anlam","a":"gram → mol","d":"Burada m gram cinsinden kütle, M ise g/mol cinsinden molar kütledir."}],"ans":"Mol sayısı <b>n = m / M</b> bağıntısıyla hesaplanır."},{"q":"CO₂'nin molar kütlesi kaçtır (C=12, O=16)?","steps":[{"t":"Atomlar","a":"1 C + 2 O","d":"CO₂'de 1 karbon ve 2 oksijen atomu vardır."},{"t":"Toplam","a":"12 + 2·16","d":"12 + 2×16 = 12 + 32 = 44 g/mol."}],"ans":"CO₂'nin molar kütlesi <b>44 g/mol</b>'dür."},{"q":"Yemek tuzunun (NaCl) molar kütlesi kaçtır (Na=23, Cl=35,5)?","steps":[{"t":"Atomlar","a":"1 Na + 1 Cl","d":"NaCl'de 1 sodyum ve 1 klor atomu vardır."},{"t":"Toplam","a":"23 + 35,5","d":"23 + 35,5 = 58,5 g/mol."}],"ans":"NaCl'nin molar kütlesi <b>58,5 g/mol</b>'dür."}],"zor":[{"q":"36 gram su (H₂O, M=18 g/mol) kaç moldür?","steps":[{"t":"Bağıntı","a":"n = m / M","d":"Mol sayısı = kütle / molar kütle."},{"t":"İşlem","a":"36 ÷ 18","d":"36 gramı 18 g/mol'e böleriz: 2 mol."}],"ans":"36 gram su <b>2 mol</b> eder."},{"q":"3 mol CO₂'nin (M=44 g/mol) kütlesi kaç gramdır?","steps":[{"t":"Bağıntı","a":"m = n × M","d":"Kütle = mol sayısı × molar kütle."},{"t":"İşlem","a":"3 × 44","d":"3 × 44 = 132 gram."}],"ans":"3 mol CO₂'nin kütlesi <b>132 gram</b>'dır."},{"q":"117 gram yemek tuzu (NaCl, M=58,5 g/mol) kaç moldür?","steps":[{"t":"Bağıntı","a":"n = m / M","d":"Mol sayısı = kütle / molar kütle."},{"t":"İşlem","a":"117 ÷ 58,5","d":"117 gramı 58,5 g/mol'e böleriz: 2 mol."}],"ans":"117 gram NaCl <b>2 mol</b> eder."},{"q":"Amonyağın (NH₃) molar kütlesi kaçtır (N=14, H=1)?","steps":[{"t":"Atomlar","a":"1 N + 3 H","d":"NH₃'te 1 azot ve 3 hidrojen atomu vardır."},{"t":"Toplam","a":"14 + 3·1","d":"14 + 3×1 = 14 + 3 = 17 g/mol."}],"ans":"NH₃'ün molar kütlesi <b>17 g/mol</b>'dür."},{"q":"0,5 mol oksijen gazının (O₂, O=16) kütlesi kaç gramdır?","steps":[{"t":"Molar kütle","a":"O₂ = 32 g/mol","d":"O₂'de 2 oksijen atomu vardır: 2×16 = 32 g/mol."},{"t":"Kütle","a":"m = n × M","d":"m = 0,5 × 32 = 16 gram."}],"ans":"0,5 mol O₂'nin kütlesi <b>16 gram</b>'dır."}]},"lise":{"kolay":[{"q":"Molar kütle kavramı, atom/molekül kütlesi ile gram dünyası arasında nasıl bir bağ kurar?","steps":[{"t":"Bağıl kütle","a":"akb cinsinden","d":"Bir molekülün kütlesi atomik kütle birimi cinsinden, atom kütlelerinin toplamıdır (örneğin H₂O = 18 akb)."},{"t":"Molar kütle","a":"aynı sayı, g/mol","d":"Bu bağıl kütle sayısı, 1 mol için gram cinsinden molar kütleye eşittir; H₂O için 18 g/mol."}],"ans":"Molar kütle, bir taneciğin bağıl kütlesini (akb) aynı sayısal değerle <b>g/mol</b> cinsinden 1 molün kütlesine bağlar."},{"q":"Glikozun (C₆H₁₂O₆) molar kütlesi nasıl hesaplanır (C=12, H=1, O=16)?","steps":[{"t":"Atom katkıları","a":"6C + 12H + 6O","d":"6 karbon, 12 hidrojen ve 6 oksijen atomunun kütleleri toplanır."},{"t":"Toplam","a":"6·12 + 12·1 + 6·16","d":"72 + 12 + 96 = 180 g/mol."}],"ans":"Glikozun (C₆H₁₂O₆) molar kütlesi <b>180 g/mol</b>'dür."},{"q":"Kütle, mol ve molar kütle arasındaki dönüşüm bağıntıları nelerdir?","steps":[{"t":"Mole çevirme","a":"n = m / M","d":"Mol sayısı, kütlenin molar kütleye bölünmesiyle bulunur."},{"t":"Kütleye çevirme","a":"m = n × M","d":"Kütle ise mol sayısı ile molar kütlenin çarpımıdır."}],"ans":"Dönüşümler <b>n = m / M</b> ve <b>m = n × M</b> bağıntılarıyla yapılır."},{"q":"88 gram CO₂ (M=44 g/mol) kaç mol ve kaç tane molekül içerir (N_A=6,02·10²³)?","steps":[{"t":"Mol sayısı","a":"n = m / M","d":"n = 88 / 44 = 2 mol."},{"t":"Molekül sayısı","a":"N = n × N_A","d":"N = 2 × 6,02·10²³ = 1,204·10²⁴ tane molekül."}],"ans":"88 gram CO₂ = <b>2 mol</b> ve <b>1,204·10²⁴</b> tane molekül içerir."},{"q":"Sülfürik asidin (H₂SO₄) molar kütlesi kaçtır (H=1, S=32, O=16)?","steps":[{"t":"Atom katkıları","a":"2H + 1S + 4O","d":"2 hidrojen, 1 kükürt ve 4 oksijen atomu vardır."},{"t":"Toplam","a":"2·1 + 32 + 4·16","d":"2 + 32 + 64 = 98 g/mol."}],"ans":"H₂SO₄'ün molar kütlesi <b>98 g/mol</b>'dür."}],"zor":[{"q":"45 gram glikozun (C₆H₁₂O₆, M=180 g/mol) içerdiği mol sayısı ve molekül sayısı nedir?","steps":[{"t":"Mol sayısı","a":"n = m / M","d":"n = 45 / 180 = 0,25 mol."},{"t":"Molekül sayısı","a":"N = n × N_A","d":"N = 0,25 × 6,02·10²³ = 1,505·10²³ tane molekül."}],"ans":"45 gram glikoz = <b>0,25 mol</b> ve <b>1,505·10²³</b> tane molekül içerir."},{"q":"54 gram suda (H₂O, M=18 g/mol) toplam kaç tane hidrojen atomu bulunur?","steps":[{"t":"Mol sayısı","a":"n = 54 / 18","d":"54 gram su = 3 mol H₂O."},{"t":"H atomu sayısı","a":"3 × 2 × N_A","d":"Her molekülde 2 H atomu olduğundan: 3 mol × 2 × 6,02·10²³ = 3,612·10²⁴ tane H atomu."}],"ans":"54 gram suda <b>3,612·10²⁴</b> tane hidrojen atomu bulunur."},{"q":"Bir bileşiğin 0,5 molünün kütlesi 49 gram ise molar kütlesi kaçtır ve hangi bileşik olabilir?","steps":[{"t":"Molar kütle","a":"M = m / n","d":"M = 49 / 0,5 = 98 g/mol."},{"t":"Bileşik","a":"H₂SO₄","d":"98 g/mol, sülfürik asit (H₂SO₄) molar kütlesine uyar (2+32+64=98)."}],"ans":"Molar kütle <b>98 g/mol</b>'dür; bu, <b>H₂SO₄</b> (sülfürik asit) ile uyumludur."},{"q":"100 gram kalsiyum karbonatta (CaCO₃, Ca=40, C=12, O=16) kaç mol bileşik vardır?","steps":[{"t":"Molar kütle","a":"40+12+3·16","d":"CaCO₃ = 40 + 12 + 48 = 100 g/mol."},{"t":"Mol sayısı","a":"n = m / M","d":"n = 100 / 100 = 1 mol."}],"ans":"100 gram CaCO₃ <b>1 mol</b> bileşik içerir (M = 100 g/mol)."},{"q":"23 gram sodyum (Na, M=23 g/mol) ile 24 gram magnezyum (Mg, M=24 g/mol) örneklerinden hangisi daha çok atom içerir?","steps":[{"t":"Na molü","a":"23/23 = 1 mol","d":"23 gram sodyum 1 mol Na, yani 6,02·10²³ atom içerir."},{"t":"Mg molü","a":"24/24 = 1 mol","d":"24 gram magnezyum da 1 mol Mg, yani 6,02·10²³ atom içerir; ikisi eşittir."}],"ans":"İkisi de <b>1'er mol</b> (6,02·10²³ atom) içerdiğinden atom sayıları <b>eşittir</b>."}]}},"molarHacim":{"ilkokul":{"kolay":[{"q":"Gazlar şişirildiğinde balon büyür. Gazın kapladığı yere ne ad verilir?","steps":[{"t":"Gaz yayılır","a":"her yeri doldurur","d":"Gaz tanecikleri serbestçe hareket eder ve bulunduğu kabı doldurur."},{"t":"Kapladığı yer","a":"hacim","d":"Bir gazın kapladığı yere hacim denir; litre (L) ile ölçülür."}],"ans":"Gazın kapladığı yere hacim denir; litre (L) ile ölçülür."},{"q":"Aynı koşullarda eşit büyüklükteki iki balonun içindeki gaz miktarı (mol) nasıldır?","steps":[{"t":"Eşit hacim","a":"aynı büyüklük","d":"İki balon aynı koşulda ve eşit büyüklükte ise hacimleri eşittir."},{"t":"Gaz miktarı","a":"eşit","d":"Eşit hacimdeki gazlar aynı sayıda tanecik içerir, yani mol miktarları eşittir."}],"ans":"Aynı koşulda eşit hacimdeki gazların mol miktarları eşittir."},{"q":"Bir mol gazın normal koşullarda kapladığı hacim kaç litredir?","fig":"<svg viewBox='0 0 320 150'><rect x='115' y='35' width='90' height='85' rx='8' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='140' cy='60' r='4' fill='#2b6be0'/><circle cx='175' cy='75' r='4' fill='#2b6be0'/><circle cx='155' cy='100' r='4' fill='#2b6be0'/><circle cx='185' cy='55' r='4' fill='#2b6be0'/><text x='160' y='28' font-size='10' text-anchor='middle' fill='#1a2b45'>1 mol gaz (NK)</text><text x='160' y='140' font-size='12' text-anchor='middle' fill='#e0552b'>22,4 L</text></svg>","steps":[{"t":"Normal koşul","a":"0 °C, 1 atm","d":"Normal koşul (NK) belli bir sıcaklık ve basınç demektir."},{"t":"Hacim","a":"22,4 L","d":"Bu koşulda 1 mol gaz 22,4 litre yer kaplar."}],"ans":"Normal koşulda 1 mol gaz 22,4 litre hacim kaplar."},{"q":"Soğuk havada balon biraz söner, sıcak havada şişer. Bu, gazın hacminin koşullara bağlı olduğunu mu gösterir?","steps":[{"t":"Sıcaklık etkisi","a":"hacmi değiştirir","d":"Isınan gaz genleşir, soğuyan gaz büzülür."},{"t":"Sonuç","a":"koşula bağlı","d":"Demek ki bir gazın hacmi sıcaklık ve basınç gibi koşullara bağlıdır."}],"ans":"Evet; gazın hacmi sıcaklık ve basınç gibi koşullara bağlı olarak değişir."},{"q":"Kütle gram ile ölçülür. Gazların miktarını ise hangi büyüklükle (litre olarak) ölçeriz?","steps":[{"t":"Katı/sıvı","a":"gram","d":"Genelde maddeleri tartarak gram cinsinden ölçeriz."},{"t":"Gaz","a":"hacim (litre)","d":"Gazlar için çoğunlukla kapladıkları hacmi litre cinsinden ölçeriz."}],"ans":"Gazların miktarını çoğunlukla kapladıkları hacimle, yani litre (L) ile ölçeriz."}],"zor":[{"q":"Normal koşulda 1 mol gaz 22,4 L ise, 2 mol gaz kaç litre yer kaplar?","steps":[{"t":"Bir mol hacmi","a":"22,4 L","d":"1 mol gaz 22,4 litredir."},{"t":"İki ile çarp","a":"2 × 22,4","d":"2 mol için 22,4'ü ikiyle çarparız: 2 × 22,4 = 44,8 L."}],"ans":"Normal koşulda 2 mol gaz 44,8 litre yer kaplar."},{"q":"Normal koşulda 1 mol gaz 22,4 L ise, yarım (0,5) mol gaz kaç litredir?","steps":[{"t":"Bir mol","a":"22,4 L","d":"1 mol gaz 22,4 litredir."},{"t":"Yarısını al","a":"22,4 ÷ 2","d":"Yarım mol için 22,4'ü ikiye böleriz: 22,4 ÷ 2 = 11,2 L."}],"ans":"Normal koşulda 0,5 mol gaz 11,2 litredir."},{"q":"Normal koşulda 44,8 litre gaz kaç moldür? (1 mol = 22,4 L)","fig":"<svg viewBox='0 0 320 150'><text x='80' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>44,8 L</text><text x='150' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>÷ 22,4</text><text x='210' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='270' y='80' font-size='13' text-anchor='middle' fill='#e0552b'>2 mol</text></svg>","steps":[{"t":"Bir mol hacmi","a":"22,4 L","d":"1 mol gaz 22,4 litredir."},{"t":"Böl","a":"44,8 ÷ 22,4","d":"Hacmi 22,4'e böleriz: 44,8 ÷ 22,4 = 2 mol."}],"ans":"Normal koşulda 44,8 litre gaz 2 moldür."},{"q":"İki ayrı balonda aynı koşulda 1'er mol gaz var. Birinde oksijen, diğerinde azot var. Hacimleri nasıldır?","steps":[{"t":"Eşit mol","a":"1'er mol","d":"Her iki balonda da 1'er mol gaz var."},{"t":"Eşit hacim","a":"22,4 L","d":"Aynı koşulda eşit mol gazlar eşit hacim kaplar; ikisi de 22,4 litredir."}],"ans":"Gazların türü farklı olsa da, eşit mol gazlar aynı koşulda eşit (22,4 L) hacim kaplar."},{"q":"Normal koşulda 11,2 litre gaz kaç moldür? (1 mol = 22,4 L)","steps":[{"t":"Bir mol hacmi","a":"22,4 L","d":"1 mol gaz 22,4 litredir."},{"t":"Böl","a":"11,2 ÷ 22,4","d":"Hacmi 22,4'e böleriz: 11,2 ÷ 22,4 = 0,5 mol."}],"ans":"Normal koşulda 11,2 litre gaz 0,5 moldür."}]},"ortaokul":{"kolay":[{"q":"Molar hacim nedir?","steps":[{"t":"Tanım","a":"1 molün hacmi","d":"Molar hacim, bir gazın 1 molünün belirli koşulda kapladığı hacimdir."},{"t":"Normal koşul değeri","a":"22,4 L/mol","d":"Normal koşulda (0 °C, 1 atm) bu hacim 22,4 litredir."}],"ans":"Molar hacim, 1 mol gazın hacmidir; normal koşulda 22,4 L/mol'dür."},{"q":"Mol ile gaz hacmi arasındaki bağıntı (normal koşul) nasıldır?","steps":[{"t":"Bağıntı","a":"n = V / 22,4","d":"Mol sayısı, hacmin 22,4'e bölümüne eşittir."},{"t":"Tersi","a":"V = n × 22,4","d":"Hacim ise mol sayısının 22,4 ile çarpımıdır."}],"ans":"Normal koşulda n = V / 22,4 ve V = n × 22,4 bağıntıları geçerlidir."},{"q":"Normal koşulda 3 mol gaz kaç litre yer kaplar?","steps":[{"t":"Bağıntı","a":"V = n × 22,4","d":"Hacim = mol × 22,4 bağıntısını kullanırız."},{"t":"Hesapla","a":"3 × 22,4","d":"V = 3 × 22,4 = 67,2 L bulunur."}],"ans":"Normal koşulda 3 mol gaz 67,2 litre yer kaplar."},{"q":"Normal koşulda 5,6 litre gaz kaç moldür?","fig":"<svg viewBox='0 0 320 150'><rect x='110' y='40' width='100' height='80' rx='8' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>5,6 L gaz</text><text x='160' y='85' font-size='11' text-anchor='middle' fill='#1a2b45'>n = 5,6 ÷ 22,4</text><text x='160' y='140' font-size='12' text-anchor='middle' fill='#e0552b'>n = 0,25 mol</text></svg>","steps":[{"t":"Bağıntı","a":"n = V / 22,4","d":"Mol = hacim ÷ 22,4 bağıntısını kullanırız."},{"t":"Hesapla","a":"5,6 ÷ 22,4","d":"n = 5,6 ÷ 22,4 = 0,25 mol bulunur."}],"ans":"Normal koşulda 5,6 litre gaz 0,25 moldür."},{"q":"Avogadro hipotezi neyi söyler?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='40' width='80' height='80' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><rect x='200' y='40' width='80' height='80' rx='6' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='60' cy='60' r='4' fill='#2b6be0'/><circle cx='95' cy='80' r='4' fill='#2b6be0'/><circle cx='70' cy='105' r='4' fill='#2b6be0'/><circle cx='220' cy='60' r='4' fill='#e0552b'/><circle cx='255' cy='80' r='4' fill='#e0552b'/><circle cx='230' cy='105' r='4' fill='#e0552b'/><text x='80' y='135' font-size='9' text-anchor='middle' fill='#1a2b45'>eşit hacim</text><text x='240' y='135' font-size='9' text-anchor='middle' fill='#1a2b45'>eşit hacim</text><text x='160' y='85' font-size='11' text-anchor='middle' fill='#1a2b45'>= eşit mol</text></svg>","steps":[{"t":"Eşit hacim","a":"aynı koşul","d":"Aynı sıcaklık ve basınçta eşit hacimli gazlar ele alınır."},{"t":"Eşit tanecik","a":"eşit mol","d":"Bu gazlar eşit sayıda tanecik (eşit mol) içerir; türü önemli değildir."}],"ans":"Avogadro hipotezi: aynı koşulda eşit hacimli gazlar eşit sayıda tanecik (eşit mol) içerir."}],"zor":[{"q":"Normal koşulda 2,5 mol gaz kaç litre yer kaplar?","steps":[{"t":"Bağıntı","a":"V = n × 22,4","d":"Hacim = mol × 22,4 bağıntısını kullanırız."},{"t":"Hesapla","a":"2,5 × 22,4","d":"V = 2,5 × 22,4 = 56 L bulunur."}],"ans":"Normal koşulda 2,5 mol gaz 56 litre yer kaplar."},{"q":"Normal koşulda 89,6 litre gaz kaç moldür?","steps":[{"t":"Bağıntı","a":"n = V / 22,4","d":"Mol = hacim ÷ 22,4 bağıntısını kullanırız."},{"t":"Hesapla","a":"89,6 ÷ 22,4","d":"n = 89,6 ÷ 22,4 = 4 mol bulunur."}],"ans":"Normal koşulda 89,6 litre gaz 4 moldür."},{"q":"Normal koşulda 33,6 litre oksijen gazı (O₂) kaç moldür?","steps":[{"t":"Bağıntı","a":"n = V / 22,4","d":"Gazın türünden bağımsız olarak n = V / 22,4 kullanılır."},{"t":"Hesapla","a":"33,6 ÷ 22,4","d":"n = 33,6 ÷ 22,4 = 1,5 mol bulunur."}],"ans":"Normal koşulda 33,6 litre O₂ gazı 1,5 moldür."},{"q":"Aynı koşulda eşit hacimli iki kapta CO₂ ve CH₄ gazları var. Mol sayıları neden eşittir?","steps":[{"t":"Avogadro hipotezi","a":"eşit hacim → eşit mol","d":"Aynı koşulda eşit hacimli gazlar eşit sayıda tanecik içerir."},{"t":"Tür önemsiz","a":"mol eşit","d":"Gazın türü (CO₂ veya CH₄) hacim için belirleyici değildir; mol sayıları eşittir."}],"ans":"Avogadro hipotezine göre aynı koşulda eşit hacimli gazlar eşit mol içerir; bu yüzden mol sayıları eşittir."},{"q":"Normal koşulda 0,2 mol gaz kaç litre yer kaplar?","steps":[{"t":"Bağıntı","a":"V = n × 22,4","d":"Hacim = mol × 22,4 bağıntısını kullanırız."},{"t":"Hesapla","a":"0,2 × 22,4","d":"V = 0,2 × 22,4 = 4,48 L bulunur."}],"ans":"Normal koşulda 0,2 mol gaz 4,48 litre yer kaplar."}]},"lise":{"kolay":[{"q":"Normal koşul (NK) hangi sıcaklık ve basınç değerlerini ifade eder?","steps":[{"t":"Sıcaklık","a":"0 °C","d":"Normal koşulda sıcaklık 0 °C (273 K) olarak alınır."},{"t":"Basınç","a":"1 atm","d":"Basınç 1 atm'dir; bu koşulda 1 mol ideal gaz 22,4 litre kaplar."}],"ans":"Normal koşul (NK): 0 °C (273 K) ve 1 atm basıncı ifade eder; 1 mol gaz 22,4 L'dir."},{"q":"Normal koşulda 1,5 mol gaz kaç litre yer kaplar?","steps":[{"t":"Bağıntı","a":"V = n × 22,4","d":"Hacim = mol × molar hacim bağıntısını kullanırız."},{"t":"Hesapla","a":"1,5 × 22,4","d":"V = 1,5 × 22,4 = 33,6 L bulunur."}],"ans":"Normal koşulda 1,5 mol gaz 33,6 litre yer kaplar."},{"q":"Normal koşulda 6,72 litre gaz kaç moldür?","steps":[{"t":"Bağıntı","a":"n = V / 22,4","d":"Mol = hacim ÷ molar hacim bağıntısını kullanırız."},{"t":"Hesapla","a":"6,72 ÷ 22,4","d":"n = 6,72 ÷ 22,4 = 0,3 mol bulunur."}],"ans":"Normal koşulda 6,72 litre gaz 0,3 moldür."},{"q":"Avogadro hipotezi ile molar hacim sabiti (22,4 L) arasında nasıl bir bağ vardır?","steps":[{"t":"Hipotez","a":"eşit hacim → eşit mol","d":"Aynı koşulda eşit hacimli gazlar eşit sayıda tanecik içerir."},{"t":"Sonuç","a":"sabit hacim","d":"Bu nedenle 1 mol her gaz, aynı (normal) koşulda hep 22,4 L kaplar; molar hacim sabittir."}],"ans":"Avogadro hipotezi, 1 mol her gazın aynı koşulda eşit hacim (NK'da 22,4 L) kapladığını gösterir."},{"q":"NK'da gazın yoğunluğu nasıl hesaplanır? (örnek: O₂, 32 g/mol)","steps":[{"t":"Bağıntı","a":"d = M / 22,4","d":"NK'da yoğunluk, molar kütlenin molar hacme bölümüdür."},{"t":"Hesapla","a":"32 ÷ 22,4","d":"O₂ için d = 32 ÷ 22,4 ≈ 1,43 g/L bulunur."}],"ans":"NK'da gaz yoğunluğu d = M / 22,4'tür; O₂ için yaklaşık 1,43 g/L'dir."}],"zor":[{"q":"NK'da 11,2 litre CO₂ gazının kütlesi kaç gramdır? (CO₂ = 44 g/mol)","fig":"<svg viewBox='0 0 320 150'><text x='160' y='35' font-size='11' text-anchor='middle' fill='#1a2b45'>11,2 L CO₂ (NK)</text><text x='160' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>n = 11,2 ÷ 22,4 = 0,5 mol</text><text x='160' y='105' font-size='11' text-anchor='middle' fill='#1a2b45'>m = 0,5 × 44</text><text x='160' y='135' font-size='13' text-anchor='middle' fill='#e0552b'>m = 22 g</text></svg>","steps":[{"t":"Mol bul","a":"n = V / 22,4","d":"n = 11,2 ÷ 22,4 = 0,5 mol."},{"t":"Kütle bul","a":"m = n × M","d":"m = 0,5 × 44 yazarız."},{"t":"Hesapla","a":"22 g","d":"0,5 × 44 = 22 g bulunur."}],"ans":"NK'da 11,2 litre CO₂'nin kütlesi 22 gramdır."},{"q":"NK'da 44 gram CO₂ gazı kaç litre yer kaplar? (CO₂ = 44 g/mol)","steps":[{"t":"Mol bul","a":"n = m / M","d":"n = 44 ÷ 44 = 1 mol."},{"t":"Hacim bul","a":"V = n × 22,4","d":"V = 1 × 22,4 yazarız."},{"t":"Hesapla","a":"22,4 L","d":"1 × 22,4 = 22,4 L bulunur."}],"ans":"NK'da 44 gram CO₂ gazı 22,4 litre yer kaplar."},{"q":"NK'da 8 gram metan (CH₄) gazının hacmi kaç litredir? (CH₄ = 16 g/mol)","steps":[{"t":"Mol bul","a":"n = m / M","d":"n = 8 ÷ 16 = 0,5 mol."},{"t":"Hacim bul","a":"V = n × 22,4","d":"V = 0,5 × 22,4 yazarız."},{"t":"Hesapla","a":"11,2 L","d":"0,5 × 22,4 = 11,2 L bulunur."}],"ans":"NK'da 8 gram metanın hacmi 11,2 litredir."},{"q":"NK'da hacmi 5,6 L olan bir gazın kütlesi 11 gramdır. Molar kütlesi kaç g/mol'dür?","steps":[{"t":"Mol bul","a":"n = V / 22,4","d":"n = 5,6 ÷ 22,4 = 0,25 mol."},{"t":"Molar kütle","a":"M = m / n","d":"M = 11 ÷ 0,25 yazarız."},{"t":"Hesapla","a":"44 g/mol","d":"11 ÷ 0,25 = 44 g/mol; bu gaz CO₂ olabilir."}],"ans":"Gazın molar kütlesi 44 g/mol'dür."},{"q":"NK'da eşit hacimli (22,4 L) O₂ ve SO₂ kaplarının kütleleri farklı mıdır? (O₂=32, SO₂=64 g/mol)","steps":[{"t":"Mol eşit","a":"1'er mol","d":"22,4 L'lik her kapta NK'da 1 mol gaz vardır; mol sayıları eşittir."},{"t":"Kütle bağıntısı","a":"m = n × M","d":"O₂: 1 × 32 = 32 g; SO₂: 1 × 64 = 64 g."},{"t":"Sonuç","a":"farklı kütle","d":"Mol eşit olsa da molar kütleler farklı olduğundan kütleler farklıdır (32 g'a karşı 64 g)."}],"ans":"Eşit hacim eşit mol içerir ama molar kütleler farklı olduğundan kütleler farklıdır: O₂ 32 g, SO₂ 64 g."}]}},"molarKutle":{"ilkokul":{"kolay":[{"q":"Bir maddenin bir <b>mol</b>'ünün gram cinsinden kütlesine ne ad verilir?","steps":[{"t":"Bir mol","a":"belirli sayıda tanecik","d":"Mol, çok sayıda taneciği bir arada saymak için kullanılan bir ölçüdür."},{"t":"Gram karşılığı","a":"molar kütle","d":"Bir molün gram cinsinden kütlesine molar kütle (g/mol) denir."}],"ans":"Bir molün gram cinsinden kütlesine molar kütle denir; birimi g/mol'dür."},{"q":"Su (H₂O) molekülünde kaç hidrojen, kaç oksijen atomu vardır?","steps":[{"t":"H sayısı","a":"2 hidrojen","d":"H₂ alt indisi 2, suda iki hidrojen atomu olduğunu gösterir."},{"t":"O sayısı","a":"1 oksijen","d":"O yanında sayı yoktur, yani bir oksijen atomu vardır."}],"ans":"Su molekülünde 2 hidrojen ve 1 oksijen atomu bulunur."},{"q":"Karbondioksit (CO₂) molekülünde toplam kaç atom vardır?","steps":[{"t":"Atomları say","a":"1 C + 2 O","d":"Bir karbon ve iki oksijen atomu vardır."},{"t":"Toplam","a":"3 atom","d":"1 + 2 = 3 atom bulunur."}],"ans":"CO₂ molekülünde toplam 3 atom (1 karbon, 2 oksijen) bulunur."},{"q":"Bir oksijen atomunun kütlesi 16 birim, bir hidrojen atomunun kütlesi 1 birimdir. Hangisi daha ağırdır?","steps":[{"t":"Sayıları karşılaştır","a":"16 > 1","d":"Oksijenin kütle değeri 16, hidrojeninki 1'dir."},{"t":"Sonuç","a":"oksijen","d":"Daha büyük sayıya sahip oksijen daha ağırdır."}],"ans":"Oksijen atomu (16) hidrojen atomundan (1) daha ağırdır."},{"q":"Bir düzine yumurta 12 yumurta demektir. Mol da çok büyük bir miktarı sayar; doğru mu?","steps":[{"t":"Düzine örneği","a":"sayma birimi","d":"Düzine gibi mol da bir sayma birimidir."},{"t":"Mol büyüklüğü","a":"çok büyük","d":"Mol, atom gibi çok küçük tanecikleri saymak için kullanılan çok büyük bir sayıdır."}],"ans":"Evet; düzine 12'yi sayar, mol ise çok daha büyük bir tanecik miktarını sayar."}],"zor":[{"q":"Suyun molar kütlesi 18 g/mol'dür. 1 mol suyun kütlesi kaç gramdır?","steps":[{"t":"Molar kütle anlamı","a":"18 g/mol","d":"1 mol suyun kütlesinin 18 gram olduğunu gösterir."},{"t":"Sonuç","a":"18 g","d":"Bu yüzden 1 mol su 18 gramdır."}],"ans":"1 mol suyun kütlesi 18 gramdır."},{"q":"1 mol suyun kütlesi 18 gram ise, 2 mol suyun kütlesi kaç gramdır?","steps":[{"t":"Bir molü bul","a":"18 g","d":"1 mol su 18 gramdır."},{"t":"İki ile çarp","a":"2 × 18","d":"2 mol için 18'i 2 ile çarparız: 2 × 18 = 36 g."}],"ans":"2 mol suyun kütlesi 36 gramdır."},{"q":"Karbondioksitin (CO₂) molar kütlesi 44 g/mol'dür. Yarım (0,5) mol CO₂ kaç gramdır?","steps":[{"t":"Bir mol","a":"44 g","d":"1 mol CO₂ 44 gramdır."},{"t":"Yarısını al","a":"44 ÷ 2","d":"Yarım mol için 44'ü ikiye böleriz: 44 ÷ 2 = 22 g."}],"ans":"0,5 mol CO₂ 22 gramdır."},{"q":"Karbon atomunun kütlesi 12, oksijen atomunun kütlesi 16 birimdir. CO molekülünün kütlesi kaç birimdir?","steps":[{"t":"Atomları yaz","a":"1 C + 1 O","d":"CO molekülünde bir karbon ve bir oksijen vardır."},{"t":"Topla","a":"12 + 16","d":"Kütleleri toplarız: 12 + 16 = 28 birim."}],"ans":"CO molekülünün kütlesi 28 birimdir (molar kütle 28 g/mol)."},{"q":"36 gram su kaç mol eder? (1 mol su = 18 g)","fig":"<svg viewBox='0 0 320 150'><rect x='60' y='55' width='50' height='40' fill='#cfd8e8' stroke='#1a2b45'/><text x='85' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>36 g</text><text x='150' y='80' font-size='13' text-anchor='middle' fill='#1a2b45'>÷ 18</text><text x='200' y='80' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><text x='260' y='80' font-size='13' text-anchor='middle' fill='#e0552b'>2 mol</text></svg>","steps":[{"t":"Bir mol kütlesi","a":"18 g","d":"1 mol su 18 gramdır."},{"t":"Böl","a":"36 ÷ 18","d":"Kütleyi molar kütleye böleriz: 36 ÷ 18 = 2 mol."}],"ans":"36 gram su 2 mol eder."}]},"ortaokul":{"kolay":[{"q":"Molar kütle nasıl hesaplanır?","steps":[{"t":"Formüldeki atomlar","a":"atom kütleleri","d":"Formüldeki her atomun kütlesini, atom sayısıyla çarparız."},{"t":"Topla","a":"toplam","d":"Bütün atomların kütlelerini toplarız; sonuç g/mol cinsinden molar kütledir."}],"ans":"Molar kütle, formüldeki tüm atomların kütlelerinin toplamına eşittir (g/mol)."},{"q":"Su (H₂O) molekülünün molar kütlesi kaç g/mol'dür? (H=1, O=16)","fig":"<svg viewBox='0 0 320 150'><circle cx='160' cy='65' r='20' fill='#e0552b' stroke='#1a2b45'/><circle cx='120' cy='100' r='13' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='200' cy='100' r='13' fill='#cfd8e8' stroke='#1a2b45'/><line x1='146' y1='78' x2='128' y2='90' stroke='#1a2b45'/><line x1='174' y1='78' x2='192' y2='90' stroke='#1a2b45'/><text x='160' y='69' font-size='10' text-anchor='middle' fill='#fff'>O 16</text><text x='118' y='104' font-size='8' text-anchor='middle' fill='#1a2b45'>H 1</text><text x='202' y='104' font-size='8' text-anchor='middle' fill='#1a2b45'>H 1</text><text x='160' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>1+1+16 = 18 g/mol</text></svg>","steps":[{"t":"Atom kütleleri","a":"2·H + O","d":"İki hidrojen ve bir oksijen: 2·1 + 16."},{"t":"Topla","a":"2 + 16 = 18","d":"Toplam 18 g/mol bulunur."}],"ans":"Suyun molar kütlesi 18 g/mol'dür."},{"q":"Karbondioksitin (CO₂) molar kütlesi kaç g/mol'dür? (C=12, O=16)","fig":"<svg viewBox='0 0 320 150'><circle cx='100' cy='75' r='16' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='160' cy='75' r='20' fill='#33415588' stroke='#1a2b45'/><circle cx='220' cy='75' r='16' fill='#e0552b' stroke='#1a2b45'/><line x1='120' y1='75' x2='142' y2='75' stroke='#1a2b45'/><line x1='178' y1='75' x2='204' y2='75' stroke='#1a2b45'/><text x='160' y='80' font-size='10' text-anchor='middle' fill='#fff'>C</text><text x='100' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>O</text><text x='220' y='80' font-size='10' text-anchor='middle' fill='#fff'>O</text></svg>","steps":[{"t":"Atomları çarp","a":"C + 2·O","d":"Bir karbon (12) ve iki oksijen (2·16 = 32)."},{"t":"Topla","a":"12 + 32 = 44","d":"Toplam 44 g/mol bulunur."}],"ans":"CO₂'nin molar kütlesi 44 g/mol'dür."},{"q":"Metan (CH₄) gazının molar kütlesi kaç g/mol'dür? (C=12, H=1)","steps":[{"t":"Atom kütleleri","a":"C + 4·H","d":"Bir karbon (12) ve dört hidrojen (4·1 = 4)."},{"t":"Topla","a":"12 + 4 = 16","d":"Toplam 16 g/mol bulunur."}],"ans":"Metanın (CH₄) molar kütlesi 16 g/mol'dür."},{"q":"Oksijen gazının (O₂) molar kütlesi kaç g/mol'dür? (O=16)","steps":[{"t":"İki oksijen","a":"2·16","d":"O₂ iki oksijen atomundan oluşur: 2·16."},{"t":"Sonuç","a":"32","d":"Toplam 32 g/mol bulunur."}],"ans":"Oksijen gazının (O₂) molar kütlesi 32 g/mol'dür."}],"zor":[{"q":"Kalsiyum karbonatın (CaCO₃) molar kütlesi kaç g/mol'dür? (Ca=40, C=12, O=16)","fig":"<svg viewBox='0 0 320 150'><text x='160' y='40' font-size='13' text-anchor='middle' fill='#1a2b45'>CaCO₃</text><text x='60' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>Ca: 40</text><text x='130' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>C: 12</text><text x='220' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>3·O: 48</text><line x1='30' y1='90' x2='290' y2='90' stroke='#1a2b45'/><text x='160' y='120' font-size='13' text-anchor='middle' fill='#e0552b'>= 100 g/mol</text></svg>","steps":[{"t":"Atomları ayır","a":"Ca + C + 3·O","d":"Bir kalsiyum (40), bir karbon (12) ve üç oksijen (3·16 = 48)."},{"t":"Topla","a":"40 + 12 + 48","d":"Toplam: 40 + 12 + 48 = 100 g/mol."}],"ans":"CaCO₃'ün molar kütlesi 100 g/mol'dür."},{"q":"Sülfürik asidin (H₂SO₄) molar kütlesi kaç g/mol'dür? (H=1, S=32, O=16)","fig":"<svg viewBox='0 0 320 150'><text x='160' y='38' font-size='13' text-anchor='middle' fill='#1a2b45'>H₂SO₄</text><text x='55' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>2·H: 2</text><text x='130' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>S: 32</text><text x='220' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>4·O: 64</text><line x1='30' y1='90' x2='290' y2='90' stroke='#1a2b45'/><text x='160' y='120' font-size='13' text-anchor='middle' fill='#e0552b'>= 98 g/mol</text></svg>","steps":[{"t":"Atomları ayır","a":"2·H + S + 4·O","d":"İki hidrojen (2), bir kükürt (32) ve dört oksijen (4·16 = 64)."},{"t":"Topla","a":"2 + 32 + 64","d":"Toplam: 2 + 32 + 64 = 98 g/mol."}],"ans":"H₂SO₄'ün molar kütlesi 98 g/mol'dür."},{"q":"3 mol suyun (H₂O) kütlesi kaç gramdır? (molar kütle 18 g/mol)","steps":[{"t":"Molar kütle","a":"18 g/mol","d":"1 mol su 18 gramdır."},{"t":"Mol ile çarp","a":"3 × 18","d":"Kütle = mol × molar kütle = 3 × 18 = 54 g."}],"ans":"3 mol suyun kütlesi 54 gramdır."},{"q":"88 gram karbondioksit (CO₂) kaç moldür? (molar kütle 44 g/mol)","steps":[{"t":"Molar kütle","a":"44 g/mol","d":"1 mol CO₂ 44 gramdır."},{"t":"Kütleyi böl","a":"88 ÷ 44","d":"mol = kütle ÷ molar kütle = 88 ÷ 44 = 2 mol."}],"ans":"88 gram CO₂ 2 moldür."},{"q":"Glikozun (C₆H₁₂O₆) molar kütlesi kaç g/mol'dür? (C=12, H=1, O=16)","steps":[{"t":"Atomları ayır","a":"6·C + 12·H + 6·O","d":"Altı karbon (6·12 = 72), on iki hidrojen (12·1 = 12), altı oksijen (6·16 = 96)."},{"t":"Topla","a":"72 + 12 + 96","d":"Toplam: 72 + 12 + 96 = 180 g/mol."}],"ans":"Glikozun (C₆H₁₂O₆) molar kütlesi 180 g/mol'dür."}]},"lise":{"kolay":[{"q":"Molar kütle ile mol miktarı arasındaki ilişki nedir?","steps":[{"t":"Tanım","a":"M = m / n","d":"Molar kütle (M), kütlenin (m) mol sayısına (n) bölümüdür."},{"t":"Düzenle","a":"n = m / M","d":"Buradan mol = kütle ÷ molar kütle bağıntısı elde edilir."}],"ans":"n = m / M; mol miktarı, kütlenin molar kütleye bölümüne eşittir."},{"q":"Amonyak (NH₃) molekülünün molar kütlesi kaç g/mol'dür? (N=14, H=1)","steps":[{"t":"Atomları ayır","a":"N + 3·H","d":"Bir azot (14) ve üç hidrojen (3·1 = 3)."},{"t":"Topla","a":"14 + 3 = 17","d":"Toplam 17 g/mol bulunur."}],"ans":"Amonyağın (NH₃) molar kütlesi 17 g/mol'dür."},{"q":"Sodyum klorürün (NaCl) molar kütlesi kaç g/mol'dür? (Na=23, Cl=35,5)","steps":[{"t":"İyonları topla","a":"Na + Cl","d":"Bir sodyum (23) ve bir klor (35,5)."},{"t":"Topla","a":"23 + 35,5","d":"Toplam: 23 + 35,5 = 58,5 g/mol."}],"ans":"NaCl'ün molar kütlesi 58,5 g/mol'dür."},{"q":"0,5 mol glikoz (C₆H₁₂O₆) kaç gramdır? (molar kütle 180 g/mol)","steps":[{"t":"Molar kütle","a":"180 g/mol","d":"1 mol glikoz 180 gramdır."},{"t":"Hesapla","a":"0,5 × 180","d":"Kütle = n × M = 0,5 × 180 = 90 g."}],"ans":"0,5 mol glikoz 90 gramdır."},{"q":"Bağıl atom kütlesi ile molar kütle arasındaki ilişki nedir?","steps":[{"t":"Bağıl atom kütlesi","a":"akb cinsinden","d":"Bir atomun karbon-12'ye göre kütlesi, atom kütle birimiyle (akb) verilir."},{"t":"Sayısal eşitlik","a":"aynı sayı","d":"Bir maddenin molar kütlesi, formül kütlesiyle sayıca aynıdır; sadece birimi g/mol'dür."}],"ans":"Molar kütle, formül kütlesiyle sayıca eşittir; birimi g/mol'dür (örneğin su 18 akb, molar kütle 18 g/mol)."}],"zor":[{"q":"49 gram sülfürik asit (H₂SO₄) kaç moldür? (molar kütle 98 g/mol)","steps":[{"t":"Molar kütle","a":"98 g/mol","d":"Önce H₂SO₄'ün molar kütlesi: 2·1 + 32 + 4·16 = 98 g/mol."},{"t":"Mol bağıntısı","a":"n = m / M","d":"n = 49 ÷ 98 yazarız."},{"t":"Hesapla","a":"0,5 mol","d":"49 ÷ 98 = 0,5 mol bulunur."}],"ans":"49 gram H₂SO₄ 0,5 moldür."},{"q":"250 gram kalsiyum karbonat (CaCO₃) kaç moldür? (molar kütle 100 g/mol)","steps":[{"t":"Molar kütle","a":"100 g/mol","d":"CaCO₃: 40 + 12 + 3·16 = 100 g/mol."},{"t":"Mol bağıntısı","a":"n = m / M","d":"n = 250 ÷ 100 yazarız."},{"t":"Hesapla","a":"2,5 mol","d":"250 ÷ 100 = 2,5 mol bulunur."}],"ans":"250 gram CaCO₃ 2,5 moldür."},{"q":"Molar kütlesi 18 g/mol olan su örneğinde 1,5 mol bulunuyorsa kütle kaç gramdır?","steps":[{"t":"Bağıntı","a":"m = n · M","d":"Kütle = mol × molar kütle bağıntısını kullanırız."},{"t":"Değerleri yaz","a":"1,5 × 18","d":"m = 1,5 × 18 işlemini yaparız."},{"t":"Hesapla","a":"27 g","d":"1,5 × 18 = 27 g bulunur."}],"ans":"1,5 mol suyun kütlesi 27 gramdır."},{"q":"Bir bileşiğin 0,25 molü 11 gram geliyorsa molar kütlesi kaç g/mol'dür?","steps":[{"t":"Bağıntı","a":"M = m / n","d":"Molar kütle = kütle ÷ mol bağıntısını kullanırız."},{"t":"Değerleri yaz","a":"11 ÷ 0,25","d":"M = 11 ÷ 0,25 işlemini yaparız."},{"t":"Hesapla","a":"44 g/mol","d":"11 ÷ 0,25 = 44 g/mol; bu CO₂ ile uyumludur."}],"ans":"Bileşiğin molar kütlesi 44 g/mol'dür."},{"q":"Glikozun (C₆H₁₂O₆, 180 g/mol) 540 gramı kaç moldür?","fig":"<svg viewBox='0 0 320 150'><text x='160' y='40' font-size='12' text-anchor='middle' fill='#1a2b45'>C₆H₁₂O₆ → 180 g/mol</text><text x='160' y='80' font-size='12' text-anchor='middle' fill='#1a2b45'>n = 540 ÷ 180</text><text x='160' y='120' font-size='14' text-anchor='middle' fill='#e0552b'>n = 3 mol</text></svg>","steps":[{"t":"Molar kütle","a":"180 g/mol","d":"C₆H₁₂O₆: 6·12 + 12·1 + 6·16 = 180 g/mol."},{"t":"Mol bağıntısı","a":"n = m / M","d":"n = 540 ÷ 180 yazarız."},{"t":"Hesapla","a":"3 mol","d":"540 ÷ 180 = 3 mol bulunur."}],"ans":"540 gram glikoz 3 moldür."}]}},"molKutleTanecik":{"ilkokul":{"kolay":[{"q":"Bir maddeyi tartınca neyini ölçeriz?","steps":[{"t":"Tartı ne ölçer","a":"kütle","d":"Bir maddeyi teraziye koyup tarttığımızda onun kütlesini (gramını) ölçeriz."},{"t":"Birim","a":"gram","d":"Kütle çoğunlukla gram (g) ile ifade edilir."}],"ans":"Bir maddeyi tarttığımızda onun kütlesini (gramını) ölçeriz."},{"q":"Bir maddenin mol miktarı (1 molün gramı) bilinirse, 1 mol o maddenin kütlesi nasıl bulunur?","fig":"<svg viewBox='0 0 300 90'><text x='10' y='40' font-size='14' fill='#1a2b45'>1 mol → kütle (g)</text><text x='10' y='72' font-size='13' fill='#e0552b'>terazide gram</text></svg>","steps":[{"t":"Mol miktarı","a":"1 molün gramı","d":"Her maddenin 1 molünün kaç gram olduğu bellidir (mol miktarı)."},{"t":"1 molün kütlesi","a":"o değer kadar","d":"1 mol maddenin kütlesi, tam olarak mol miktarına eşittir."}],"ans":"1 mol maddenin kütlesi, o maddenin mol miktarına (1 molün gramına) eşittir."},{"q":"1 mol karbon 12 gram ise, 2 mol karbon kaç gram eder? (C=12)","steps":[{"t":"1 mol kaç gram","a":"12 g","d":"Karbonun 1 molü 12 gramdır."},{"t":"2 katına çıkar","a":"12 × 2 = 24","d":"2 mol, 1 molün 2 katı olduğundan kütle de 2 katı olur: 12 × 2 = 24 gram."}],"ans":"2 mol karbon 24 gram eder."},{"q":"24 gram karbon kaç mol eder? (1 mol karbon = 12 g)","steps":[{"t":"1 mol kaç gram","a":"12 g","d":"Karbonun 1 molü 12 gramdır."},{"t":"Böl","a":"24 ÷ 12 = 2","d":"24 gramı 12 ye bölersek 2 çıkar; yani 24 gram karbon 2 mol eder."}],"ans":"24 gram karbon 2 mol eder."},{"q":"1 mol su 18 gram ise yarım (0,5) mol su kaç gram eder? (su = 18 g/mol)","steps":[{"t":"1 mol kaç gram","a":"18 g","d":"Suyun 1 molü 18 gramdır."},{"t":"Yarısını al","a":"18 ÷ 2 = 9","d":"Yarım mol, 1 molün yarısı olduğundan kütle de yarıya iner: 18 ÷ 2 = 9 gram."}],"ans":"0,5 mol su 9 gram eder."}],"zor":[{"q":"3 mol su kaç gram eder? (su = 18 g/mol)","steps":[{"t":"1 mol kaç gram","a":"18 g","d":"Suyun 1 molü 18 gramdır."},{"t":"3 katına çıkar","a":"18 × 3 = 54","d":"3 mol için kütle 18 × 3 = 54 gram olur."}],"ans":"3 mol su 54 gram eder."},{"q":"46 gram sodyum kaç mol eder? (Na = 23 g/mol)","steps":[{"t":"1 mol kaç gram","a":"23 g","d":"Sodyumun 1 molü 23 gramdır."},{"t":"Böl","a":"46 ÷ 23 = 2","d":"46 gramı 23 e bölersek 2 çıkar; yani 46 gram sodyum 2 mol eder."}],"ans":"46 gram sodyum 2 mol eder."},{"q":"2 mol madde içinde kaç tane tanecik vardır? (1 mol = 6,02·10²³ tane)","fig":"<svg viewBox='0 0 300 90'><text x='10' y='40' font-size='14' fill='#1a2b45'>2 mol = ? tane</text><text x='10' y='72' font-size='13' fill='#e0552b'>12,04·10²³ tane</text></svg>","steps":[{"t":"1 mol kaç tane","a":"6,02·10²³","d":"Bir mol 6,02·10²³ tanecik içerir."},{"t":"2 katına çıkar","a":"12,04·10²³","d":"2 mol için tanecik sayısı 2 × 6,02·10²³ = 12,04·10²³ olur."}],"ans":"2 mol madde içinde 12,04·10²³ tane tanecik vardır."},{"q":"1 mol oksijen gazı 32 gram ise 64 gram oksijen kaç mol eder? (O₂ = 32 g/mol)","steps":[{"t":"1 mol kaç gram","a":"32 g","d":"Oksijen gazının (O₂) 1 molü 32 gramdır."},{"t":"Böl","a":"64 ÷ 32 = 2","d":"64 gramı 32 ye bölersek 2 çıkar; yani 64 gram oksijen 2 mol eder."}],"ans":"64 gram oksijen gazı 2 mol eder."},{"q":"Hem kütleyi hem tanecik sayısını bulmak için ortak köprü hangi büyüklüktür?","steps":[{"t":"Ortak nokta","a":"mol","d":"Gram ile tanecik sayısı doğrudan birbirine çevrilmez; ikisinin de ortak köprüsü moldür."},{"t":"Nasıl","a":"önce mole","d":"Önce mol bulunur, sonra mol kullanılarak hem kütleye hem tanecik sayısına geçilir."}],"ans":"Kütle ile tanecik sayısı arasındaki ortak köprü moldür; önce mol bulunur, sonra diğerine geçilir."}]},"ortaokul":{"kolay":[{"q":"Mol, kütle ve mol miktarı arasındaki bağıntı nedir?","fig":"<svg viewBox='0 0 320 90'><text x='10' y='40' font-size='14' fill='#1a2b45'>n = m / M</text><text x='10' y='72' font-size='12' fill='#e0552b'>mol = kütle ÷ molmiktarı</text></svg>","steps":[{"t":"Formül","a":"n = m / M","d":"Mol sayısı (n), kütlenin (m) mol miktarına (M, g/mol) bölünmesiyle bulunur."},{"t":"Ters yön","a":"m = n × M","d":"Kütle isteniyorsa mol sayısı mol miktarıyla çarpılır: m = n × M."}],"ans":"Mol sayısı n = m / M; kütle ise m = n × M bağıntısıyla bulunur (M = mol miktarı, g/mol)."},{"q":"36 gram su kaç moldür? (H₂O = 18 g/mol)","steps":[{"t":"Formülü yaz","a":"n = m / M","d":"Mol sayısı, kütlenin mol miktarına bölünmesiyle bulunur."},{"t":"Yerine koy","a":"36 ÷ 18 = 2","d":"n = 36 / 18 = 2 mol su eder."}],"ans":"36 gram su 2 moldür."},{"q":"0,5 mol NaCl kaç gramdır? (Na=23, Cl=35,5)","steps":[{"t":"Mol miktarını bul","a":"58,5 g/mol","d":"NaCl in mol miktarı 23 + 35,5 = 58,5 g/moldür."},{"t":"Kütleyi hesapla","a":"0,5 × 58,5 = 29,25","d":"m = n × M = 0,5 × 58,5 = 29,25 gramdır."}],"ans":"0,5 mol NaCl 29,25 gramdır."},{"q":"2 mol CO₂ kaç gramdır? (C=12, O=16)","steps":[{"t":"Mol miktarını bul","a":"44 g/mol","d":"CO₂ nin mol miktarı 12 + 2 × 16 = 12 + 32 = 44 g/moldür."},{"t":"Kütleyi hesapla","a":"2 × 44 = 88","d":"m = n × M = 2 × 44 = 88 gramdır."}],"ans":"2 mol CO₂ 88 gramdır."},{"q":"1,5 mol madde içinde kaç tane tanecik vardır?","steps":[{"t":"Formülü yaz","a":"N = n × N_A","d":"Tanecik sayısı, mol ile Avogadro sayısının çarpımıdır."},{"t":"Yerine koy","a":"1,5 × 6,02·10²³","d":"N = 1,5 × 6,02·10²³ = 9,03·10²³ tanecik bulunur."}],"ans":"1,5 mol madde içinde 9,03·10²³ tane tanecik vardır."}],"zor":[{"q":"88 gram CO₂ içinde kaç tane molekül vardır? (C=12, O=16; N_A=6,02·10²³)","fig":"<svg viewBox='0 0 320 90'><text x='10' y='35' font-size='12' fill='#1a2b45'>kütle → mol → tanecik</text><text x='10' y='65' font-size='12' fill='#e0552b'>m/M = n,  N = n·N_A</text></svg>","steps":[{"t":"Mole çevir","a":"2 mol","d":"CO₂ mol miktarı 44 g/moldür; n = 88 / 44 = 2 mol."},{"t":"Taneciğe çevir","a":"12,04·10²³","d":"N = n × N_A = 2 × 6,02·10²³ = 12,04·10²³ molekül bulunur."}],"ans":"88 gram CO₂ içinde 12,04·10²³ tane molekül vardır."},{"q":"3,01·10²³ tane su molekülünün kütlesi kaç gramdır? (H₂O = 18 g/mol)","steps":[{"t":"Mole çevir","a":"0,5 mol","d":"n = N / N_A = 3,01·10²³ / 6,02·10²³ = 0,5 mol su."},{"t":"Kütleye çevir","a":"0,5 × 18 = 9","d":"m = n × M = 0,5 × 18 = 9 gramdır."}],"ans":"3,01·10²³ tane su molekülünün kütlesi 9 gramdır."},{"q":"11,5 gram sodyum kaç tane atom içerir? (Na=23 g/mol)","steps":[{"t":"Mole çevir","a":"0,5 mol","d":"n = m / M = 11,5 / 23 = 0,5 mol sodyum."},{"t":"Taneciğe çevir","a":"3,01·10²³","d":"N = n × N_A = 0,5 × 6,02·10²³ = 3,01·10²³ atom içerir."}],"ans":"11,5 gram sodyum 3,01·10²³ tane atom içerir."},{"q":"4 mol NH₃ kaç gramdır? (N=14, H=1)","steps":[{"t":"Mol miktarı","a":"17 g/mol","d":"NH₃ mol miktarı 14 + 3 × 1 = 17 g/moldür."},{"t":"Kütleyi hesapla","a":"4 × 17 = 68","d":"m = n × M = 4 × 17 = 68 gramdır."}],"ans":"4 mol NH₃ 68 gramdır."},{"q":"117 gram NaCl içinde kaç tane formül birimi vardır? (Na=23, Cl=35,5)","steps":[{"t":"Mole çevir","a":"2 mol","d":"NaCl mol miktarı 58,5 g/moldür; n = 117 / 58,5 = 2 mol."},{"t":"Taneciğe çevir","a":"12,04·10²³","d":"N = n × N_A = 2 × 6,02·10²³ = 12,04·10²³ formül birimi vardır."}],"ans":"117 gram NaCl içinde 12,04·10²³ tane formül birimi vardır."}]},"lise":{"kolay":[{"q":"Mol köprüsüyle kütle ve tanecik sayısı arasındaki dönüşüm hangi iki bağıntıyla yapılır?","fig":"<svg viewBox='0 0 330 95'><text x='10' y='35' font-size='13' fill='#1a2b45'>kütle ⇌ mol ⇌ tanecik</text><text x='10' y='65' font-size='12' fill='#e0552b'>m = n·M   ve   N = n·N_A</text></svg>","steps":[{"t":"Kütle köprüsü","a":"m = n × M","d":"Mol ile kütle arasında m = n × M (M mol miktarı, g/mol) bağıntısı vardır."},{"t":"Tanecik köprüsü","a":"N = n × N_A","d":"Mol ile tanecik sayısı arasında N = n × N_A bağıntısı vardır; mol her iki dönüşümün ortak köprüsüdür."}],"ans":"Kütle ile m = n × M, tanecik sayısı ile N = n × N_A bağıntıları kullanılır; mol her iki dönüşümün ortak köprüsüdür."},{"q":"0,25 mol H₂SO₄ kaç gramdır? (H=1, S=32, O=16)","steps":[{"t":"Mol miktarı","a":"98 g/mol","d":"H₂SO₄ mol miktarı 2 × 1 + 32 + 4 × 16 = 2 + 32 + 64 = 98 g/moldür."},{"t":"Kütleyi hesapla","a":"0,25 × 98 = 24,5","d":"m = n × M = 0,25 × 98 = 24,5 gramdır."}],"ans":"0,25 mol H₂SO₄ 24,5 gramdır."},{"q":"54 gram glikoz (C₆H₁₂O₆) kaç moldür? (C=12, H=1, O=16)","steps":[{"t":"Mol miktarı","a":"180 g/mol","d":"Glikoz mol miktarı 6 × 12 + 12 × 1 + 6 × 16 = 72 + 12 + 96 = 180 g/moldür."},{"t":"Mole çevir","a":"54 ÷ 180 = 0,3","d":"n = m / M = 54 / 180 = 0,3 mol eder."}],"ans":"54 gram glikoz 0,3 moldür."},{"q":"1,204·10²³ tane CH₄ molekülünün kütlesi kaç gramdır? (C=12, H=1)","steps":[{"t":"Mole çevir","a":"0,2 mol","d":"n = N / N_A = 1,204·10²³ / 6,02·10²³ = 0,2 mol CH₄."},{"t":"Kütleye çevir","a":"0,2 × 16 = 3,2","d":"CH₄ mol miktarı 12 + 4 = 16 g/mol; m = 0,2 × 16 = 3,2 gramdır."}],"ans":"1,204·10²³ tane CH₄ molekülünün kütlesi 3,2 gramdır."},{"q":"8 gram NaOH kaç tane formül birimi içerir? (Na=23, O=16, H=1)","steps":[{"t":"Mole çevir","a":"0,2 mol","d":"NaOH mol miktarı 23 + 16 + 1 = 40 g/mol; n = 8 / 40 = 0,2 mol."},{"t":"Taneciğe çevir","a":"1,204·10²³","d":"N = n × N_A = 0,2 × 6,02·10²³ = 1,204·10²³ formül birimi içerir."}],"ans":"8 gram NaOH 1,204·10²³ tane formül birimi içerir."}],"zor":[{"q":"36 gram suyun (H₂O) içinde toplam kaç tane atom vardır? (H=1, O=16)","fig":"<svg viewBox='0 0 320 110'><circle cx='150' cy='50' r='15' fill='#e0552b' stroke='#1a2b45'/><text x='150' y='55' font-size='11' text-anchor='middle' fill='#fff'>O</text><circle cx='115' cy='72' r='10' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='185' cy='72' r='10' fill='#cfd8e8' stroke='#1a2b45'/><text x='150' y='100' font-size='11' text-anchor='middle' fill='#1a2b45'>1 H₂O = 3 atom</text></svg>","steps":[{"t":"Mole çevir","a":"2 mol su","d":"H₂O mol miktarı 18 g/mol; n = 36 / 18 = 2 mol su."},{"t":"Atomu hesapla","a":"6 mol → tane","d":"Her su 3 atom içerdiğinden atom = 3 × 2 = 6 mol = 6 × 6,02·10²³ = 36,12·10²³ atomdur."}],"ans":"36 gram su içinde 6 mol, yani 36,12·10²³ tane atom vardır."},{"q":"22 gram CO₂ içinde kaç tane oksijen atomu bulunur? (C=12, O=16)","steps":[{"t":"Mole çevir","a":"0,5 mol CO₂","d":"CO₂ mol miktarı 44 g/mol; n = 22 / 44 = 0,5 mol."},{"t":"O atomunu hesapla","a":"1 mol → tane","d":"Her CO₂ de 2 oksijen var; O = 2 × 0,5 = 1 mol = 6,02·10²³ tane atomdur."}],"ans":"22 gram CO₂ içinde 1 mol, yani 6,02·10²³ tane oksijen atomu bulunur."},{"q":"İçinde 1,806·10²⁴ tane atom bulunan amonyak (NH₃) örneği kaç gramdır? (N=14, H=1)","steps":[{"t":"Atomu mole çevir","a":"3 mol atom","d":"Atom sayısı / N_A = 1,806·10²⁴ / 6,02·10²³ = 3 mol atom."},{"t":"Molekül ve kütle","a":"0,75 mol → 12,75 g","d":"Her NH₃ 4 atom içerir; molekül = 3 / 4 = 0,75 mol. Mol miktarı 17 g/mol olduğundan m = 0,75 × 17 = 12,75 gramdır."}],"ans":"1,806·10²⁴ tane atom içeren amonyak örneği 0,75 mol, yani 12,75 gramdır."},{"q":"Eşit kütlede (örneğin 16 g) alınan O₂ ve CH₄ gazlarından hangisi daha çok molekül içerir? (O=16, C=12, H=1)","steps":[{"t":"Molleri bul","a":"O₂: 0,5 / CH₄: 1","d":"O₂ mol miktarı 32 g/mol → n = 16/32 = 0,5 mol; CH₄ mol miktarı 16 g/mol → n = 16/16 = 1 mol."},{"t":"Karşılaştır","a":"CH₄ daha çok","d":"Molekül sayısı mol ile orantılıdır; CH₄ (1 mol) O₂ ye (0,5 mol) göre 2 kat daha fazla molekül içerir."}],"ans":"Eşit kütlede CH₄ (1 mol) O₂ den (0,5 mol) 2 kat daha çok molekül içerir; küçük mol miktarlı madde daha çok molekül verir."},{"q":"0,1 mol Ca(OH)₂ içinde toplam kaç tane oksijen atomu ve örneğin kütlesi kaç gramdır? (Ca=40, O=16, H=1)","steps":[{"t":"Kütleyi bul","a":"7,4 g","d":"Ca(OH)₂ mol miktarı 40 + 2 × (16 + 1) = 40 + 34 = 74 g/mol; m = 0,1 × 74 = 7,4 gramdır."},{"t":"O atomunu hesapla","a":"1,204·10²³","d":"Her birimde 2 oksijen var; O = 2 × 0,1 = 0,2 mol = 0,2 × 6,02·10²³ = 1,204·10²³ tane atomdur."}],"ans":"0,1 mol Ca(OH)₂ 7,4 gramdır ve içinde 1,204·10²³ tane oksijen atomu bulunur."}]}},"molNedir":{"ilkokul":{"kolay":[{"q":"Bir kutu kalemi tane tane saymak yerine, çok sayıda kalemi kolayca saymak için ne kullanırız?","steps":[{"t":"Sorun","a":"saymak zor","d":"Çok sayıda nesneyi tek tek saymak çok uzun sürer ve yorucudur."},{"t":"Çözüm","a":"sayma birimi","d":"Bir düzine (12 tane) gibi bir sayma birimi kullanırsak çok sayıda kalemi kolayca sayabiliriz."}],"ans":"Çok sayıda nesneyi kolay saymak için bir <b>sayma birimi</b> (örneğin düzine) kullanırız."},{"q":"Bir düzine yumurta kaç tane yumurta demektir?","steps":[{"t":"Düzine","a":"12 tane","d":"Düzine, bir sayma birimidir ve her zaman 12 tane demektir."},{"t":"Sonuç","a":"12 yumurta","d":"Bir düzine yumurta dediğimizde 12 tane yumurtadan söz ederiz."}],"ans":"Bir düzine yumurta <b>12 tane</b> yumurta demektir."},{"q":"Kimyacılar çok çok küçük olan atomları saymak için kullandıkları sayma birimine ne ad verir?","steps":[{"t":"Atomlar küçük","a":"çok küçük","d":"Atomlar gözle görülemeyecek kadar küçüktür, bu yüzden çok çok fazla sayıda olurlar."},{"t":"Kimyacının birimi","a":"mol","d":"Kimyacılar atomları kolay saymak için <b>mol</b> adında özel bir sayma birimi kullanır."}],"ans":"Kimyacıların atomları saymak için kullandığı sayma birimine <b>mol</b> denir."},{"q":"Düzine 12 tane demekse, mol da bir sayma birimi midir?","steps":[{"t":"Düzine örneği","a":"sayma birimi","d":"Düzine, '12 tane' anlamına gelen bir sayma birimidir."},{"t":"Mol da öyle","a":"evet birim","d":"Mol da tıpkı düzine gibi bir sayma birimidir; ama çok daha büyük bir sayıyı ifade eder."}],"ans":"Evet, mol da tıpkı düzine gibi bir <b>sayma birimidir</b>."},{"q":"Neden kimyacılar atomları 'bir', 'iki', 'üç' diye tek tek saymaz?","steps":[{"t":"Çok fazla","a":"sayılamaz çoklukta","d":"Küçük bir madde parçasında bile saymakla bitmeyecek kadar çok atom vardır."},{"t":"Birim kullanmak","a":"mol","d":"Bu kadar çok şeyi tek tek saymak yerine mol gibi bir birim kullanmak çok daha kolaydır."}],"ans":"Atomlar sayılamayacak kadar çok olduğu için tek tek saymak yerine <b>mol</b> birimini kullanırız."}],"zor":[{"q":"Markette 5 düzine yumurta varsa toplam kaç yumurta vardır?","steps":[{"t":"Bir düzine","a":"12 tane","d":"Bir düzine 12 tane demektir."},{"t":"Çarpma","a":"5 × 12 = 60","d":"5 düzine için 5 × 12 işlemini yaparız ve 60 buluruz."}],"ans":"5 düzine yumurta <b>60 tane</b> yumurta eder."},{"q":"Mol kelimesi, kimyacılar için neye yarayan bir 'paket' gibidir?","steps":[{"t":"Paket fikri","a":"belli sayıda tane","d":"Bir paket, içinde belli sayıda nesne bulunan bir gruptur, tıpkı düzinedeki 12 gibi."},{"t":"Mol paketi","a":"çok büyük paket","d":"Mol da içinde çok büyük ve hep aynı sayıda tanecik bulunan bir 'paket' gibidir."}],"ans":"Mol, kimyacılar için içinde her zaman <b>aynı ve çok büyük sayıda tanecik</b> bulunan bir paket gibidir."},{"q":"Tek tek saymak yerine birim kullanmak hangi günlük durumlarda işimizi kolaylaştırır?","steps":[{"t":"Günlük örnekler","a":"düzine, deste","d":"Yumurtayı düzine, kağıdı deste ile sayarız; tek tek saymaktan kolaydır."},{"t":"Kimyada karşılığı","a":"mol","d":"Kimyada da çok sayıda atomu saymak için aynı mantıkla mol birimi kullanılır."}],"ans":"Çok sayıda şeyi saymada birim kullanmak işi kolaylaştırır; kimyada bunun karşılığı <b>mol</b> birimidir."},{"q":"Bir mol şeker mi yoksa bir tane şeker tanesi mi daha çok tanecik içerir?","steps":[{"t":"Tek tane","a":"1 tanecik grubu","d":"Bir tane şeker, görece az tanecikten oluşur."},{"t":"Bir mol","a":"çok daha fazla","d":"Bir mol ise sayılamayacak kadar çok tanecik içeren büyük bir birimdir."}],"ans":"Bir mol madde, tek bir taneden çok çok daha <b>fazla tanecik</b> içerir."},{"q":"Kimyacılar neden 'mol' gibi özel bir sayma birimine ihtiyaç duymuştur?","steps":[{"t":"İhtiyaç","a":"çok küçük ve çok sayıda","d":"Atomlar hem çok küçük hem de inanılmaz çok sayıda olduğu için tek tek saymak imkânsızdır."},{"t":"Çözüm birimi","a":"mol","d":"Bu yüzden kimyacılar bu büyük sayıyı kolayca ifade etmek için mol birimini kullanmaya başlamıştır."}],"ans":"Atomlar çok küçük ve çok sayıda olduğu için kimyacılar onları kolay ifade eden <b>mol</b> birimine ihtiyaç duymuştur."}]},"ortaokul":{"kolay":[{"q":"Kimyada mol kavramı neyi ifade eder?","steps":[{"t":"Tanım","a":"sayma birimi","d":"Mol, kimyada tanecik (atom, molekül, iyon) saymak için kullanılan temel bir sayma birimidir."},{"t":"Benzetme","a":"düzine gibi","d":"Tıpkı düzinenin 12 tane demesi gibi, mol da belirli ve sabit bir tanecik sayısını ifade eder."}],"ans":"Mol, kimyada belirli sayıda tanecik içeren bir <b>sayma birimidir</b>."},{"q":"1 mol herhangi bir madde kaç tanecik içerir?","steps":[{"t":"Sabit sayı","a":"6,02·10²³","d":"1 mol madde her zaman 6,02·10²³ tane tanecik içerir."},{"t":"Adı","a":"Avogadro sayısı","d":"Bu sabit sayıya Avogadro sayısı denir."}],"ans":"1 mol madde <b>6,02·10²³</b> tanecik içerir; bu sayı Avogadro sayısıdır."},{"q":"Mol birimini kullanmamızın temel nedeni nedir?","steps":[{"t":"Sorun","a":"tanecikler çok küçük","d":"Atom ve moleküller tek tek sayılamayacak kadar küçük ve çok sayıdadır."},{"t":"Kolaylık","a":"toplu sayma","d":"Mol sayesinde bu çok büyük tanecik miktarlarını basit sayılarla ifade edebiliriz."}],"ans":"Çok küçük ve çok sayıda taneciği kolay ifade etmek için <b>mol</b> birimini kullanırız."},{"q":"Avogadro sayısı nedir ve mol ile ilişkisi nasıldır?","steps":[{"t":"Avogadro sayısı","a":"6,02·10²³","d":"Avogadro sayısı 6,02·10²³ değerindedir."},{"t":"Mol ile bağ","a":"1 mol = bu sayı","d":"1 mol maddedeki tanecik sayısı tam olarak Avogadro sayısına eşittir."}],"ans":"Avogadro sayısı 6,02·10²³'tür ve <b>1 mol</b> maddedeki tanecik sayısına eşittir."},{"q":"Düzine ile mol arasındaki temel fark nedir?","steps":[{"t":"Düzine","a":"12 tane","d":"Düzine küçük bir sayma birimidir, 12 taneyi ifade eder."},{"t":"Mol","a":"6,02·10²³ tane","d":"Mol ise çok daha büyük bir birimdir, 6,02·10²³ taneyi ifade eder."}],"ans":"İkisi de sayma birimidir; ancak düzine 12, mol ise <b>6,02·10²³</b> taneyi ifade eder."}],"zor":[{"q":"2 mol su molekülü kaç tane su molekülü içerir?","steps":[{"t":"1 mol","a":"6,02·10²³","d":"1 mol su, 6,02·10²³ su molekülü demektir."},{"t":"2 mol","a":"2 × 6,02·10²³","d":"2 mol için bu sayıyı 2 ile çarparız: 2 × 6,02·10²³ = 1,204·10²⁴."}],"ans":"2 mol su, <b>1,204·10²⁴</b> tane su molekülü içerir."},{"q":"Neden 12 yumurta için 'düzine', atomlar için ise 'mol' gibi farklı bir birim kullanırız?","steps":[{"t":"Ölçek farkı","a":"sayı büyüklüğü","d":"Yumurtalar onlarca tane iken atomlar trilyonlarca trilyon tanedir."},{"t":"Uygun birim","a":"mol çok büyük","d":"Atomların sayısı düzine ile ifade edilemeyecek kadar büyük olduğundan çok daha büyük olan mol birimi kullanılır."}],"ans":"Atomların sayısı düzineyle ifade edilemeyecek kadar büyük olduğundan, onlara uygun çok daha büyük bir birim olan <b>mol</b> kullanılır."},{"q":"Yarım mol (0,5 mol) bir madde kaç tanecik içerir?","steps":[{"t":"1 mol","a":"6,02·10²³","d":"1 mol madde 6,02·10²³ tanecik içerir."},{"t":"0,5 mol","a":"yarısı","d":"0,5 mol için bu sayının yarısını alırız: 6,02·10²³ ÷ 2 = 3,01·10²³."}],"ans":"0,5 mol madde <b>3,01·10²³</b> tanecik içerir."},{"q":"Mol birimi olmadan kimyada hesap yapmak neden çok zor olurdu?","steps":[{"t":"Tanecik sayıları","a":"devasa sayılar","d":"Mol olmasaydı her hesapta 6,02·10²³ gibi devasa sayılarla uğraşmak zorunda kalırdık."},{"t":"Kolaylık","a":"basit sayılar","d":"Mol sayesinde '2 mol', '0,5 mol' gibi basit sayılarla pratik şekilde hesap yapabiliriz."}],"ans":"Mol olmasaydı sürekli devasa sayılarla uğraşırdık; mol bu sayıları <b>basit ve hesaplanabilir</b> hale getirir."},{"q":"3 mol demir atomu, 3 düzine demir parçasından kat kat fazla tanecik içerir; bu fark nereden gelir?","steps":[{"t":"3 düzine","a":"36 tane","d":"3 düzine yalnızca 3 × 12 = 36 tane demektir."},{"t":"3 mol","a":"3 × 6,02·10²³","d":"3 mol ise 3 × 6,02·10²³ = 1,806·10²⁴ tane demektir; düzineye göre akıl almaz derecede büyüktür."}],"ans":"3 düzine 36 tane iken 3 mol <b>1,806·10²⁴</b> tanedir; fark, molün düzineden çok daha büyük bir birim olmasından gelir."}]},"lise":{"kolay":[{"q":"Mol, SI birim sisteminde hangi büyüklüğün birimidir ve nasıl tanımlanır?","steps":[{"t":"Büyüklük","a":"madde miktarı","d":"Mol, bir maddenin içerdiği tanecik sayısını, yani madde miktarını ölçen temel SI birimidir."},{"t":"Tanım","a":"6,02·10²³ tanecik","d":"1 mol, tam olarak Avogadro sayısı kadar (6,02·10²³) temel tanecik içeren madde miktarı olarak tanımlanır."}],"ans":"Mol, <b>madde miktarının</b> SI birimidir ve 1 mol, 6,02·10²³ tanecik içeren miktar olarak tanımlanır."},{"q":"Kimyacılar makroskobik kütleyi mikroskobik tanecik sayısıyla ilişkilendirmek için neden mol kavramına ihtiyaç duyar?","steps":[{"t":"İki dünya","a":"gram ↔ tanecik","d":"Laboratuvarda gramla ölçeriz, ama tepkimeler tanecik düzeyinde gerçekleşir."},{"t":"Köprü","a":"mol","d":"Mol, tartılabilen kütle ile sayılamayan tanecik sayısı arasında bir köprü kurar."}],"ans":"Mol, tartılan <b>kütle ile tanecik sayısı</b> arasında köprü kurduğu için kimyada vazgeçilmezdir."},{"q":"'Mol bir sayma birimidir' ifadesi ne anlama gelir ve hangi taneciklere uygulanabilir?","steps":[{"t":"Sayma birimi","a":"sabit miktar","d":"Mol, düzine gibi sabit bir miktarı (6,02·10²³ tane) ifade eden bir sayma birimidir."},{"t":"Kapsam","a":"her tür tanecik","d":"Atom, molekül, iyon, elektron gibi her türlü taneciğe uygulanabilir; ama hangi tanecik olduğu belirtilmelidir."}],"ans":"Mol, 6,02·10²³ taneyi ifade eden bir sayma birimidir ve <b>atom, molekül, iyon</b> gibi her tür taneciğe uygulanır."},{"q":"Niçin '1 mol atom' demek yeterli değildir, 'neyin moolü' olduğunu belirtmek gerekir?","steps":[{"t":"Mol = sayı","a":"tanecik sayısı","d":"Mol sadece bir tanecik sayısını verir, türünü vermez."},{"t":"Belirtme","a":"madde adı şart","d":"1 mol H atomu ile 1 mol O atomu aynı sayıda tanecik içerir ama farklı maddelerdir; bu yüzden tür belirtilir."}],"ans":"Mol yalnızca sayıyı verdiği için, anlamlı olması adına <b>hangi maddenin</b> molü olduğu belirtilmelidir."},{"q":"Düzine ve mol arasındaki benzerlik ve büyüklük farkı nasıl açıklanır?","steps":[{"t":"Benzerlik","a":"ikisi de sayma birimi","d":"Hem düzine hem mol, sabit sayıda nesneyi ifade eden sayma birimleridir."},{"t":"Fark","a":"12 ↔ 6,02·10²³","d":"Düzine 12, mol ise 6,02·10²³ taneyi temsil eder; mol, düzineden yaklaşık 5·10²² kat büyüktür."}],"ans":"İkisi de sayma birimidir; ancak mol (6,02·10²³), düzineden (12) <b>akıl almaz derecede büyük</b> bir birimdir."}],"zor":[{"q":"Mol kavramı, kimyasal tepkimelerin mol oranıyla açıklanmasını nasıl mümkün kılar?","steps":[{"t":"Denklem oranı","a":"katsayılar","d":"Bir denklemdeki katsayılar (örneğin 2H₂ + O₂ → 2H₂O) taneciklerin birleşme oranını verir."},{"t":"Mol oranı","a":"aynı oran","d":"Bu tanecik oranı aynı zamanda mol oranıdır; 2 mol H₂, 1 mol O₂ ile birleşir, çünkü mol tanecik sayısıyla orantılıdır."}],"ans":"Mol, tanecik sayısıyla orantılı olduğundan denklem katsayıları doğrudan <b>mol oranı</b> olarak okunur ve tepkimeler hesaplanabilir."},{"q":"1 mol elektron ile 1 mol su molekülü aynı sayıda tanecik içerdiği halde neden çok farklı şeylerdir?","steps":[{"t":"Eşit sayı","a":"6,02·10²³","d":"İkisi de 6,02·10²³ tanecik içerir, çünkü mol yalnızca sayıyı belirtir."},{"t":"Farklı tanecik","a":"tür farkı","d":"Biri elektron, diğeri su molekülü olduğundan kütleleri, boyutları ve özellikleri tamamen farklıdır."}],"ans":"İkisi de 6,02·10²³ tanecik içerir; fark, <b>tanecik türünün</b> (elektron ve su molekülü) farklı olmasından gelir."},{"q":"Mol kavramı kullanılmasaydı, basit bir tepkime hesabı pratik olarak neden imkânsız hale gelirdi?","steps":[{"t":"Tanecik ile çalışma","a":"10²³ ölçeği","d":"Tanecikleri tek tek saysaydık her hesapta 10²³ düzeyinde devasa sayılarla işlem yapmamız gerekirdi."},{"t":"Mol kolaylığı","a":"orantılı küçük sayılar","d":"Mol, bu devasa sayıları '2 mol', '0,5 mol' gibi yönetilebilir sayılara indirger ve orantısal hesabı pratikleştirir."}],"ans":"Mol olmasaydı her işlem 10²³ düzeyinde sayılarla yapılırdı; mol bunları <b>yönetilebilir sayılara</b> indirgeyerek hesabı mümkün kılar."},{"q":"Madde miktarının (mol) kütle ya da hacimden ayrı, bağımsız bir temel büyüklük olarak tanımlanması neden gereklidir?","steps":[{"t":"Kütle yetersiz","a":"tür bağımlı","d":"Eşit kütledeki iki farklı madde farklı sayıda tanecik içerir; tek başına kütle tanecik sayısını vermez."},{"t":"Mol gerekliliği","a":"tanecik temelli","d":"Tepkimeler tanecik oranına göre yürüdüğünden, doğrudan tanecik sayısını ölçen mol gibi bağımsız bir büyüklük gerekir."}],"ans":"Kütle ve hacim tanecik sayısını doğrudan vermediğinden, tepkimeleri açıklamak için tanecik sayısına dayanan bağımsız bir büyüklük olan <b>mol</b> gereklidir."},{"q":"'Avogadro sayısı kadar tanecik' tanımı, mol kavramının evrenselliğini nasıl sağlar?","steps":[{"t":"Sabit referans","a":"6,02·10²³","d":"Mol, hangi madde olursa olsun her zaman aynı sabit sayıda (6,02·10²³) taneciği ifade eder."},{"t":"Evrensellik","a":"madde bağımsız","d":"Bu sabitlik sayesinde 1 mol H, 1 mol Fe ya da 1 mol H₂O hep aynı sayıda tanecik içerir; böylece farklı maddeler ortak bir ölçekte karşılaştırılabilir."}],"ans":"Mol her madde için aynı sabit tanecik sayısına dayandığından, farklı maddeleri ortak bir ölçekte karşılaştırmayı sağlayan <b>evrensel</b> bir birimdir."}]}},"molOranlari":{"ilkokul":{"kolay":[{"q":"Bir tarife göre 1 bardak su ile 2 kaşık toz karıştırılıyor. 2 bardak su için kaç kaşık toz gerekir?","steps":[{"t":"Oranı bul","a":"1 su : 2 toz","d":"Tarifteki oran bozulmamalı; her bardak su için 2 kaşık toz gerekiyor."},{"t":"İki katına çıkar","a":"4 kaşık","d":"Su 2 katına çıkınca toz da 2 katına çıkar: 2·2 = 4 kaşık toz gerekir."}],"ans":"2 bardak su için 4 kaşık toz gerekir; oran sabit kalmalıdır."},{"q":"Suyun formülü H₂O'dur. Bir su tanesinde kaç hidrojen, kaç oksijen vardır?","steps":[{"t":"Formülü oku","a":"H 2, O 1","d":"H₂O'daki 2 alt indisi hidrojenin 2 tane, oksijenin (indissiz) 1 tane olduğunu gösterir."},{"t":"Oran","a":"2 : 1","d":"Yani her su tanesinde hidrojen oksijene göre 2 katı sayıdadır; oran 2'ye 1'dir."}],"ans":"Bir su tanesinde 2 hidrojen ve 1 oksijen vardır; oran 2:1'dir."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde 2 hidrojen molekülü için kaç oksijen molekülü gerekir?","fig":"<svg viewBox='0 0 320 110'><text x='25' y='50' font-size='15' fill='#1a2b45'>2 H₂</text><text x='75' y='50' font-size='15' fill='#1a2b45'>+</text><text x='95' y='50' font-size='15' fill='#1a2b45'>1 O₂</text><text x='145' y='50' font-size='17' fill='#e0552b'>→</text><text x='180' y='50' font-size='15' fill='#1a2b45'>2 H₂O</text><text x='160' y='92' font-size='11' text-anchor='middle' fill='#5b6b85'>oran 2 : 1 : 2</text></svg>","steps":[{"t":"Öndeki sayıları oku","a":"2 ve 1","d":"H₂'nin önünde 2, O₂'nin önünde 1 (yazılmayan) katsayı vardır."},{"t":"Oran","a":"1 oksijen","d":"2 hidrojen molekülü için 1 oksijen molekülü gerekir; oran 2'ye 1'dir."}],"ans":"2 hidrojen molekülü için 1 oksijen molekülü gerekir (oran 2:1)."},{"q":"Bir tepkimede 3 tane A maddesi 6 tane B maddesi veriyorsa, 1 tane A kaç tane B verir?","steps":[{"t":"Oranı bul","a":"3 A → 6 B","d":"3 A'dan 6 B çıkıyorsa, her A'dan 6÷3 = 2 B çıkar."},{"t":"Sonuç","a":"2 B","d":"Yani 1 tane A maddesi 2 tane B maddesi verir."}],"ans":"1 tane A, 2 tane B verir; oran 1'e 2'dir."},{"q":"Pankek tarifinde 1 yumurta 2 pankek yapıyor. 6 pankek için kaç yumurta gerekir?","steps":[{"t":"Oranı kur","a":"1 yumurta : 2 pankek","d":"Her yumurta 2 pankek yaptığına göre pankek sayısı yumurtanın 2 katıdır."},{"t":"Geri hesapla","a":"3 yumurta","d":"6 pankek için: 6÷2 = 3 yumurta gerekir."}],"ans":"6 pankek için 3 yumurta gerekir; oran korunur."}],"zor":[{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde 4 hidrojen molekülü kaç su molekülü oluşturur?","steps":[{"t":"Oranı oku","a":"2 H₂ → 2 H₂O","d":"Katsayılara göre 2 H₂'den 2 H₂O oluşur, yani H₂ ile H₂O sayısı eşittir (1:1)."},{"t":"Hesapla","a":"4 su","d":"H₂ ve H₂O oranı 1:1 olduğundan 4 hidrojen molekülü 4 su molekülü oluşturur."}],"ans":"4 hidrojen molekülü 4 su molekülü oluşturur (oran 1:1)."},{"q":"2 Na + Cl₂ → 2 NaCl tepkimesinde 6 sodyum atomu kaç NaCl oluşturur?","steps":[{"t":"Oranı oku","a":"2 Na → 2 NaCl","d":"Katsayılara göre sodyum ile NaCl sayısı eşittir (oran 1:1)."},{"t":"Hesapla","a":"6 NaCl","d":"Oran 1:1 olduğundan 6 sodyum atomu 6 NaCl oluşturur."}],"ans":"6 sodyum atomu 6 tane NaCl oluşturur (oran 1:1)."},{"q":"N₂ + 3 H₂ → 2 NH₃ tepkimesinde 1 azot molekülü kaç hidrojen molekülüyle tepkir?","fig":"<svg viewBox='0 0 320 110'><text x='20' y='50' font-size='15' fill='#1a2b45'>1 N₂ + 3 H₂</text><text x='150' y='50' font-size='17' fill='#e0552b'>→</text><text x='185' y='50' font-size='15' fill='#1a2b45'>2 NH₃</text><text x='160' y='92' font-size='11' text-anchor='middle' fill='#5b6b85'>oran 1 : 3 : 2</text></svg>","steps":[{"t":"Katsayıları oku","a":"1 N₂, 3 H₂","d":"N₂'nin katsayısı 1, H₂'nin katsayısı 3'tür."},{"t":"Oran","a":"3 hidrojen","d":"1 azot molekülü 3 hidrojen molekülüyle tepkir (oran 1:3)."}],"ans":"1 azot molekülü 3 hidrojen molekülüyle tepkir (oran 1:3)."},{"q":"Bir tepkimede 2 A + 1 B → 3 C oranı varsa, 8 A maddesi kaç C oluşturur?","steps":[{"t":"Oranı kur","a":"2 A → 3 C","d":"Her 2 A maddesi 3 C oluşturur; A ile C oranı 2'ye 3'tür."},{"t":"Hesapla","a":"12 C","d":"8 A, 2'nin 4 katıdır; o hâlde C de 4 katına çıkar: 3·4 = 12 C oluşur."}],"ans":"8 A maddesi 12 tane C oluşturur (2 A → 3 C oranıyla)."},{"q":"CH₄ + 2 O₂ → CO₂ + 2 H₂O tepkimesinde 1 metan molekülü kaç oksijen molekülüyle yanar?","steps":[{"t":"Katsayıları oku","a":"1 CH₄, 2 O₂","d":"CH₄'ün katsayısı 1, O₂'nin katsayısı 2'dir."},{"t":"Oran","a":"2 oksijen","d":"1 metan molekülü 2 oksijen molekülüyle yanar (oran 1:2)."}],"ans":"1 metan molekülü 2 oksijen molekülüyle yanar (oran 1:2)."}]},"ortaokul":{"kolay":[{"q":"Bir kimyasal denklemdeki katsayılar maddelerin hangi büyüklüğünün oranını verir?","steps":[{"t":"Katsayı anlamı","a":"mol/molekül sayısı","d":"Denklemdeki katsayılar, tepkimeye giren ve çıkan maddelerin molekül (veya mol) sayılarını gösterir."},{"t":"Oran","a":"mol oranı","d":"Bu sayıların birbirine bölünmesiyle maddeler arası mol oranı (tepkime oranı) elde edilir."}],"ans":"Denklem katsayıları maddelerin mol (molekül) sayılarının oranını, yani mol oranını verir."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde 4 mol H₂ kaç mol su oluşturur?","steps":[{"t":"Mol oranı","a":"H₂ : H₂O = 2 : 2","d":"Katsayılara göre 2 mol H₂'den 2 mol H₂O oluşur; oran 1'e 1'dir."},{"t":"Hesapla","a":"4 mol su","d":"Oran 1:1 olduğundan 4 mol H₂, 4 mol H₂O oluşturur."}],"ans":"4 mol H₂, 4 mol su (H₂O) oluşturur (oran 2:2 = 1:1)."},{"q":"N₂ + 3 H₂ → 2 NH₃ tepkimesinde 2 mol azot kaç mol amonyak oluşturur?","steps":[{"t":"Mol oranı","a":"N₂ : NH₃ = 1 : 2","d":"Katsayılara göre 1 mol N₂'den 2 mol NH₃ oluşur."},{"t":"Hesapla","a":"4 mol NH₃","d":"2 mol N₂ kullanılırsa 2·2 = 4 mol amonyak oluşur."}],"ans":"2 mol azot 4 mol amonyak (NH₃) oluşturur (oran 1:2)."},{"q":"Normal koşullarda gazların hacim oranı mol oranıyla aynı mıdır?","fig":"<svg viewBox='0 0 320 120'><rect x='25' y='35' width='40' height='55' fill='#cfd8e8' stroke='#1a2b45'/><rect x='75' y='35' width='40' height='55' fill='#cfd8e8' stroke='#1a2b45'/><text x='70' y='108' font-size='10' text-anchor='middle' fill='#5b6b85'>2 hacim H₂</text><rect x='150' y='35' width='40' height='55' fill='#f0c' fill-opacity='0.25' stroke='#1a2b45'/><text x='170' y='108' font-size='10' text-anchor='middle' fill='#5b6b85'>1 hacim O₂</text></svg>","steps":[{"t":"Avogadro ilkesi","a":"aynı hacim aynı mol","d":"Aynı koşulda eşit hacimli gazlar eşit sayıda mol içerir."},{"t":"Sonuç","a":"evet, aynı","d":"Bu yüzden gazlarda hacim oranı, mol oranı (yani katsayı oranı) ile aynıdır."}],"ans":"Evet; aynı koşulda gazların hacim oranı, mol oranıyla (katsayı oranıyla) aynıdır."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde 10 L hidrojen gazı kaç litre oksijenle tepkir? (aynı koşullarda)","steps":[{"t":"Hacim oranı","a":"H₂ : O₂ = 2 : 1","d":"Gazlarda hacim oranı katsayı oranıdır; H₂'ye O₂ oranı 2'ye 1'dir."},{"t":"Hesapla","a":"5 L oksijen","d":"10 L hidrojen için: 10 ÷ 2 = 5 L oksijen gerekir."}],"ans":"10 L hidrojen 5 L oksijenle tepkir (hacim oranı 2:1)."}],"zor":[{"q":"CH₄ + 2 O₂ → CO₂ + 2 H₂O tepkimesinde 3 mol metan tam yandığında kaç mol oksijen harcanır?","steps":[{"t":"Mol oranı","a":"CH₄ : O₂ = 1 : 2","d":"Katsayılara göre 1 mol metan 2 mol oksijenle yanar."},{"t":"Hesapla","a":"6 mol O₂","d":"3 mol metan için: 3·2 = 6 mol oksijen harcanır."}],"ans":"3 mol metanın yanması için 6 mol oksijen harcanır (oran 1:2)."},{"q":"N₂ + 3 H₂ → 2 NH₃ tepkimesinde 6 mol hidrojen kaç mol azotla tepkir ve kaç mol amonyak oluşturur?","steps":[{"t":"Hidrojen-azot oranı","a":"H₂ : N₂ = 3 : 1","d":"6 mol H₂ için: 6 ÷ 3 = 2 mol azot gerekir."},{"t":"Amonyak miktarı","a":"4 mol NH₃","d":"H₂ : NH₃ = 3 : 2 olduğundan 6 mol H₂ → (6÷3)·2 = 4 mol amonyak oluşturur."}],"ans":"6 mol hidrojen 2 mol azotla tepkir ve 4 mol amonyak oluşturur."},{"q":"2 Na + Cl₂ → 2 NaCl tepkimesinde 4 mol sodyum kaç mol klor gazıyla tepkir?","steps":[{"t":"Mol oranı","a":"Na : Cl₂ = 2 : 1","d":"Katsayılara göre 2 mol sodyum 1 mol klor gazıyla tepkir."},{"t":"Hesapla","a":"2 mol Cl₂","d":"4 mol sodyum için: 4 ÷ 2 = 2 mol klor gazı gerekir."}],"ans":"4 mol sodyum 2 mol klor gazıyla (Cl₂) tepkir (oran 2:1)."},{"q":"C₃H₈ + 5 O₂ → 3 CO₂ + 4 H₂O tepkimesinde 2 mol propan yandığında kaç mol CO₂ oluşur?","fig":"<svg viewBox='0 0 320 110'><text x='10' y='50' font-size='13' fill='#1a2b45'>C₃H₈ + 5O₂</text><text x='130' y='50' font-size='17' fill='#e0552b'>→</text><text x='165' y='50' font-size='13' fill='#1a2b45'>3CO₂ + 4H₂O</text><text x='160' y='92' font-size='10' text-anchor='middle' fill='#5b6b85'>1 propan : 3 CO₂</text></svg>","steps":[{"t":"Mol oranı","a":"C₃H₈ : CO₂ = 1 : 3","d":"Katsayılara göre 1 mol propandan 3 mol CO₂ oluşur."},{"t":"Hesapla","a":"6 mol CO₂","d":"2 mol propan için: 2·3 = 6 mol karbondioksit oluşur."}],"ans":"2 mol propandan 6 mol CO₂ oluşur (oran 1:3)."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde aynı koşulda 8 L oksijen tepkirse kaç litre su buharı oluşur?","steps":[{"t":"Hacim oranı","a":"O₂ : H₂O = 1 : 2","d":"Gazlarda hacim oranı katsayı oranıdır; O₂'ye su buharı oranı 1'e 2'dir."},{"t":"Hesapla","a":"16 L","d":"8 L oksijen için: 8·2 = 16 L su buharı oluşur."}],"ans":"8 L oksijenden 16 L su buharı oluşur (hacim oranı 1:2)."}]},"lise":{"kolay":[{"q":"Stokiyometride mol oranı (katsayı oranı) hesaplamalarda nasıl kullanılır?","steps":[{"t":"Köprü görevi","a":"mol oranı","d":"Denklem katsayılarından elde edilen mol oranı, bir maddenin molünü başka bir maddenin molüne çeviren köprüdür."},{"t":"Uygulama","a":"çarpan","d":"Bilinen mol, hedef maddeyle arasındaki katsayı oranıyla çarpılarak istenen mol bulunur."}],"ans":"Mol oranı, bilinen maddenin molünü istenen maddenin molüne çeviren çarpan olarak kullanılır."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde 5 mol oksijenden kaç mol su oluşur?","steps":[{"t":"Mol oranı","a":"O₂ : H₂O = 1 : 2","d":"Katsayılara göre 1 mol oksijenden 2 mol su oluşur."},{"t":"Hesapla","a":"10 mol su","d":"5 mol oksijen için: 5·2 = 10 mol su oluşur."}],"ans":"5 mol oksijenden 10 mol su (H₂O) oluşur (oran 1:2)."},{"q":"N₂ + 3 H₂ ⇌ 2 NH₃ tepkimesinde 56 g azot (14 g/mol·2) kaç mol amonyak verir?","steps":[{"t":"Azotun molü","a":"2 mol","d":"N₂ molmüktarı 28 g/mol; mol = 56 ÷ 28 = 2 mol azot."},{"t":"Mol oranıyla","a":"4 mol NH₃","d":"N₂ : NH₃ = 1 : 2 olduğundan 2 mol azot → 2·2 = 4 mol amonyak verir."}],"ans":"56 g azot (2 mol) tepkirse 4 mol amonyak oluşur."},{"q":"CH₄ + 2 O₂ → CO₂ + 2 H₂O tepkimesinde NK'da 22,4 L metan yandığında kaç mol CO₂ oluşur?","steps":[{"t":"Metanın molü","a":"1 mol","d":"NK'da 22,4 L gaz = 1 moldür; 22,4 L metan 1 mol metandır."},{"t":"Mol oranıyla","a":"1 mol CO₂","d":"CH₄ : CO₂ = 1 : 1 olduğundan 1 mol metandan 1 mol CO₂ oluşur."}],"ans":"NK'da 22,4 L (1 mol) metandan 1 mol CO₂ oluşur."},{"q":"Gazlar arası tepkimelerde mol oranının doğrudan hacim oranı olarak kullanılmasının nedeni nedir?","steps":[{"t":"Avogadro yasası","a":"V ∝ n","d":"Sabit sıcaklık ve basınçta gaz hacmi mol sayısıyla doğru orantılıdır (eşit hacim eşit mol)."},{"t":"Sonuç","a":"katsayı = hacim oranı","d":"Bu nedenle gaz fazındaki maddeler için denklem katsayıları aynı zamanda hacim oranını verir."}],"ans":"Avogadro yasası gereği aynı koşulda hacim mol ile orantılı olduğundan, gazlarda katsayı oranı doğrudan hacim oranıdır."}],"zor":[{"q":"C₃H₈ + 5 O₂ → 3 CO₂ + 4 H₂O tepkimesinde 88 g propan (C₃H₈, 44 g/mol) tam yandığında oluşan CO₂ kütlesini bul.","steps":[{"t":"Propanın molü","a":"2 mol","d":"C₃H₈ molmüktarı 3·12 + 8·1 = 44 g/mol; mol = 88 ÷ 44 = 2 mol."},{"t":"CO₂ molü ve kütlesi","a":"6 mol, 264 g","d":"C₃H₈ : CO₂ = 1 : 3 → 2·3 = 6 mol CO₂. CO₂ molmüktarı 44 g/mol; kütle = 6·44 = 264 g."}],"ans":"88 g propandan 6 mol, yani 264 g CO₂ oluşur."},{"q":"N₂ + 3 H₂ ⇌ 2 NH₃ tepkimesinde NK'da 67,2 L azot gazından kaç litre amonyak elde edilir? (aynı koşulda)","steps":[{"t":"Azotun molü","a":"3 mol","d":"NK'da mol = hacim ÷ 22,4 = 67,2 ÷ 22,4 = 3 mol azot."},{"t":"Amonyak hacmi","a":"6 mol = 134,4 L","d":"N₂ : NH₃ = 1 : 2 → 3·2 = 6 mol NH₃. Hacim = 6·22,4 = 134,4 L amonyak."}],"ans":"67,2 L (3 mol) azottan 6 mol, yani 134,4 L amonyak elde edilir."},{"q":"2 Al + 3 H₂SO₄ → Al₂(SO₄)₃ + 3 H₂ tepkimesinde 0,54 g alüminyum (27 g/mol) kaç mol hidrojen gazı açığa çıkarır?","steps":[{"t":"Alüminyumun molü","a":"0,02 mol","d":"Al molmüktarı 27 g/mol; mol = 0,54 ÷ 27 = 0,02 mol."},{"t":"Hidrojen molü","a":"0,03 mol","d":"Al : H₂ = 2 : 3 olduğundan 0,02·(3÷2) = 0,03 mol hidrojen gazı oluşur."}],"ans":"0,54 g alüminyum 0,03 mol hidrojen gazı açığa çıkarır."},{"q":"4 NH₃ + 5 O₂ → 4 NO + 6 H₂O tepkimesinde 8 mol amonyaktan kaç mol NO ve kaç mol su oluşur?","fig":"<svg viewBox='0 0 320 110'><text x='6' y='50' font-size='12' fill='#1a2b45'>4NH₃ + 5O₂</text><text x='128' y='50' font-size='16' fill='#e0552b'>→</text><text x='162' y='50' font-size='12' fill='#1a2b45'>4NO + 6H₂O</text><text x='160' y='92' font-size='10' text-anchor='middle' fill='#5b6b85'>NH₃ : NO : H₂O = 4 : 4 : 6</text></svg>","steps":[{"t":"NO miktarı","a":"8 mol","d":"NH₃ : NO = 4 : 4 = 1 : 1 olduğundan 8 mol amonyak 8 mol NO verir."},{"t":"Su miktarı","a":"12 mol","d":"NH₃ : H₂O = 4 : 6 = 2 : 3 olduğundan 8·(6÷4) = 12 mol su oluşur."}],"ans":"8 mol amonyaktan 8 mol NO ve 12 mol su oluşur."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesinde 6,02·10²³ tane (1 mol) oksijen molekülü kaç gram su oluşturur?","steps":[{"t":"Oksijenin molü","a":"1 mol","d":"6,02·10²³ tane = 1 moldür (Avogadro sayısı); 1 mol oksijen demektir."},{"t":"Su kütlesi","a":"36 g","d":"O₂ : H₂O = 1 : 2 → 2 mol su. Su molmüktarı 18 g/mol; kütle = 2·18 = 36 g."}],"ans":"1 mol (6,02·10²³ tane) oksijen 2 mol, yani 36 g su oluşturur."}]}},"sinirlayiciBilesen":{"ilkokul":{"kolay":[{"q":"Sandviç yapmak için her sandviçte 2 dilim ekmek gerekiyor. 10 dilim ekmek ve 3 dilim peynir varsa, hangi malzeme önce biter gibi düşün: ekmek mi yoksa başka bir şey mi sınırlar?","steps":[{"t":"Eşleştir","a":"sayıyı karşılaştır","d":"Hangi malzemeden yetecek kadar var, hangisi azsa onu bulmak gerekir."},{"t":"Sonuç","a":"az olan biter","d":"En az olan malzeme önce biter ve kaç sandviç yapılacağını o belirler."}],"ans":"En az olan (yetersiz kalan) malzeme önce biter ve sonucu o belirler."},{"q":"Bir bisiklet 2 tekerlek ister. 10 tekerlek ve 3 gövde varsa kaç bisiklet yapılır?","steps":[{"t":"Tekerlekten","a":"5 bisiklet","d":"10 tekerlek ile 10 ÷ 2 = 5 bisiklet yapılabilir."},{"t":"Gövdeden","a":"3 bisiklet","d":"3 gövde ile en fazla 3 bisiklet yapılır. Daha az olan kazanır: 3 bisiklet."}],"ans":"3 bisiklet yapılır; gövde önce bittiği için sonucu gövde belirler."},{"q":"Bir çay için 1 poşet çay ve 1 bardak gerekiyor. 4 poşet çay, 6 bardak varsa kaç çay yapılır?","fig":"<svg viewBox='0 0 320 110'><rect x='30' y='35' width='30' height='40' fill='#cfd8e8' stroke='#1a2b45'/><text x='45' y='100' font-size='10' text-anchor='middle' fill='#5b6b85'>4 poşet</text><circle cx='180' cy='55' r='18' fill='#e0552b' fill-opacity='0.3' stroke='#1a2b45'/><text x='200' y='100' font-size='10' text-anchor='middle' fill='#5b6b85'>6 bardak</text></svg>","steps":[{"t":"Az olanı bul","a":"4 poşet","d":"Çay yapmak için poşet ve bardak gerekir; poşet 4, bardak 6'dır; az olan poşettir."},{"t":"Sonuç","a":"4 çay","d":"Poşet önce biteceği için en fazla 4 çay yapılabilir; 2 bardak boş kalır."}],"ans":"4 çay yapılır; poşet önce bittiği için sonucu o belirler, 2 bardak artar."},{"q":"Bir şeyden çok, başka bir şeyden az olunca artan (kalan) malzeme hangisidir?","steps":[{"t":"Kıyasla","a":"çok olan","d":"İki malzemeden biri yeterli, diğeri yetersizdir."},{"t":"Sonuç","a":"çok olan artar","d":"Az olan tükenir; çok olandan ise bir kısmı kullanılmadan artar (kalır)."}],"ans":"Çok (fazla) olan malzemeden bir kısmı kullanılmadan artar (kalır)."},{"q":"6 vida ve 10 tahta var. Her sandalye 3 vida ve 2 tahta ister. Hangisi önce biter?","steps":[{"t":"Vidadan","a":"2 sandalye","d":"6 vida ile 6 ÷ 3 = 2 sandalye yapılır."},{"t":"Tahtadan","a":"5 sandalye","d":"10 tahta ile 10 ÷ 2 = 5 sandalye yapılır. Az olan vidadır; 2 sandalye yapılır."}],"ans":"Vida önce biter; sadece 2 sandalye yapılır, sonucu vida belirler."}],"zor":[{"q":"Bir oyuncak araba 4 tekerlek ve 1 gövde ister. 20 tekerlek ve 6 gövde varsa kaç araba yapılır ve ne artar?","steps":[{"t":"Tekerlekten","a":"5 araba","d":"20 ÷ 4 = 5 araba yapılabilir."},{"t":"Gövdeden ve artan","a":"6 araba; tekerlek biter","d":"6 gövde ile 6 araba olur ama tekerlek 5'e yeter. Az olan tekerlektir; 5 araba olur, 1 gövde artar."}],"ans":"5 araba yapılır; tekerlek önce biter (sınırlar), 1 gövde artar."},{"q":"Her kek için 2 yumurta ve 3 bardak un gerekiyor. 10 yumurta, 9 bardak un varsa kaç kek olur?","steps":[{"t":"Yumurtadan","a":"5 kek","d":"10 ÷ 2 = 5 kek yapılabilir."},{"t":"Undan","a":"3 kek","d":"9 ÷ 3 = 3 kek yapılabilir. Az olan undur; 3 kek olur."}],"ans":"3 kek yapılır; un önce bittiği için sonucu un belirler."},{"q":"Hidrojen ve oksijen su yapar: 2 hidrojen tanesi 1 oksijen tanesi ister. 6 hidrojen, 5 oksijen tanesi varsa hangisi artar?","fig":"<svg viewBox='0 0 320 110'><circle cx='60' cy='55' r='14' fill='#cfd8e8' stroke='#1a2b45'/><text x='60' y='100' font-size='10' text-anchor='middle' fill='#5b6b85'>6 H₂</text><circle cx='200' cy='55' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='100' font-size='10' text-anchor='middle' fill='#5b6b85'>5 O₂</text></svg>","steps":[{"t":"Oran","a":"2 H₂ : 1 O₂","d":"6 hidrojen tanesi için 6 ÷ 2 = 3 oksijen gerekir."},{"t":"Artan","a":"oksijen artar","d":"3 oksijen yeter; elimizde 5 var. Hidrojen önce biter, 5 − 3 = 2 oksijen artar."}],"ans":"Hidrojen önce biter; 2 oksijen tanesi artar (kullanılmaz)."},{"q":"İki malzemeden hangisinin sınırlayıcı olduğunu anlamak için ne yapılır?","steps":[{"t":"Kaçar ürün","a":"ayrı ayrı hesapla","d":"Her malzemeyle kaç ürün yapılabileceği ayrı ayrı hesaplanır."},{"t":"En az olan","a":"sınırlayıcı","d":"En az ürün veren malzeme sınırlayıcıdır; o biter ve ürün miktarını o belirler."}],"ans":"Her malzemeyle kaç ürün çıkacağı hesaplanır; en az ürün veren sınırlayıcıdır."},{"q":"Her bardak limonata 2 limon ve 1 bardak su ister. 8 limon, 5 bardak su varsa kaç limonata olur ve ne artar?","steps":[{"t":"Limondan","a":"4 limonata","d":"8 ÷ 2 = 4 limonata yapılır."},{"t":"Sudan ve artan","a":"5; su artar","d":"5 su ile 5 limonata olur ama limon 4'e yeter. Limon sınırlar; 4 limonata olur, 1 bardak su artar."}],"ans":"4 limonata olur; limon sınırlayıcıdır, 1 bardak su artar."}]},"ortaokul":{"kolay":[{"q":"Sınırlayıcı bileşen (sınırlayıcı madde) nedir?","steps":[{"t":"Tanım","a":"önce biten madde","d":"Tepkimede ilk tükenen, yani sayısı yetersiz kalan girene sınırlayıcı bileşen denir."},{"t":"Etkisi","a":"ürünü belirler","d":"Tepkime sınırlayıcı bittiği anda durur; bu yüzden oluşacak ürün miktarını sınırlayıcı bileşen belirler."}],"ans":"Sınırlayıcı bileşen, tepkimede ilk tükenen ve ürün miktarını belirleyen girendir."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesine 6 mol H₂ ve 2 mol O₂ giriyor. Sınırlayıcı hangisidir?","steps":[{"t":"Gerekeni bul","a":"3 mol O₂ gerek","d":"6 mol H₂'nin tamamı için 6 ÷ 2 = 3 mol oksijen gerekir; ama sadece 2 mol var."},{"t":"Sonuç","a":"O₂ sınırlayıcı","d":"Oksijen yeterli değil, önce biter; bu yüzden oksijen sınırlayıcı bileşendir."}],"ans":"Oksijen (O₂) sınırlayıcıdır; 3 mol gerekirken 2 mol bulunduğundan önce biter."},{"q":"Sınırlayıcı bileşen bitince tepkimedeki diğer maddeye ne olur?","steps":[{"t":"Fazla madde","a":"artar","d":"Sınırlayıcı tükenince tepkime durur; ihtiyaçtan fazla olan diğer madde tepkimeye girmeden kalır."},{"t":"Adı","a":"artan madde","d":"Bu kullanılmadan kalan girene artan (fazla) madde denir."}],"ans":"İhtiyaçtan fazla olan diğer madde tepkimeye girmeden kalır; buna artan madde denir."},{"q":"N₂ + 3 H₂ → 2 NH₃ tepkimesine 2 mol N₂ ve 3 mol H₂ giriyor. Sınırlayıcı hangisidir?","fig":"<svg viewBox='0 0 320 110'><rect x='35' y='40' width='50' height='45' fill='#5b6b85' fill-opacity='0.3' stroke='#1a2b45'/><text x='60' y='100' font-size='10' text-anchor='middle' fill='#5b6b85'>2 mol N₂</text><rect x='190' y='40' width='50' height='45' fill='#cfd8e8' stroke='#1a2b45'/><text x='215' y='100' font-size='10' text-anchor='middle' fill='#5b6b85'>3 mol H₂</text></svg>","steps":[{"t":"H₂ gereksinimi","a":"6 mol gerek","d":"2 mol N₂'nin tamamı için 2·3 = 6 mol H₂ gerekir; ama sadece 3 mol var."},{"t":"Sonuç","a":"H₂ sınırlayıcı","d":"Hidrojen yetersizdir, önce biter; bu yüzden hidrojen sınırlayıcı bileşendir."}],"ans":"Hidrojen (H₂) sınırlayıcıdır; 6 mol gerekirken 3 mol bulunduğundan önce biter."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesine 4 mol H₂ ve 3 mol O₂ giriyor. Kaç mol oksijen artar?","steps":[{"t":"Harcanan O₂","a":"2 mol","d":"4 mol H₂ için H₂ : O₂ = 2 : 1 oranıyla 4 ÷ 2 = 2 mol oksijen harcanır."},{"t":"Artan","a":"1 mol","d":"3 mol oksijenin 2 molü harcanır; 3 − 2 = 1 mol oksijen artar (hidrojen sınırlayıcı)."}],"ans":"Hidrojen sınırlayıcıdır; 2 mol oksijen harcanır, 1 mol oksijen artar."}],"zor":[{"q":"CH₄ + 2 O₂ → CO₂ + 2 H₂O tepkimesine 3 mol CH₄ ve 4 mol O₂ giriyor. Sınırlayıcı bileşen hangisidir?","steps":[{"t":"O₂ gereksinimi","a":"6 mol gerek","d":"3 mol metanın tamamı için CH₄ : O₂ = 1 : 2 oranıyla 3·2 = 6 mol oksijen gerekir."},{"t":"Karşılaştır","a":"O₂ sınırlayıcı","d":"Sadece 4 mol oksijen var; 6 mol gerekirken yetmediği için oksijen önce biter, sınırlayıcıdır."}],"ans":"Oksijen (O₂) sınırlayıcıdır; 6 mol gerekirken 4 mol bulunduğundan önce biter."},{"q":"N₂ + 3 H₂ → 2 NH₃ tepkimesine 4 mol N₂ ve 9 mol H₂ giriyor. Sınırlayıcı ve oluşan amonyak kaç moldür?","steps":[{"t":"Mol oranıyla kıyas","a":"N₂'ye 12 mol H₂ gerek","d":"4 mol N₂ için 4·3 = 12 mol H₂ gerekir ama 9 mol var; H₂ yetmez, sınırlayıcıdır."},{"t":"Ürün hesabı","a":"6 mol NH₃","d":"Sınırlayıcı H₂'ye göre: H₂ : NH₃ = 3 : 2 → 9·(2÷3) = 6 mol amonyak oluşur."}],"ans":"Hidrojen sınırlayıcıdır; 6 mol amonyak oluşur (1 mol N₂ artar)."},{"q":"2 Na + Cl₂ → 2 NaCl tepkimesine 5 mol Na ve 2 mol Cl₂ giriyor. Sınırlayıcı hangisidir ve ne artar?","fig":"<svg viewBox='0 0 320 110'><circle cx='70' cy='55' r='18' fill='#e0552b' fill-opacity='0.4' stroke='#1a2b45'/><text x='70' y='100' font-size='10' text-anchor='middle' fill='#5b6b85'>5 mol Na</text><circle cx='200' cy='55' r='16' fill='#2b6be0' fill-opacity='0.3' stroke='#1a2b45'/><text x='200' y='100' font-size='10' text-anchor='middle' fill='#5b6b85'>2 mol Cl₂</text></svg>","steps":[{"t":"Cl₂ gereksinimi","a":"2,5 mol gerek","d":"5 mol Na için Na : Cl₂ = 2 : 1 oranıyla 5 ÷ 2 = 2,5 mol klor gerekir; ama 2 mol var."},{"t":"Sonuç ve artan","a":"Cl₂ sınırlayıcı","d":"Klor yetmez, sınırlayıcıdır. 2 mol Cl₂, 4 mol Na harcar; 5 − 4 = 1 mol sodyum artar."}],"ans":"Klor (Cl₂) sınırlayıcıdır; 1 mol sodyum artar, 4 mol NaCl oluşur."},{"q":"Bir tepkimede iki girenden hangisinin sınırlayıcı olduğu mol oranı karşılaştırmasıyla nasıl bulunur?","steps":[{"t":"Bölme yöntemi","a":"mol ÷ katsayı","d":"Her girenin mol sayısı kendi katsayısına bölünür."},{"t":"En küçük","a":"sınırlayıcı","d":"Bu bölümün sonucu en küçük çıkan giren sınırlayıcıdır; çünkü o, en az ürün verebilir."}],"ans":"Her girenin molü kendi katsayısına bölünür; sonucu en küçük olan giren sınırlayıcıdır."},{"q":"CH₄ + 2 O₂ → CO₂ + 2 H₂O tepkimesine 2 mol CH₄ ve 6 mol O₂ giriyor. Sınırlayıcı ve oluşan su kaç moldür?","steps":[{"t":"Bölerek kıyas","a":"CH₄ → 2, O₂ → 3","d":"Mol ÷ katsayı: CH₄ için 2 ÷ 1 = 2; O₂ için 6 ÷ 2 = 3. En küçük metandır; metan sınırlayıcıdır."},{"t":"Su hesabı","a":"4 mol","d":"Sınırlayıcı CH₄'e göre CH₄ : H₂O = 1 : 2 → 2·2 = 4 mol su oluşur (2 mol O₂ artar)."}],"ans":"Metan (CH₄) sınırlayıcıdır; 4 mol su oluşur ve 2 mol oksijen artar."}]},"lise":{"kolay":[{"q":"Sınırlayıcı bileşen kavramı neden gerçek tepkimeler için önemlidir?","steps":[{"t":"Gerçek koşul","a":"madde tam oranlı değil","d":"Pratikte girenler her zaman tam stokiyometrik oranda bulunmaz; biri eksik, biri fazla olabilir."},{"t":"Ürünü belirler","a":"sınırlayıcı","d":"Tepkime, sınırlayıcı bileşen tükenince durur; bu yüzden teorik ürün miktarı sınırlayıcıya göre hesaplanır."}],"ans":"Girenler tam oranlı olmadığından, ürün miktarını ilk tükenen (sınırlayıcı) bileşen belirler; bu nedenle önemlidir."},{"q":"Sınırlayıcı bileşen, girenlerin mol sayıları katsayılara bölünerek nasıl bulunur?","steps":[{"t":"Normalize et","a":"mol ÷ katsayı","d":"Her girenin mol sayısı, denklemdeki kendi katsayısına bölünerek 'kaç tepkime turu' yapabileceği bulunur."},{"t":"Karşılaştır","a":"en küçük sınırlar","d":"Bölüm değeri en küçük olan giren, en az tur yaptırabildiği için sınırlayıcıdır."}],"ans":"Her girenin molü katsayısına bölünür; bölüm en küçük çıkan giren sınırlayıcı bileşendir."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesine 4 mol H₂ ve 3 mol O₂ giriyor. Sınırlayıcıyı bul.","steps":[{"t":"Mol ÷ katsayı","a":"H₂ → 2, O₂ → 3","d":"H₂ için 4 ÷ 2 = 2; O₂ için 3 ÷ 1 = 3. En küçük değer hidrojendedir."},{"t":"Sonuç","a":"H₂ sınırlayıcı","d":"Bölüm en küçük (2) olduğundan hidrojen önce biter; sınırlayıcı bileşendir."}],"ans":"Hidrojen (H₂) sınırlayıcıdır; bölüm değeri (2) en küçük çıkmıştır."},{"q":"Sınırlayıcı bileşen tükendiğinde tepkimenin durmasının nedeni nedir?","steps":[{"t":"Eşleşme gereği","a":"oranlı tüketim","d":"Tepkime, girenleri sabit mol oranında tüketir; her tur için her girenden belirli miktar gerekir."},{"t":"Tükeniş","a":"durma","d":"Sınırlayıcı bittiğinde, fazla madde olsa bile onu eşleştirecek girene kalmadığı için tepkime durur."}],"ans":"Tepkime girenleri sabit oranda tükettiğinden, sınırlayıcı bitince onu eşleştirecek madde kalmaz ve tepkime durur."},{"q":"N₂ + 3 H₂ ⇌ 2 NH₃ tepkimesine 3 mol N₂ ve 6 mol H₂ giriyor. Sınırlayıcı hangisidir?","steps":[{"t":"Mol ÷ katsayı","a":"N₂ → 3, H₂ → 2","d":"N₂ için 3 ÷ 1 = 3; H₂ için 6 ÷ 3 = 2. En küçük değer hidrojendedir."},{"t":"Sonuç","a":"H₂ sınırlayıcı","d":"Bölüm en küçük (2) olduğundan hidrojen önce biter; sınırlayıcı bileşendir."}],"ans":"Hidrojen (H₂) sınırlayıcıdır; bölüm değeri (2) en küçük çıkmıştır."}],"zor":[{"q":"N₂ + 3 H₂ → 2 NH₃ tepkimesine 28 g azot (28 g/mol) ve 9 g hidrojen (2 g/mol) giriyor. Sınırlayıcıyı bul ve oluşan amonyak molünü hesapla.","steps":[{"t":"Mol hesabı","a":"N₂ 1 mol, H₂ 4,5 mol","d":"Azot: 28 ÷ 28 = 1 mol. Hidrojen: 9 ÷ 2 = 4,5 mol."},{"t":"Kıyas ve ürün","a":"N₂ sınırlayıcı, 2 mol NH₃","d":"Mol ÷ katsayı: N₂ → 1, H₂ → 1,5; en küçük N₂'dir (sınırlayıcı). N₂ : NH₃ = 1 : 2 → 1·2 = 2 mol amonyak oluşur (1,5 mol H₂ artar)."}],"ans":"Azot (N₂) sınırlayıcıdır; 2 mol amonyak oluşur ve 1,5 mol hidrojen artar."},{"q":"CH₄ + 2 O₂ → CO₂ + 2 H₂O tepkimesine 16 g metan (16 g/mol) ve 64 g oksijen (32 g/mol) giriyor. Sınırlayıcıyı bul ve oluşan CO₂ kütlesini hesapla.","steps":[{"t":"Mol hesabı","a":"CH₄ 1 mol, O₂ 2 mol","d":"Metan: 16 ÷ 16 = 1 mol. Oksijen: 64 ÷ 32 = 2 mol."},{"t":"Kıyas ve ürün","a":"tam oranlı, CO₂ 44 g","d":"Mol ÷ katsayı: CH₄ → 1, O₂ → 1; eşit olduğundan ikisi tam tükenir (artan yok). CH₄ : CO₂ = 1 : 1 → 1 mol CO₂ = 44 g."}],"ans":"Girenler tam stokiyometrik orandadır (artan yok); 1 mol, yani 44 g CO₂ oluşur."},{"q":"2 Al + 3 Cl₂ → 2 AlCl₃ tepkimesine 0,2 mol Al ve 0,5 mol Cl₂ giriyor. Sınırlayıcıyı bul ve artan maddenin molünü hesapla.","fig":"<svg viewBox='0 0 320 110'><circle cx='70' cy='52' r='17' fill='#5b6b85' fill-opacity='0.35' stroke='#1a2b45'/><text x='70' y='95' font-size='10' text-anchor='middle' fill='#5b6b85'>0,2 mol Al</text><circle cx='205' cy='52' r='17' fill='#2b6be0' fill-opacity='0.3' stroke='#1a2b45'/><text x='205' y='95' font-size='10' text-anchor='middle' fill='#5b6b85'>0,5 mol Cl₂</text></svg>","steps":[{"t":"Mol ÷ katsayı","a":"Al → 0,1; Cl₂ → 0,167","d":"Al için 0,2 ÷ 2 = 0,1; Cl₂ için 0,5 ÷ 3 ≈ 0,167. En küçük Al'dir; alüminyum sınırlayıcıdır."},{"t":"Artan Cl₂","a":"0,2 mol","d":"0,2 mol Al, Al : Cl₂ = 2 : 3 oranıyla 0,2·(3÷2) = 0,3 mol klor harcar; 0,5 − 0,3 = 0,2 mol klor artar."}],"ans":"Alüminyum (Al) sınırlayıcıdır; 0,3 mol klor harcanır, 0,2 mol Cl₂ artar."},{"q":"2 H₂ + O₂ → 2 H₂O tepkimesine NK'da 44,8 L hidrojen (mol = V/22,4) ve 1 mol oksijen giriyor. Sınırlayıcıyı bul ve oluşan su molünü hesapla.","steps":[{"t":"Mol hesabı","a":"H₂ 2 mol, O₂ 1 mol","d":"Hidrojen: 44,8 ÷ 22,4 = 2 mol. Oksijen 1 mol verilmiş."},{"t":"Kıyas ve ürün","a":"tam oranlı, 2 mol su","d":"Mol ÷ katsayı: H₂ → 1, O₂ → 1; eşit, ikisi de tam tükenir. H₂ : H₂O = 2 : 2 → 2 mol su oluşur, artan yoktur."}],"ans":"Girenler tam stokiyometrik orandadır (artan yok); 2 mol su oluşur."},{"q":"3 NaOH + H₃PO₄ → Na₃PO₄ + 3 H₂O tepkimesine 0,6 mol NaOH ve 0,3 mol H₃PO₄ giriyor. Sınırlayıcıyı bul.","steps":[{"t":"Mol ÷ katsayı","a":"NaOH → 0,2; H₃PO₄ → 0,3","d":"NaOH için 0,6 ÷ 3 = 0,2; H₃PO₄ için 0,3 ÷ 1 = 0,3. En küçük değer NaOH'dadır."},{"t":"Sonuç","a":"NaOH sınırlayıcı","d":"Bölüm en küçük (0,2) olduğundan NaOH önce biter; sınırlayıcıdır (0,1 mol H₃PO₄ artar)."}],"ans":"NaOH sınırlayıcıdır; bölüm değeri (0,2) en küçüktür ve 0,1 mol H₃PO₄ artar."}]}},"tepkimeOranlari":{"ilkokul":{"kolay":[{"q":"Bir kek tarifinde 2 yumurta için 1 bardak un gerekiyorsa, 4 yumurta için kaç bardak un gerekir?","steps":[{"t":"Oranı bul","a":"2 yumurta : 1 un","d":"Tarif 2 yumurta ile 1 bardak un ister; bu bir orandır."},{"t":"İki katına çıkar","a":"4 yumurta : 2 un","d":"Yumurta 2 katına çıkınca un da 2 katına çıkar; 4 yumurta için 2 bardak un gerekir."}],"ans":"4 yumurta için 2 bardak un gerekir (oran sabit kalır)."},{"q":"Tepkimedeki sayılar (katsayılar) bize ne söyler?","steps":[{"t":"Sayıların anlamı","a":"madde oranı","d":"Tepkimenin önündeki sayılar, maddelerin hangi oranda birleştiğini gösterir."},{"t":"Örnek düşün","a":"oran gibi","d":"Tıpkı tarifteki 2 yumurta 1 un gibi, maddeler de belli bir oranda birleşir."}],"ans":"Tepkimedeki sayılar (katsayılar) maddelerin hangi oranda birleştiğini gösterir."},{"q":"Su oluşurken 2 hidrojen ile 1 oksijen birleşiyorsa, 4 hidrojen kaç oksijenle birleşir?","fig":"<svg viewBox='0 0 320 120'><circle cx='40' cy='60' r='10' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='70' cy='60' r='10' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='65' font-size='16' fill='#1a2b45'>+</text><circle cx='130' cy='60' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='65' font-size='16' fill='#1a2b45'>→</text><text x='200' y='65' font-size='13' fill='#1a2b45'>2 H : 1 O</text></svg>","steps":[{"t":"Oranı yaz","a":"2 H : 1 O","d":"İki hidrojen bir oksijenle birleşir; oran 2 ye 1 dir."},{"t":"İki katına çıkar","a":"4 H : 2 O","d":"Hidrojen 2 katına çıkınca oksijen de 2 katına çıkar; 4 hidrojen 2 oksijenle birleşir."}],"ans":"4 hidrojen, 2 oksijenle birleşir (oran 2 ye 1 olarak korunur)."},{"q":"Bir araba yapmak için 4 tekerlek gerekiyorsa, 3 araba için kaç tekerlek gerekir?","steps":[{"t":"Oranı bul","a":"1 araba : 4 tekerlek","d":"Bir araba 4 tekerlek ister; bu bir orandır."},{"t":"3 katına çıkar","a":"3 × 4 = 12","d":"Üç araba için 3 × 4 = 12 tekerlek gerekir."}],"ans":"3 araba için 12 tekerlek gerekir (1 ye 4 oranıyla)."},{"q":"Bir tepkimede 1 birim A maddesi, 3 birim B maddesiyle birleşiyorsa, 2 birim A kaç birim B ister?","steps":[{"t":"Oranı yaz","a":"1 A : 3 B","d":"Bir birim A, üç birim B ile birleşir."},{"t":"2 katına çıkar","a":"2 A : 6 B","d":"A 2 katına çıkınca B de 2 katına çıkar; 2 A için 6 B gerekir."}],"ans":"2 birim A maddesi 6 birim B maddesiyle birleşir."}],"zor":[{"q":"2 hidrojen ile 1 oksijenden 2 su tanesi oluşuyorsa, 6 hidrojen kaç su tanesi yapar?","steps":[{"t":"Oranı yaz","a":"2 H → 2 su","d":"İki hidrojen, iki su tanesi yapar; yani hidrojen ile su oranı eşittir."},{"t":"6 ya çıkar","a":"6 su","d":"Hidrojen 6 olunca su da 6 olur; 6 hidrojen 6 su tanesi yapar."}],"ans":"6 hidrojen, 6 su tanesi oluşturur (hidrojen ile su oranı eşit olduğundan)."},{"q":"Bir tepkimede 2 birim X, 1 birim Y ile birleşip 2 birim Z veriyorsa, 8 birim X kaç birim Z verir?","steps":[{"t":"X ile Z oranı","a":"2 X : 2 Z","d":"İki X, iki Z verdiğinden X ile Z oranı 1 e 1 dir (eşittir)."},{"t":"8 e çıkar","a":"8 Z","d":"X 8 olunca Z de 8 olur; 8 birim X, 8 birim Z verir."}],"ans":"8 birim X maddesi 8 birim Z verir (X ile Z oranı eşittir)."},{"q":"Tarif 3 elma ile 2 muz isterse, elinizde 9 elma varken kaç muz gerekir?","fig":"<svg viewBox='0 0 300 110'><text x='40' y='55' font-size='13' fill='#1a2b45'>3 elma</text><text x='110' y='55' font-size='16' fill='#1a2b45'>:</text><text x='140' y='55' font-size='13' fill='#1a2b45'>2 muz</text><text x='40' y='90' font-size='13' fill='#e0552b'>9 elma</text><text x='110' y='90' font-size='16' fill='#1a2b45'>:</text><text x='140' y='90' font-size='13' fill='#e0552b'>? muz</text></svg>","steps":[{"t":"Kaç katı bul","a":"9 ÷ 3 = 3","d":"9 elma, 3 elmanın 3 katıdır."},{"t":"Muzu da 3 katına çıkar","a":"2 × 3 = 6","d":"Elma 3 katına çıktığı için muz da 3 katına çıkar; 2 × 3 = 6 muz gerekir."}],"ans":"9 elma için 6 muz gerekir (3 ye 2 oranıyla)."},{"q":"Bir tepkimede 1 birim A, 2 birim B ile birleşir. 5 birim A için kaç birim B gerekir?","steps":[{"t":"Oranı yaz","a":"1 A : 2 B","d":"Bir birim A iki birim B ister."},{"t":"5 katına çıkar","a":"5 × 2 = 10","d":"A 5 birim olunca B 5 × 2 = 10 birim olur."}],"ans":"5 birim A maddesi 10 birim B maddesiyle birleşir."},{"q":"2 araba ile 1 kamyon taşınıyorsa, 10 araba kaç kamyonla taşınır?","steps":[{"t":"Oranı yaz","a":"2 araba : 1 kamyon","d":"İki araba bir kamyona karşılık gelir; oran 2 ye 1 dir."},{"t":"Böl","a":"10 ÷ 2 = 5","d":"10 araba, 2 şer 2 şer 5 gruptur; her grup 1 kamyon ister, yani 5 kamyon gerekir."}],"ans":"10 araba için 5 kamyon gerekir (2 ye 1 oranıyla)."}]},"ortaokul":{"kolay":[{"q":"2H₂ + O₂ → 2H₂O tepkimesinde H₂, O₂ ve H₂O için mol oranı nedir?","fig":"<svg viewBox='0 0 320 90'><text x='10' y='50' font-size='15' fill='#1a2b45'>2H₂ + O₂ → 2H₂O</text><text x='10' y='80' font-size='13' fill='#e0552b'>oran: 2 : 1 : 2</text></svg>","steps":[{"t":"Katsayılara bak","a":"2, 1, 2","d":"Denklemdeki katsayılar H₂ için 2, O₂ için 1 (yazılmayan 1), H₂O için 2 dir."},{"t":"Oranı yaz","a":"2 : 1 : 2","d":"Bu katsayılar doğrudan mol oranını verir: H₂ : O₂ : H₂O = 2 : 1 : 2."}],"ans":"Denklem katsayıları mol oranıdır: H₂ : O₂ : H₂O = 2 : 1 : 2."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde 4 mol H₂ kaç mol O₂ ile tepkir?","steps":[{"t":"Oranı yaz","a":"2 H₂ : 1 O₂","d":"Katsayılara göre 2 mol H₂, 1 mol O₂ ile tepkir."},{"t":"Orantı kur","a":"4 ÷ 2 = 2","d":"4 mol H₂, 2 mol H₂ nin 2 katıdır; O₂ de 2 katına çıkar: 1 × 2 = 2 mol O₂."}],"ans":"4 mol H₂, 2 mol O₂ ile tepkir (2 ye 1 oranıyla)."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde 3 mol O₂ harcanırsa kaç mol H₂O oluşur?","steps":[{"t":"O₂ ile H₂O oranı","a":"1 : 2","d":"Katsayılara göre 1 mol O₂ den 2 mol H₂O oluşur."},{"t":"3 katına çıkar","a":"2 × 3 = 6","d":"3 mol O₂ kullanılırsa H₂O da 3 katına çıkar: 2 × 3 = 6 mol."}],"ans":"3 mol O₂ harcandığında 6 mol H₂O oluşur (1 ye 2 oranıyla)."},{"q":"N₂ + 3H₂ → 2NH₃ tepkimesinde N₂, H₂ ve NH₃ için mol oranı nedir?","steps":[{"t":"Katsayılar","a":"1, 3, 2","d":"N₂ için 1 (yazılmayan), H₂ için 3, NH₃ için 2 katsayısı vardır."},{"t":"Oranı yaz","a":"1 : 3 : 2","d":"Bu katsayılar mol oranını verir: N₂ : H₂ : NH₃ = 1 : 3 : 2."}],"ans":"Mol oranı N₂ : H₂ : NH₃ = 1 : 3 : 2 dir."},{"q":"2Na + Cl₂ → 2NaCl tepkimesinde 1 mol Cl₂ kaç mol NaCl verir?","steps":[{"t":"Cl₂ ile NaCl oranı","a":"1 : 2","d":"Katsayılara göre 1 mol Cl₂ den 2 mol NaCl oluşur."},{"t":"Yerine koy","a":"2 mol","d":"1 mol Cl₂ doğrudan 2 mol NaCl verir."}],"ans":"1 mol Cl₂, 2 mol NaCl verir (1 ye 2 oranıyla)."}],"zor":[{"q":"CH₄ + 2O₂ → CO₂ + 2H₂O tepkimesinde 5 mol CH₄ tam yandığında kaç mol O₂ harcanır?","fig":"<svg viewBox='0 0 320 90'><text x='10' y='45' font-size='14' fill='#1a2b45'>CH₄ + 2O₂ → CO₂ + 2H₂O</text><text x='10' y='75' font-size='13' fill='#e0552b'>CH₄ : O₂ = 1 : 2</text></svg>","steps":[{"t":"CH₄ ile O₂ oranı","a":"1 : 2","d":"Katsayılara göre 1 mol CH₄, 2 mol O₂ ile yanar."},{"t":"5 katına çıkar","a":"2 × 5 = 10","d":"5 mol CH₄ için O₂ de 5 katına çıkar: 2 × 5 = 10 mol O₂ harcanır."}],"ans":"5 mol CH₄ tam yandığında 10 mol O₂ harcanır (1 ye 2 oranıyla)."},{"q":"N₂ + 3H₂ → 2NH₃ tepkimesinde 6 mol H₂ tepkirse kaç mol NH₃ oluşur?","steps":[{"t":"H₂ ile NH₃ oranı","a":"3 : 2","d":"Katsayılara göre 3 mol H₂ den 2 mol NH₃ oluşur."},{"t":"Orantı kur","a":"6 ÷ 3 = 2","d":"6 mol H₂, 3 mol H₂ nin 2 katıdır; NH₃ de 2 katına çıkar: 2 × 2 = 4 mol."}],"ans":"6 mol H₂ tepkidiğinde 4 mol NH₃ oluşur (3 ye 2 oranıyla)."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde 5 mol H₂ ile 2 mol O₂ karıştırılıyor. Kaç mol H₂O oluşur ve hangi madde artar?","steps":[{"t":"Gerekli O₂ yi bul","a":"2,5 mol","d":"5 mol H₂ için gereken O₂, 5 ÷ 2 = 2,5 mol olmalıdır; ama elimizde 2 mol O₂ var, demek ki O₂ sınırlayıcıdır."},{"t":"O₂ ye göre hesapla","a":"4 mol H₂O","d":"2 mol O₂, 2 ye 2 oranıyla 4 mol H₂O verir ve bu sırada 4 mol H₂ harcanır; 1 mol H₂ artar."}],"ans":"4 mol H₂O oluşur; O₂ sınırlayıcı olduğundan 1 mol H₂ artar."},{"q":"2Na + Cl₂ → 2NaCl tepkimesinde 0,5 mol Cl₂ ile tepkimeye kaç mol Na girer?","steps":[{"t":"Na ile Cl₂ oranı","a":"2 : 1","d":"Katsayılara göre 2 mol Na, 1 mol Cl₂ ile tepkir."},{"t":"Yarıya indir","a":"2 × 0,5 = 1","d":"0,5 mol Cl₂, 1 mol Cl₂ nin yarısıdır; Na da yarıya iner: 2 × 0,5 = 1 mol Na."}],"ans":"0,5 mol Cl₂ için 1 mol Na tepkimeye girer (2 ye 1 oranıyla)."},{"q":"CaCO₃ → CaO + CO₂ tepkimesinde 4 mol CaCO₃ ayrışırsa kaç mol CO₂ açığa çıkar?","steps":[{"t":"Oranı yaz","a":"1 : 1","d":"Katsayılar 1 : 1 : 1 dir; 1 mol CaCO₃ den 1 mol CO₂ oluşur."},{"t":"4 katına çıkar","a":"4 mol","d":"4 mol CaCO₃ ayrışınca eşit oranda 4 mol CO₂ açığa çıkar."}],"ans":"4 mol CaCO₃ ayrıştığında 4 mol CO₂ açığa çıkar (1 ye 1 oranıyla)."}]},"lise":{"kolay":[{"q":"Bir tepkime denkleminin katsayıları neyi ifade eder ve neden mol oranı olarak kullanılır?","steps":[{"t":"Katsayının anlamı","a":"tanecik/mol oranı","d":"Denkleştirilmiş bir tepkimede katsayılar, maddelerin birbirine göre tepkime tanecik sayısı oranını gösterir."},{"t":"Mole geçiş","a":"oran korunur","d":"Tanecik oranı sabit olduğundan aynı oran mol cinsinden de geçerlidir; bu yüzden katsayılar doğrudan mol oranı olarak kullanılır."}],"ans":"Denkleştirilmiş tepkimenin katsayıları tanecik oranını verir; bu oran mol cinsinden de korunduğundan katsayılar mol oranı olarak kullanılır."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde 0,8 mol O₂ tam tepkirse kaç mol H₂O oluşur?","steps":[{"t":"O₂ ile H₂O oranı","a":"1 : 2","d":"Katsayılara göre 1 mol O₂ den 2 mol H₂O oluşur."},{"t":"Yerine koy","a":"2 × 0,8 = 1,6","d":"0,8 mol O₂ için H₂O miktarı 2 × 0,8 = 1,6 mol olur."}],"ans":"0,8 mol O₂ tepkidiğinde 1,6 mol H₂O oluşur (1 ye 2 oranıyla)."},{"q":"CH₄ + 2O₂ → CO₂ + 2H₂O tepkimesinde 3 mol CH₄ yandığında kaç mol CO₂ ve kaç mol H₂O oluşur?","fig":"<svg viewBox='0 0 330 100'><text x='10' y='40' font-size='14' fill='#1a2b45'>CH₄ + 2O₂ → CO₂ + 2H₂O</text><text x='10' y='70' font-size='12' fill='#e0552b'>CH₄ : CO₂ : H₂O = 1 : 1 : 2</text></svg>","steps":[{"t":"Oranları yaz","a":"1 : 1 : 2","d":"Katsayılara göre CH₄ : CO₂ : H₂O = 1 : 1 : 2 dir."},{"t":"3 katına çıkar","a":"CO₂ = 3, H₂O = 6","d":"3 mol CH₄ için CO₂ = 1 × 3 = 3 mol, H₂O = 2 × 3 = 6 mol oluşur."}],"ans":"3 mol CH₄ yandığında 3 mol CO₂ ve 6 mol H₂O oluşur."},{"q":"N₂ + 3H₂ → 2NH₃ tepkimesinde 2 mol NH₃ üretmek için kaç mol N₂ ve kaç mol H₂ gerekir?","steps":[{"t":"NH₃ ye göre oran","a":"N₂:H₂:NH₃ = 1:3:2","d":"Katsayılara göre 2 mol NH₃ için 1 mol N₂ ve 3 mol H₂ gerekir."},{"t":"Doğrudan oku","a":"1 mol N₂, 3 mol H₂","d":"2 mol NH₃, katsayıyla birebir uyduğundan 1 mol N₂ ve 3 mol H₂ gerekir."}],"ans":"2 mol NH₃ için 1 mol N₂ ve 3 mol H₂ gerekir (1 : 3 : 2 oranıyla)."},{"q":"2Na + Cl₂ → 2NaCl tepkimesinde 4 mol Na tam tepkirse kaç mol Cl₂ harcanır ve kaç mol NaCl oluşur?","steps":[{"t":"Oranları yaz","a":"Na:Cl₂:NaCl = 2:1:2","d":"Katsayılara göre 2 mol Na, 1 mol Cl₂ ile 2 mol NaCl verir."},{"t":"2 katına çıkar","a":"Cl₂=2, NaCl=4","d":"4 mol Na için Cl₂ = 1 × 2 = 2 mol, NaCl = 2 × 2 = 4 mol olur."}],"ans":"4 mol Na için 2 mol Cl₂ harcanır ve 4 mol NaCl oluşur."}],"zor":[{"q":"4Fe + 3O₂ → 2Fe₂O₃ tepkimesinde 0,6 mol O₂ tam tepkirse kaç mol Fe harcanır ve kaç mol Fe₂O₃ oluşur?","fig":"<svg viewBox='0 0 330 100'><text x='10' y='40' font-size='14' fill='#1a2b45'>4Fe + 3O₂ → 2Fe₂O₃</text><text x='10' y='70' font-size='12' fill='#e0552b'>Fe : O₂ : Fe₂O₃ = 4 : 3 : 2</text></svg>","steps":[{"t":"Oranı kur","a":"Fe:O₂ = 4:3","d":"Katsayılara göre 3 mol O₂, 4 mol Fe ile tepkir; 0,6 mol O₂ için Fe = (4/3) × 0,6 = 0,8 mol."},{"t":"Fe₂O₃ yi bul","a":"(2/3) × 0,6 = 0,4","d":"O₂ ile Fe₂O₃ oranı 3 : 2 dir; Fe₂O₃ = (2/3) × 0,6 = 0,4 mol oluşur."}],"ans":"0,6 mol O₂ için 0,8 mol Fe harcanır ve 0,4 mol Fe₂O₃ oluşur."},{"q":"N₂ + 3H₂ → 2NH₃ tepkimesinde 2 mol N₂ ile 9 mol H₂ karıştırılıyor. Hangi madde sınırlayıcıdır ve kaç mol NH₃ oluşur?","steps":[{"t":"Gerekli H₂ yi bul","a":"6 mol","d":"2 mol N₂ için gereken H₂, 3 ye 1 oranıyla 3 × 2 = 6 mol olmalıdır; elimizde 9 mol H₂ var, fazlasıyla yeterli, o yüzden N₂ sınırlayıcıdır."},{"t":"N₂ ye göre hesapla","a":"4 mol NH₃","d":"N₂ ile NH₃ oranı 1 : 2 olduğundan 2 mol N₂ den 2 × 2 = 4 mol NH₃ oluşur (3 mol H₂ artar)."}],"ans":"N₂ sınırlayıcıdır; 2 mol N₂ den 4 mol NH₃ oluşur ve 3 mol H₂ artar."},{"q":"2C₂H₆ + 7O₂ → 4CO₂ + 6H₂O tepkimesinde 1,5 mol C₂H₆ tam yandığında oluşan CO₂ ve H₂O mol sayıları nedir?","fig":"<svg viewBox='0 0 340 100'><text x='8' y='40' font-size='13' fill='#1a2b45'>2C₂H₆ + 7O₂ → 4CO₂ + 6H₂O</text><text x='8' y='72' font-size='12' fill='#e0552b'>C₂H₆ : CO₂ : H₂O = 2 : 4 : 6</text></svg>","steps":[{"t":"CO₂ yi bul","a":"3 mol","d":"C₂H₆ ile CO₂ oranı 2 : 4 yani 1 : 2 dir; 1,5 mol C₂H₆ için CO₂ = 2 × 1,5 = 3 mol."},{"t":"H₂O yu bul","a":"4,5 mol","d":"C₂H₆ ile H₂O oranı 2 : 6 yani 1 : 3 tür; H₂O = 3 × 1,5 = 4,5 mol oluşur."}],"ans":"1,5 mol C₂H₆ yandığında 3 mol CO₂ ve 4,5 mol H₂O oluşur."},{"q":"2KClO₃ → 2KCl + 3O₂ tepkimesinde 0,4 mol KClO₃ ısıtılarak tamamen ayrışırsa kaç mol O₂ açığa çıkar?","steps":[{"t":"Oranı kur","a":"KClO₃:O₂ = 2:3","d":"Katsayılara göre 2 mol KClO₃ den 3 mol O₂ oluşur."},{"t":"Orantı uygula","a":"(3/2) × 0,4 = 0,6","d":"0,4 mol KClO₃ için O₂ = (3/2) × 0,4 = 0,6 mol açığa çıkar."}],"ans":"0,4 mol KClO₃ tamamen ayrıştığında 0,6 mol O₂ açığa çıkar (2 ye 3 oranıyla)."},{"q":"3H₂ + N₂ → 2NH₃ tepkimesinde mol oranı korunurken kütlenin de korunduğu nasıl gösterilir? (H=1, N=14)","steps":[{"t":"Mol oranı","a":"3 : 1 : 2","d":"Katsayılar mol oranını verir; 3 mol H₂, 1 mol N₂ ile 2 mol NH₃ oluşturur."},{"t":"Kütleyi kontrol et","a":"34 g = 34 g","d":"Girenler: 3 × 2 + 1 × 28 = 6 + 28 = 34 g; ürün: 2 × 17 = 34 g. Mol oranı katsayılarla, kütle ise eşitlikle korunur."}],"ans":"Katsayılar mol oranını (3 : 1 : 2) verir; girenlerin kütlesi 34 g ürünün kütlesi 34 g olduğundan kütle de korunur."}]}},"verimHesabi":{"ilkokul":{"kolay":[{"q":"Annen hamurdan 20 kurabiye çıkmasını bekliyordu ama fırından 18 kurabiye çıktı. Beklenenin yüzde kaçı gerçekleşti?","fig":"<svg viewBox='0 0 320 130'><circle cx='60' cy='50' r='14' fill='#e0552b'/><circle cx='100' cy='50' r='14' fill='#e0552b'/><circle cx='140' cy='50' r='14' fill='#e0552b'/><text x='100' y='95' font-size='11' text-anchor='middle' fill='#1a2b45'>18 / 20 kurabiye</text></svg>","steps":[{"t":"Oranı kur","a":"18 ÷ 20","d":"Gerçekleşeni beklenene böleriz: 18 ÷ 20 = 0,9 olur."},{"t":"Yüzdeye çevir","a":"%90","d":"0,9 sayısını 100 ile çarparız: 0,9 × 100 = 90, yani verim %90 olur."}],"ans":"18 kurabiye 20'nin yüzde 90'ıdır; yani verim %90 olmuştur."},{"q":"Bir sınıf 50 kâğıt uçak yapmayı planladı ama yalnızca 25 tane bitirebildi. Planın yüzde kaçı tamamlandı?","steps":[{"t":"Oranı kur","a":"25 ÷ 50","d":"Yapılanı planlanana böleriz: 25 ÷ 50 = 0,5 çıkar."},{"t":"Yüzdeye çevir","a":"%50","d":"0,5 × 100 = 50, yani planın yarısı, yüzde 50'si tamamlanmıştır."}],"ans":"25 uçak 50'nin yarısıdır; plan yüzde 50 oranında tamamlanmıştır."},{"q":"Limonatadan 10 bardak çıkması bekleniyordu, 10 bardak çıktı. Bu işin verimi yüzde kaçtır?","steps":[{"t":"Oranı kur","a":"10 ÷ 10","d":"Çıkan miktarı beklenen miktara böleriz: 10 ÷ 10 = 1 olur."},{"t":"Yüzdeye çevir","a":"%100","d":"1 × 100 = 100, yani hiç kayıp yok, verim tam yüzde 100'dür."}],"ans":"Beklenen kadar çıktığı için kayıp yoktur; verim yüzde 100'dür."},{"q":"Verim 'beklenenin ne kadarını elde ettik' demektir. Daha çok kayıp olunca verim yüzdesi artar mı azalır mı?","steps":[{"t":"Kayıp nedir","a":"elde edemediğimiz","d":"Kayıp, beklediğimiz ama gerçekte elde edemediğimiz kısımdır."},{"t":"Etkisi","a":"verim azalır","d":"Kayıp arttıkça elimizde kalan azalır, bu yüzden verim yüzdesi de azalır."}],"ans":"Kayıp arttıkça elde ettiğimiz azalır; bu yüzden verim yüzdesi azalır."},{"q":"Bir fabrikada 100 oyuncaktan 80'i sağlam çıktı, 20'si bozuktu. Sağlam oyuncakların verimi yüzde kaçtır?","fig":"<svg viewBox='0 0 320 120'><rect x='40' y='40' width='160' height='30' fill='#2b6be0'/><rect x='200' y='40' width='40' height='30' fill='#cfd8e8' stroke='#1a2b45'/><text x='120' y='95' font-size='11' text-anchor='middle' fill='#1a2b45'>80 sağlam</text><text x='220' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>20 bozuk</text></svg>","steps":[{"t":"Oranı kur","a":"80 ÷ 100","d":"Sağlam çıkanı toplam beklenene böleriz: 80 ÷ 100 = 0,8 olur."},{"t":"Yüzdeye çevir","a":"%80","d":"0,8 × 100 = 80, yani sağlam oyuncak verimi yüzde 80'dir."}],"ans":"80 sağlam oyuncak 100'ün yüzde 80'idir; verim %80'dir."}],"zor":[{"q":"Bir pasta tarifinden 24 dilim çıkması bekleniyordu ama 18 dilim çıktı. Verim yüzde kaçtır?","steps":[{"t":"Oranı kur","a":"18 ÷ 24","d":"Gerçekleşeni beklenene böleriz: 18 ÷ 24 = 0,75 olur."},{"t":"Yüzdeye çevir","a":"%75","d":"0,75 × 100 = 75, yani verim yüzde 75'tir; dörtte üçü elde edilmiştir."}],"ans":"18 dilim 24'ün dörtte üçüdür; verim %75'tir."},{"q":"İki arkadaştan biri planının %90'ını, diğeri %60'ını tamamladı. Hangisinin verimi daha yüksektir ve bu ne anlama gelir?","steps":[{"t":"Karşılaştır","a":"%90 > %60","d":"90 sayısı 60'tan büyüktür, bu yüzden ilk arkadaşın verimi daha yüksektir."},{"t":"Anlamı","a":"daha az kayıp","d":"Yüksek verim, planlanana daha yakın sonuç ve daha az kayıp demektir."}],"ans":"İlk arkadaşın verimi (%90) daha yüksektir; bu, planına daha yakın sonuç aldığı ve daha az kaybı olduğu anlamına gelir."},{"q":"Bir bahçeden 40 kg domates beklenirken kuraklık yüzünden 30 kg toplandı. Verimi bulup kayıp yüzdesini söyleyiniz.","fig":"<svg viewBox='0 0 320 120'><circle cx='70' cy='55' r='12' fill='#e0552b'/><circle cx='105' cy='55' r='12' fill='#e0552b'/><circle cx='140' cy='55' r='12' fill='#e0552b'/><circle cx='180' cy='55' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='125' y='100' font-size='11' text-anchor='middle' fill='#1a2b45'>30 / 40 kg</text></svg>","steps":[{"t":"Verimi bul","a":"30 ÷ 40","d":"Toplananı beklenene böleriz: 30 ÷ 40 = 0,75; yüzdeye çevirince %75 verim."},{"t":"Kaybı bul","a":"%25","d":"Tamamı %100 olduğundan kayıp 100 − 75 = %25'tir."}],"ans":"Verim %75'tir; kalan %25 ise kuraklık nedeniyle kayıptır."},{"q":"Bir öğrenci 200 boncuktan bileklik yapacaktı ama 150 boncuk kullanabildi. Verim yüzde kaçtır ve kaç boncuk işe yaramadı?","steps":[{"t":"Verimi bul","a":"150 ÷ 200","d":"Kullanılanı planlanana böleriz: 150 ÷ 200 = 0,75; yani %75 verim."},{"t":"Artan boncuk","a":"50 boncuk","d":"200 − 150 = 50 boncuk kullanılamamış, yani işe yaramamıştır."}],"ans":"Verim %75'tir; 200 − 150 = 50 boncuk kullanılamamıştır."},{"q":"Bir limonatacı 1 limondan 2 bardak yapmayı planlıyor. 10 limon kullandı ama 16 bardak çıktı. Verim yüzde kaçtır?","steps":[{"t":"Beklenen miktar","a":"20 bardak","d":"10 limon × 2 bardak = 20 bardak çıkması beklenir; bu teorik (beklenen) miktardır."},{"t":"Verimi bul","a":"16 ÷ 20","d":"Gerçek çıkanı beklenene böleriz: 16 ÷ 20 = 0,8; yani verim %80'dir."}],"ans":"Beklenen 20 bardaktı; 16 bardak çıktığı için verim 16 ÷ 20 = %80'dir."}]},"ortaokul":{"kolay":[{"q":"Verim hesabında 'teorik ürün' ve 'gerçek ürün' ne anlama gelir?","steps":[{"t":"Teorik ürün","a":"beklenen en çok","d":"Teorik ürün, tepkimenin hesapça verebileceği en yüksek (beklenen) ürün miktarıdır."},{"t":"Gerçek ürün","a":"deneyde elde edilen","d":"Gerçek ürün ise deneyi yaptığımızda elimize geçen, çoğunlukla kayıplar nedeniyle daha az olan miktardır."}],"ans":"Teorik ürün hesapça beklenen en yüksek miktar, gerçek ürün ise deneyde gerçekten elde edilen miktardır."},{"q":"Bir tepkimede teorik olarak 50 g ürün beklenirken 40 g elde edildi. Yüzde verim kaçtır?","fig":"<svg viewBox='0 0 320 120'><text x='160' y='28' font-size='11' text-anchor='middle' fill='#1a2b45'>verim = gerçek / teorik × 100</text><rect x='50' y='50' width='160' height='26' fill='#2b6be0'/><rect x='210' y='50' width='40' height='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='130' y='100' font-size='11' text-anchor='middle' fill='#1a2b45'>40 g / 50 g</text></svg>","steps":[{"t":"Formül","a":"gerçek/teorik×100","d":"Yüzde verim = (gerçek ürün ÷ teorik ürün) × 100 bağıntısıyla bulunur."},{"t":"Yerine koy","a":"%80","d":"(40 ÷ 50) × 100 = 0,8 × 100 = 80, yani verim %80'dir."}],"ans":"(40 ÷ 50) × 100 = %80; tepkimenin verimi yüzde 80'dir."},{"q":"Yüzde verim formülü nedir ve neden hiçbir zaman %100'ü geçmez?","steps":[{"t":"Formül","a":"(gerçek/teorik)×100","d":"Yüzde verim = (gerçek ürün ÷ teorik ürün) × 100 olarak tanımlanır."},{"t":"Neden ≤ %100","a":"gerçek ≤ teorik","d":"Gerçek ürün, hesaplanan teorik üründen fazla olamaz; kayıplar nedeniyle ona eşit ya da daha az olur, bu yüzden verim %100'ü geçmez."}],"ans":"Yüzde verim = (gerçek ürün ÷ teorik ürün) × 100'dür; gerçek ürün teoriği aşamadığından verim %100'ü geçmez."},{"q":"Bir tepkimede gerçek ürün, teorik ürüne tam olarak eşit çıkarsa verim kaç olur?","steps":[{"t":"Eşitlik","a":"gerçek = teorik","d":"Gerçek ürün teorik ürüne eşitse oran tam 1 olur."},{"t":"Yüzde","a":"%100","d":"1 × 100 = 100, yani hiç kayıp olmadığını gösteren ideal %100 verim elde edilir."}],"ans":"Gerçek ürün teoriğe eşitse verim %100'dür; bu kaybın olmadığı ideal durumu gösterir."},{"q":"Verimin %100 olmamasının başlıca nedenleri nelerdir?","steps":[{"t":"Kayıplar","a":"yan tepkime, kaçak","d":"Maddenin bir kısmı yan tepkimelere girebilir, kaplarda kalabilir ya da süzme-aktarmada kaybolabilir."},{"t":"Eksik tepkime","a":"tam dönüşmeme","d":"Tepkenlerin tümü ürüne dönüşmeyebilir; bu nedenlerle gerçek ürün teoriğin altında kalır."}],"ans":"Yan tepkimeler, madde kaçakları, aktarma kayıpları ve tepkimenin tam tamamlanmaması verimi %100'ün altına indirir."}],"zor":[{"q":"Bir tepkimede teorik ürün 80 g, elde edilen gerçek ürün 60 g'dır. Yüzde verimi hesaplayınız.","steps":[{"t":"Formülü yaz","a":"(gerçek/teorik)×100","d":"Yüzde verim = (gerçek ürün ÷ teorik ürün) × 100 bağıntısı kullanılır."},{"t":"Yerine koy","a":"%75","d":"(60 ÷ 80) × 100 = 0,75 × 100 = 75; tepkimenin verimi %75'tir."}],"ans":"(60 ÷ 80) × 100 = %75; tepkimenin yüzde verimi 75'tir."},{"q":"Bir tepkimenin teorik ürünü 200 g, verimi %90 ise gerçekte kaç gram ürün elde edilir?","steps":[{"t":"İlişkiyi kur","a":"gerçek = verim×teorik","d":"Yüzde verim formülünden gerçek ürün = (verim ÷ 100) × teorik ürün olarak çekilir."},{"t":"Yerine koy","a":"180 g","d":"(90 ÷ 100) × 200 = 0,9 × 200 = 180 g gerçek ürün elde edilir."}],"ans":"Gerçek ürün = 0,90 × 200 = 180 g; verim %90 olduğunda 180 g ürün elde edilir."},{"q":"2H₂ + O₂ → 2H₂O tepkimesinde teorik olarak 36 g su beklenirken 27 g su elde edildi. Verim yüzde kaçtır?","fig":"<svg viewBox='0 0 320 120'><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>2H₂ + O₂ → 2H₂O</text><rect x='50' y='48' width='150' height='26' fill='#2b6be0'/><rect x='200' y='48' width='50' height='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='140' y='98' font-size='11' text-anchor='middle' fill='#1a2b45'>27 g / 36 g su</text></svg>","steps":[{"t":"Teorik ve gerçek","a":"36 g ve 27 g","d":"Hesapça beklenen teorik su 36 g, deneyde elde edilen gerçek su ise 27 g'dır."},{"t":"Verimi bul","a":"%75","d":"(27 ÷ 36) × 100 = 0,75 × 100 = 75; suyun elde ediliş verimi %75'tir."}],"ans":"(27 ÷ 36) × 100 = %75; tepkimede suyun verimi yüzde 75'tir."},{"q":"C + O₂ → CO₂ tepkimesinde 12 g karbon tam yanarsa teorik olarak 44 g CO₂ beklenir. Gerçekte 33 g CO₂ oluşursa verim kaçtır? (C=12, O=16)","steps":[{"t":"Teorik ürün","a":"44 g CO₂","d":"12 g karbon (1 mol) tam yanınca 1 mol, yani 44 g CO₂ oluşması beklenir; bu teorik üründür."},{"t":"Verimi bul","a":"%75","d":"(33 ÷ 44) × 100 = 0,75 × 100 = 75; tepkimenin verimi %75'tir."}],"ans":"Teorik 44 g CO₂'ye karşılık 33 g elde edildiğinden verim (33 ÷ 44) × 100 = %75'tir."},{"q":"Bir tepkimenin verimi %80 ve gerçekte 48 g ürün elde edilmiştir. Teorik ürün kaç gramdır?","steps":[{"t":"İlişkiyi kur","a":"teorik = gerçek/verim","d":"Yüzde verim = (gerçek ÷ teorik) × 100 olduğundan teorik ürün = gerçek ÷ (verim ÷ 100) olur."},{"t":"Yerine koy","a":"60 g","d":"48 ÷ (80 ÷ 100) = 48 ÷ 0,8 = 60 g; teorik ürün 60 gramdır."}],"ans":"Teorik ürün = 48 ÷ 0,80 = 60 g; %80 verimle 48 g elde edildiğine göre teorik 60 gramdır."}]},"lise":{"kolay":[{"q":"Yüzde verim kavramını tanımlayıp teorik verim ile gerçek verim arasındaki farkı açıklayınız.","steps":[{"t":"Tanım","a":"(gerçek/teorik)×100","d":"Yüzde verim, gerçek ürün miktarının teorik ürün miktarına oranının yüzdesidir: % verim = (gerçek ürün ÷ teorik ürün) × 100."},{"t":"Fark","a":"hesap vs deney","d":"Teorik verim, sınırlayıcı bileşene göre stokiyometriyle hesaplanan en yüksek üründür; gerçek verim ise deneyde fiilen elde edilen ve kayıplar nedeniyle daha düşük olan miktardır."}],"ans":"Yüzde verim = (gerçek ürün ÷ teorik ürün) × 100'dür; teorik verim hesapla bulunan en yüksek miktar, gerçek verim ise deneyde elde edilen ve genellikle daha az olan miktardır."},{"q":"N₂ + 3H₂ ⇌ 2NH₃ tepkimesinde teorik olarak 34 g NH₃ beklenirken 23,8 g elde edildi. Yüzde verim kaçtır? (N=14, H=1)","fig":"<svg viewBox='0 0 320 120'><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>N₂ + 3H₂ ⇌ 2NH₃</text><rect x='50' y='50' width='140' height='24' fill='#2b6be0'/><rect x='190' y='50' width='60' height='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='150' y='98' font-size='11' text-anchor='middle' fill='#1a2b45'>23,8 g / 34 g NH₃</text></svg>","steps":[{"t":"Teorik ve gerçek","a":"34 g ve 23,8 g","d":"Teorik amonyak 34 g (2 mol × 17 g/mol), deneyde elde edilen gerçek amonyak 23,8 g'dır."},{"t":"Verimi bul","a":"%70","d":"(23,8 ÷ 34) × 100 = 0,7 × 100 = 70; amonyak sentezinin verimi %70'tir."}],"ans":"(23,8 ÷ 34) × 100 = %70; amonyak sentezinin yüzde verimi 70'tir."},{"q":"Yüzde verimin teorik üst sınırının %100 olmasının nedeni nedir; gerçek verim teoriği neden aşamaz?","steps":[{"t":"Teorik tanım","a":"maksimum ürün","d":"Teorik ürün, kütlenin korunumu ve stokiyometri gereği tepkenlerden oluşabilecek en yüksek üründür."},{"t":"Üst sınır","a":"gerçek ≤ teorik","d":"Gerçek ürün, var olan atomlardan fazlasını içeremeyeceğinden teoriği aşamaz; bu nedenle yüzde verim en çok %100 olur, ölçüm fazlası ürün safsızlık/kuru bırakılmama gibi hatalardan gelir."}],"ans":"Teorik ürün kütle korunumuyla belirlenen maksimumdur; gerçek ürün var olan atomdan fazlasını içeremeyeceği için teoriği aşamaz, dolayısıyla verim en çok %100'dür."},{"q":"Verimi %100'ün altına çeken laboratuvar kaynaklı başlıca kayıp türlerini açıklayınız.","steps":[{"t":"Tepkime kaynaklı","a":"yan tepkime, denge","d":"Tepkenlerin bir kısmı istenmeyen yan ürünlere dönüşebilir ya da denge tepkimesi tam tamamlanmadan dengeye ulaşır."},{"t":"İşlem kaynaklı","a":"aktarma, süzme, çözünme","d":"Süzme, kristallendirme, aktarma sırasında madde kaybı olur; ürünün bir kısmı çözücüde kalabilir. Bu kayıpların tümü gerçek ürünü azaltır."}],"ans":"Yan tepkimeler ve tamamlanmamış denge ile süzme, aktarma, çözücüde kalma gibi işlem kayıpları gerçek ürünü azaltarak verimi %100'ün altına indirir."},{"q":"CaCO₃ → CaO + CO₂ tepkimesinde 100 g CaCO₃ ısıtıldığında teorik olarak 56 g CaO beklenir. 50,4 g CaO elde edilirse verim kaçtır? (Ca=40, C=12, O=16)","steps":[{"t":"Teorik CaO","a":"56 g","d":"100 g CaCO₃ (1 mol) bozununca 1 mol, yani 56 g CaO oluşması beklenir; bu teorik üründür."},{"t":"Verimi bul","a":"%90","d":"(50,4 ÷ 56) × 100 = 0,9 × 100 = 90; bozunma tepkimesinin verimi %90'dır."}],"ans":"Teorik 56 g CaO'ya karşılık 50,4 g elde edildiğinden verim (50,4 ÷ 56) × 100 = %90'dır."}],"zor":[{"q":"CH₄ + 2O₂ → CO₂ + 2H₂O tepkimesinde 16 g metan tam yakılıyor, deneyde 33 g CO₂ toplanıyor. Yüzde verimi bulunuz. (C=12, H=1, O=16)","steps":[{"t":"Mol ve teorik ürün","a":"1 mol CH₄ → 44 g CO₂","d":"CH₄ molkütlesi 16 g/mol; 16 g = 1 mol. Mol oranı 1 CH₄ : 1 CO₂ olduğundan 1 mol CO₂, yani 44 g CO₂ teorik olarak beklenir."},{"t":"Verim formülü","a":"(33/44)×100","d":"Yüzde verim = (gerçek ÷ teorik) × 100 = (33 ÷ 44) × 100 bağıntısıyla hesaplanır."},{"t":"Sonuç","a":"%75","d":"(33 ÷ 44) × 100 = 0,75 × 100 = 75; yanmanın CO₂ verimi %75'tir."}],"ans":"1 mol metandan teorik 44 g CO₂ beklenir; 33 g elde edildiğinden verim (33 ÷ 44) × 100 = %75'tir."},{"q":"2Na + Cl₂ → 2NaCl tepkimesinde 23 g sodyum tam tepkiyor. Verim %80 ise gerçekte kaç gram NaCl elde edilir? (Na=23, Cl=35,5)","fig":"<svg viewBox='0 0 320 120'><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>2Na + Cl₂ → 2NaCl</text><rect x='50' y='50' width='130' height='24' fill='#2b6be0'/><rect x='180' y='50' width='40' height='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='140' y='98' font-size='11' text-anchor='middle' fill='#1a2b45'>%80 verim</text></svg>","steps":[{"t":"Teorik NaCl","a":"58,5 g","d":"23 g Na = 1 mol; mol oranı 2 Na : 2 NaCl = 1 : 1 olduğundan 1 mol NaCl, yani 58,5 g teorik olarak beklenir."},{"t":"Gerçek ürün","a":"verim×teorik","d":"Gerçek ürün = (verim ÷ 100) × teorik = 0,80 × 58,5 olarak hesaplanır."},{"t":"Sonuç","a":"46,8 g","d":"0,80 × 58,5 = 46,8 g; %80 verimle 46,8 g NaCl elde edilir."}],"ans":"Teorik 58,5 g NaCl beklenir; %80 verimle gerçek ürün 0,80 × 58,5 = 46,8 g olur."},{"q":"Bir sentezde teorik ürün 250 g, elde edilen gerçek ürün 200 g'dır. Verimi bulup, aynı verimle 400 g teorikten kaç gram ürün beklenir?","steps":[{"t":"Verimi bul","a":"%80","d":"(200 ÷ 250) × 100 = 0,8 × 100 = 80; tepkimenin verimi %80'dir."},{"t":"Yeni gerçek ürün","a":"verim×teorik","d":"Aynı %80 verimle gerçek ürün = 0,80 × teorik formülüyle hesaplanır."},{"t":"Sonuç","a":"320 g","d":"0,80 × 400 = 320 g; aynı verimle 400 g teorikten 320 g ürün beklenir."}],"ans":"Verim (200 ÷ 250) × 100 = %80'dir; aynı verimle 400 g teorikten 0,80 × 400 = 320 g ürün beklenir."},{"q":"C + O₂ → CO₂ tepkimesinde 24 g karbon yakılıyor, deney sonunda 66 g CO₂ toplanıyor. Yüzde verimi hesaplayınız. (C=12, O=16)","steps":[{"t":"Mol ve teorik ürün","a":"2 mol C → 88 g CO₂","d":"24 g karbon = 2 mol; mol oranı 1 C : 1 CO₂ olduğundan 2 mol CO₂, yani 2 × 44 = 88 g CO₂ teorik olarak beklenir."},{"t":"Verim formülü","a":"(66/88)×100","d":"Yüzde verim = (gerçek ÷ teorik) × 100 = (66 ÷ 88) × 100 bağıntısı kullanılır."},{"t":"Sonuç","a":"%75","d":"(66 ÷ 88) × 100 = 0,75 × 100 = 75; tepkimenin verimi %75'tir."}],"ans":"2 mol karbondan teorik 88 g CO₂ beklenir; 66 g toplandığından verim (66 ÷ 88) × 100 = %75'tir."},{"q":"N₂ + 3H₂ ⇌ 2NH₃ tepkimesinde 28 g azot ile yeterli hidrojen tepkiyor. Verim %85 ise kaç gram NH₃ elde edilir? (N=14, H=1)","steps":[{"t":"Mol ve teorik ürün","a":"1 mol N₂ → 34 g NH₃","d":"28 g azot = 1 mol N₂; mol oranı 1 N₂ : 2 NH₃ olduğundan 2 mol NH₃, yani 2 × 17 = 34 g NH₃ teorik olarak beklenir."},{"t":"Gerçek ürün","a":"0,85×34","d":"Gerçek ürün = (verim ÷ 100) × teorik = 0,85 × 34 olarak hesaplanır."},{"t":"Sonuç","a":"28,9 g","d":"0,85 × 34 = 28,9 g; %85 verimle 28,9 g amonyak elde edilir."}],"ans":"1 mol azottan teorik 34 g NH₃ beklenir; %85 verimle gerçek ürün 0,85 × 34 = 28,9 g olur."}]}}};
